import type { BibleBook } from '../bibleData';

export const johnBook: BibleBook = {
  id: 'john',
  name: 'João',
  englishName: 'John',
  testament: 'new',
  chapters: {
    1: [
      { v: 1,  en: 'In the beginning was the Word, and the Word was with God, and the Word was God.', pt: 'No princípio era o Verbo, e o Verbo estava com Deus, e o Verbo era Deus.' },
      { v: 2,  en: 'The same was in the beginning with God.', pt: 'Ele estava no princípio com Deus.' },
      { v: 3,  en: 'All things were made by him; and without him was not any thing made that was made.', pt: 'Todas as coisas foram feitas por intermédio dele, e sem ele nada do que foi feito se fez.' },
      { v: 4,  en: 'In him was life; and the life was the light of men.', pt: 'Nele estava a vida, e a vida era a luz dos homens.' },
      { v: 5,  en: 'And the light shineth in darkness; and the darkness comprehended it not.', pt: 'E a luz resplandece nas trevas, e as trevas não a compreenderam.' },
      { v: 6,  en: 'There was a man sent from God, whose name was John.', pt: 'Houve um homem enviado por Deus, cujo nome era João.' },
      { v: 7,  en: 'The same came for a witness, to bear witness of the Light, that all men through him might believe.', pt: 'Este veio para testemunho, para que testificasse da Luz, para que todos cressem por meio dele.' },
      { v: 8,  en: 'He was not that Light, but was sent to bear witness of that Light.', pt: 'Ele não era a Luz, mas enviado para testificar da Luz.' },
      { v: 9,  en: 'That was the true Light, which lighteth every man that cometh into the world.', pt: 'Havia a Luz verdadeira, que, chegando ao mundo, ilumina todo o homem.' },
      { v: 10, en: 'He was in the world, and the world was made by him, and the world knew him not.', pt: 'Ele estava no mundo, e o mundo foi feito por ele, e o mundo não o conheceu.' },
      { v: 11, en: 'He came unto his own, and his own received him not.', pt: 'Veio para o que era seu, e os seus não o receberam.' },
      { v: 12, en: 'But as many as received him, to them gave he power to become the sons of God, even to them that believe on his name:', pt: 'Mas a todos quantos o receberam deu-lhes o poder de serem feitos filhos de Deus, a saber, aos que creem no seu nome:' },
      { v: 13, en: 'Which were born, not of blood, nor of the will of the flesh, nor of the will of man, but of God.', pt: 'Os quais não nasceram do sangue, nem da vontade da carne, nem da vontade do homem, mas de Deus.' },
      { v: 14, en: 'And the Word was made flesh, and dwelt among us, (and we beheld his glory, the glory as of the only begotten of the Father,) full of grace and truth.', pt: 'E o Verbo se fez carne e habitou entre nós, e vimos a sua glória, como a glória do unigênito do Pai, cheio de graça e de verdade.' },
      { v: 15, en: 'John bare witness of him, and cried, saying, This was he of whom I spake, He that cometh after me is preferred before me: for he was before me.', pt: 'João testificou dele e bradou: Este é aquele de quem eu disse: O que vem depois de mim é antes de mim, porque era primeiro do que eu.' },
      { v: 16, en: 'And of his fulness have all we received, and grace for grace.', pt: 'Porque todos nós recebemos da sua plenitude, graça sobre graça.' },
      { v: 17, en: 'For the law was given by Moses, but grace and truth came by Jesus Christ.', pt: 'Porque a lei foi dada por Moisés; a graça e a verdade vieram por Jesus Cristo.' },
      { v: 18, en: 'No man hath seen God at any time; the only begotten Son, which is in the bosom of the Father, he hath declared him.', pt: 'Ninguém jamais viu a Deus; o Filho unigênito, que está no seio do Pai, esse o revelou.' },
      { v: 19, en: 'And this is the record of John, when the Jews sent priests and Levites from Jerusalem to ask him, Who art thou?', pt: 'E este é o testemunho de João, quando os judeus mandaram de Jerusalém sacerdotes e levitas, a fim de lhe perguntarem: Quem és tu?' },
      { v: 20, en: 'And he confessed, and denied not; but confessed, I am not the Christ.', pt: 'E ele confessou e não negou; confessou: Eu não sou o Cristo.' },
      { v: 21, en: 'And they asked him, What then? Art thou Elias? And he saith, I am not. Art thou that prophet? And he answered, No.', pt: 'Perguntaram-lhe: Que és, pois? És Elias? E ele disse: Não sou. És o profeta? E respondeu: Não.' },
      { v: 22, en: 'Then said they unto him, Who art thou? that we may give an answer to them that sent us. What sayest thou of thyself?', pt: 'Disseram-lhe: Quem és tu? Para que possamos dar resposta aos que nos enviaram. Que dizes tu de ti mesmo?' },
      { v: 23, en: 'He said, I am the voice of one crying in the wilderness, Make straight the way of the Lord, as said the prophet Esaias.', pt: 'Disse: Eu sou a voz do que clama no deserto: Endireitai o caminho do Senhor, como disse o profeta Isaías.' },
      { v: 24, en: 'And they which were sent were of the Pharisees.', pt: 'E os que foram enviados eram dos fariseus.' },
      { v: 25, en: 'And they asked him, and said unto him, Why baptizest thou then, if thou be not that Christ, nor Elias, neither that prophet?', pt: 'E eles lhe perguntaram: Por que, pois, batizas tu, se não és o Cristo, nem Elias, nem o profeta?' },
      { v: 26, en: 'John answered them, saying, I baptize with water: but there standeth one among you, whom ye know not;', pt: 'João lhes respondeu: Eu batizo com água; mas no meio de vós está alguém que não conheceis.' },
      { v: 27, en: "He it is, who coming after me is preferred before me, whose shoe's latchet I am not worthy to unloose.", pt: 'É aquele que vem depois de mim, que é antes de mim, de quem eu não sou digno de desatar a correia da sandália.' },
      { v: 28, en: 'These things were done in Bethabara beyond Jordan, where John was baptizing.', pt: 'Estas coisas aconteceram em Betânia, além do Jordão, onde João estava batizando.' },
      { v: 29, en: 'The next day John seeth Jesus coming unto him, and saith, Behold the Lamb of God, which taketh away the sin of the world.', pt: 'No dia seguinte, João viu Jesus a aproximar-se dele e disse: Eis o Cordeiro de Deus, que tira o pecado do mundo.' },
      { v: 30, en: 'This is he of whom I said, After me cometh a man which is preferred before me: for he was before me.', pt: 'Este é aquele a respeito de quem eu disse: Depois de mim vem um homem que é antes de mim, pois era primeiro do que eu.' },
      { v: 31, en: 'And I knew him not: but that he should be made manifest to Israel, therefore am I come baptizing with water.', pt: 'E eu não o conhecia; mas, para que ele se manifestasse a Israel, vim eu batizando com água.' },
      { v: 32, en: 'And John bare record, saying, I saw the Spirit descending from heaven like a dove, and it abode upon him.', pt: 'E João testemunhou: Vi o Espírito descer do céu como pomba, e ficou sobre ele.' },
      { v: 33, en: 'And I knew him not: but he that sent me to baptize with water, the same said unto me, Upon whom thou shalt see the Spirit descending, and remaining on him, the same is he which baptizeth with the Holy Ghost.', pt: 'E eu não o conhecia; mas aquele que me enviou a batizar com água me disse: Sobre quem vires descer o Espírito e pousar sobre ele, esse é o que batiza com o Espírito Santo.' },
      { v: 34, en: 'And I saw, and bare record that this is the Son of God.', pt: 'E eu vi e testifico que este é o Filho de Deus.' },
      { v: 35, en: 'Again the next day after John stood, and two of his disciples;', pt: 'No dia seguinte, estava João outra vez lá, e dois dos seus discípulos.' },
      { v: 36, en: 'And looking upon Jesus as he walked, he saith, Behold the Lamb of God!', pt: 'E, olhando para Jesus enquanto caminhava, disse: Eis o Cordeiro de Deus!' },
      { v: 37, en: 'And the two disciples heard him speak, and they followed Jesus.', pt: 'E os dois discípulos ouviram-no falar assim, e seguiram Jesus.' },
      { v: 38, en: 'Then Jesus turned, and saw them following, and saith unto them, What seek ye? They said unto him, Rabbi, (which is to say, being interpreted, Master,) where dwellest thou?', pt: 'Então Jesus se voltou e, vendo que o seguiam, lhes perguntou: Que buscais? E eles disseram: Rabi (que traduzido quer dizer, Mestre), onde moras?' },
      { v: 39, en: 'He saith unto them, Come and see. They came and saw where he dwelt, and abode with him that day: for it was about the tenth hour.', pt: 'Ele lhes disse: Vinde e vede. Foram, pois, e viram onde ele morava; e ficaram com ele aquele dia, pois eram quase dez horas.' },
      { v: 40, en: "One of the two which heard John speak, and followed him, was Andrew, Simon Peter's brother.", pt: 'André, irmão de Simão Pedro, era um dos dois que ouviram João e seguiram Jesus.' },
      { v: 41, en: 'He first findeth his own brother Simon, and saith unto him, We have found the Messias, which is, being interpreted, the Christ.', pt: 'Este achou primeiro o seu próprio irmão Simão e disse-lhe: Achamos o Messias (que traduzido é Cristo).' },
      { v: 42, en: 'And he brought him to Jesus. And when Jesus beheld him, he said, Thou art Simon the son of Jona: thou shalt be called Cephas, which is by interpretation, A stone.', pt: 'E o levou a Jesus. Jesus fitou-lhe os olhos e disse: Tu és Simão, filho de João; tu serás chamado Cefas (que quer dizer Pedro).' },
      { v: 43, en: 'The day following Jesus would go forth into Galilee, and findeth Philip, and saith unto him, Follow me.', pt: 'No dia seguinte, Jesus quis ir para a Galileia e achou Filipe e disse-lhe: Segue-me.' },
      { v: 44, en: 'Now Philip was of Bethsaida, the city of Andrew and Peter.', pt: 'Ora, Filipe era de Betsaida, da cidade de André e de Pedro.' },
      { v: 45, en: 'Philip findeth Nathanael, and saith unto him, We have found him, of whom Moses in the law, and the prophets, did write, Jesus of Nazareth, the son of Joseph.', pt: 'Filipe achou Natanael e disse-lhe: Achamos aquele de quem Moisés escreveu na lei, e os profetas: Jesus de Nazaré, filho de José.' },
      { v: 46, en: 'And Nathanael said unto him, Can there any good thing come out of Nazareth? Philip saith unto him, Come and see.', pt: 'E Natanael lhe disse: Pode sair alguma coisa boa de Nazaré? Filipe lhe respondeu: Vem e vê.' },
      { v: 47, en: 'Jesus saw Nathanael coming to him, and saith of him, Behold an Israelite indeed, in whom is no guile!', pt: 'Jesus viu Natanael a aproximar-se e disse a seu respeito: Eis verdadeiro israelita, em quem não há dolo!' },
      { v: 48, en: 'Nathanael saith unto him, Whence knowest thou me? Jesus answered and said unto him, Before that Philip called thee, when thou wast under the fig tree, I saw thee.', pt: 'Natanael lhe disse: Como me conheces? Jesus respondeu: Antes de Filipe te chamar, quando estavas debaixo da figueira, eu te vi.' },
      { v: 49, en: 'Nathanael answered and saith unto him, Rabbi, thou art the Son of God; thou art the King of Israel.', pt: 'Natanael respondeu: Rabi, tu és o Filho de Deus, tu és o Rei de Israel!' },
      { v: 50, en: 'Jesus answered and said unto him, Because I said unto thee, I saw thee under the fig tree, believest thou? thou shalt see greater things than these.', pt: 'Jesus respondeu: Porque te disse que te vi debaixo da figueira, crês? Coisas maiores do que estas verás.' },
      { v: 51, en: 'And he saith unto him, Verily, verily, I say unto you, Hereafter ye shall see heaven open, and the angels of God ascending and descending upon the Son of man.', pt: 'E acrescentou: Em verdade, em verdade vos digo: daqui em diante vereis o céu aberto e os anjos de Deus subindo e descendo sobre o Filho do homem.' },
    ],
    2: [
      { v: 1,  en: 'And the third day there was a marriage in Cana of Galilee; and the mother of Jesus was there:', pt: 'E ao terceiro dia realizou-se uma boda em Caná da Galileia, e estava ali a mãe de Jesus.' },
      { v: 2,  en: 'And both Jesus was called, and his disciples, to the marriage.', pt: 'E foram também convidados para a boda Jesus e os seus discípulos.' },
      { v: 3,  en: 'And when they wanted wine, the mother of Jesus saith unto him, They have no wine.', pt: 'E, faltando o vinho, a mãe de Jesus disse-lhe: Não têm vinho.' },
      { v: 4,  en: 'Jesus saith unto her, Woman, what have I to do with thee? mine hour is not yet come.', pt: 'Disse-lhe Jesus: Mulher, que tenho eu contigo? Ainda não é chegada a minha hora.' },
      { v: 5,  en: 'His mother saith unto the servants, Whatsoever he saith unto you, do it.', pt: 'Disse sua mãe aos serventes: Fazei tudo o que ele vos disser.' },
      { v: 6,  en: 'And there were set there six waterpots of stone, after the manner of the purifying of the Jews, containing two or three firkins apiece.', pt: 'E estavam ali postos seis potes de pedra, para a purificação dos judeus, cada um com capacidade para duas ou três medidas.' },
      { v: 7,  en: 'Jesus saith unto them, Fill the waterpots with water. And they filled them up to the brim.', pt: 'Jesus disse-lhes: Enchei de água estes potes. E encheram-nos até em cima.' },
      { v: 8,  en: 'And he saith unto them, Draw out now, and bear unto the governor of the feast. And they bare it.', pt: 'E disse-lhes: Tirai agora e levai ao mestre-sala. E levaram.' },
      { v: 9,  en: 'When the ruler of the feast had tasted the water that was made wine, and knew not whence it was: (but the servants which drew the water knew;) the governor of the feast called the bridegroom,', pt: 'E quando o mestre-sala provou a água tornada vinho, não sabendo de onde vinha (mas os serventes que haviam tirado a água o sabiam), chamou o noivo,' },
      { v: 10, en: 'And saith unto him, Every man at the beginning doth set forth good wine; and when men have well drunk, then that which is worse: but thou hast kept the good wine until now.', pt: 'E disse-lhe: Todo o homem serve primeiro o bom vinho e, quando estão satisfeitos, o inferior; mas tu guardaste o bom vinho até agora.' },
      { v: 11, en: 'This beginning of miracles did Jesus in Cana of Galilee, and manifested forth his glory; and his disciples believed on him.', pt: 'Jesus fez este primeiro milagre em Caná da Galileia e manifestou a sua glória; e os seus discípulos creram nele.' },
      { v: 12, en: 'After this he went down to Capernaum, he, and his mother, and his brethren, and his disciples: and they continued there not many days.', pt: 'Depois disto desceu a Cafarnaum, ele e sua mãe, e seus irmãos, e seus discípulos; e ficaram ali não muitos dias.' },
      { v: 13, en: "And the Jews' passover was at hand, and Jesus went up to Jerusalem,", pt: 'E a páscoa dos judeus estava próxima, e Jesus subiu a Jerusalém.' },
      { v: 14, en: 'And found in the temple those that sold oxen and sheep and doves, and the changers of money sitting:', pt: 'E achou no templo os que vendiam bois, e ovelhas, e pombas, e os cambistas sentados.' },
      { v: 15, en: "And when he had made a scourge of small cords, he drove them all out of the temple, and the sheep, and the oxen; and poured out the changers' money, and overthrew the tables;", pt: 'E, fazendo um açoite de cordas, expulsou todos do templo, e também as ovelhas e os bois; e derramou o dinheiro dos cambistas e derribou as mesas.' },
      { v: 16, en: "And said unto them that sold doves, Take these things hence; make not my Father's house an house of merchandise.", pt: 'E disse aos que vendiam pombas: Tirai daqui isso; não façais da casa de meu Pai casa de mercado.' },
      { v: 17, en: 'And his disciples remembered that it was written, The zeal of thine house hath eaten me up.', pt: 'E os seus discípulos lembraram-se de que está escrito: O zelo da tua casa me consumirá.' },
      { v: 18, en: 'Then answered the Jews and said unto him, What sign shewest thou unto us, seeing that thou doest these things?', pt: 'Então os judeus responderam e disseram-lhe: Que sinal nos mostras, pois que fazes estas coisas?' },
      { v: 19, en: 'Jesus answered and said unto them, Destroy this temple, and in three days I will raise it up.', pt: 'Jesus respondeu: Destruí este templo, e em três dias o levantarei.' },
      { v: 20, en: 'Then said the Jews, Forty and six years was this temple in building, and wilt thou rear it up in three days?', pt: 'Então os judeus disseram: Em quarenta e seis anos foi edificado este templo, e tu o levantarás em três dias?' },
      { v: 21, en: 'But he spake of the temple of his body.', pt: 'Mas ele falava do templo do seu corpo.' },
      { v: 22, en: 'When therefore he was risen from the dead, his disciples remembered that he had said this unto them; and they believed the scripture, and the word which Jesus had said.', pt: 'Quando, pois, ressuscitou dos mortos, lembraram-se os seus discípulos de que dissera isso; e creram na Escritura e na palavra que Jesus dissera.' },
      { v: 23, en: 'Now when he was in Jerusalem at the passover, in the feast day, many believed in his name, when they saw the miracles which he did.', pt: 'E, estando em Jerusalém na páscoa, no dia da festa, muitos creram no seu nome, vendo os milagres que fazia.' },
      { v: 24, en: 'But Jesus did not commit himself unto them, because he knew all men,', pt: 'Jesus, porém, não se confiava a eles, porque conhecia a todos,' },
      { v: 25, en: 'And needed not that any should testify of man: for he knew what was in man.', pt: 'E não tinha necessidade de que alguém desse testemunho do homem; porque ele mesmo sabia o que estava no homem.' },
    ],
    3: [
      { v: 1,  en: 'There was a man of the Pharisees, named Nicodemus, a ruler of the Jews:', pt: 'E havia entre os fariseus um homem chamado Nicodemos, príncipe dos judeus.' },
      { v: 2,  en: 'The same came to Jesus by night, and said unto him, Rabbi, we know that thou art a teacher come from God: for no man can do these miracles that thou doest, except God be with him.', pt: 'Este foi ter com Jesus de noite e disse-lhe: Rabi, sabemos que és Mestre vindo da parte de Deus, porque ninguém pode fazer estes sinais que tu fazes, se Deus não estiver com ele.' },
      { v: 3,  en: 'Jesus answered and said unto him, Verily, verily, I say unto thee, Except a man be born again, he cannot see the kingdom of God.', pt: 'Jesus respondeu e disse-lhe: Em verdade, em verdade te digo que aquele que não nascer de novo não pode ver o reino de Deus.' },
      { v: 4,  en: "Nicodemus saith unto him, How can a man be born when he is old? can he enter the second time into his mother's womb, and be born?", pt: 'Nicodemos disse-lhe: Como pode um homem nascer, sendo velho? Pode entrar segunda vez no ventre de sua mãe e nascer?' },
      { v: 5,  en: 'Jesus answered, Verily, verily, I say unto thee, Except a man be born of water and of the Spirit, he cannot enter into the kingdom of God.', pt: 'Jesus respondeu: Em verdade, em verdade te digo que aquele que não nascer da água e do Espírito não pode entrar no reino de Deus.' },
      { v: 6,  en: 'That which is born of the flesh is flesh; and that which is born of the Spirit is spirit.', pt: 'O que é nascido da carne é carne, e o que é nascido do Espírito é espírito.' },
      { v: 7,  en: 'Marvel not that I said unto thee, Ye must be born again.', pt: 'Não te maravilhes de eu te dizer: Tendes de nascer de novo.' },
      { v: 8,  en: 'The wind bloweth where it listeth, and thou hearest the sound thereof, but canst not tell whence it cometh, and whither it goeth: so is every one that is born of the Spirit.', pt: 'O vento sopra onde quer, e ouves a sua voz, mas não sabes de onde vem nem para onde vai; assim é todo o que é nascido do Espírito.' },
      { v: 9,  en: 'Nicodemus answered and said unto him, How can these things be?', pt: 'Nicodemos respondeu e disse-lhe: Como podem ser assim estas coisas?' },
      { v: 10, en: 'Jesus answered and said unto him, Art thou a master of Israel, and knowest not these things?', pt: 'Respondeu-lhe Jesus: Tu és mestre em Israel e não sabes estas coisas?' },
      { v: 11, en: 'Verily, verily, I say unto thee, We speak that we do know, and testify that we have seen; and ye receive not our witness.', pt: 'Em verdade, em verdade te digo que falamos do que sabemos e testificamos do que vimos; mas não aceitais o nosso testemunho.' },
      { v: 12, en: 'If I have told you earthly things, and ye believe not, how shall ye believe, if I tell you of heavenly things?', pt: 'Se vos falei de coisas terrenas e não credes, como crereis se vos falar das celestiais?' },
      { v: 13, en: 'And no man hath ascended up to heaven, but he that came down from heaven, even the Son of man which is in heaven.', pt: 'Ninguém sobe ao céu, senão o que desceu do céu, o Filho do homem, que está no céu.' },
      { v: 14, en: 'And as Moses lifted up the serpent in the wilderness, even so must the Son of man be lifted up:', pt: 'E, assim como Moisés levantou a serpente no deserto, assim importa que o Filho do homem seja levantado,' },
      { v: 15, en: 'That whosoever believeth in him should not perish, but have eternal life.', pt: 'Para que todo aquele que nele crê não pereça, mas tenha a vida eterna.' },
      { v: 16, en: 'For God so loved the world, that he gave his only begotten Son, that whosoever believeth in him should not perish, but have everlasting life.', pt: 'Porque Deus amou ao mundo de tal maneira que deu o seu Filho unigênito, para que todo o que nele crê não pereça, mas tenha a vida eterna.' },
      { v: 17, en: 'For God sent not his Son into the world to condemn the world; but that the world through him might be saved.', pt: 'Porque Deus enviou o seu Filho ao mundo, não para que condenasse o mundo, mas para que o mundo fosse salvo por ele.' },
      { v: 18, en: 'He that believeth on him is not condemned: but he that believeth not is condemned already, because he hath not believed in the name of the only begotten Son of God.', pt: 'Quem crê nele não é condenado; mas quem não crê já está condenado, porquanto não crê no nome do unigênito Filho de Deus.' },
      { v: 19, en: 'And this is the condemnation, that light is come into the world, and men loved darkness rather than light, because their deeds were evil.', pt: 'E é este o julgamento: que a luz veio ao mundo, e os homens amaram mais as trevas do que a luz, porque as suas obras eram más.' },
      { v: 20, en: 'For every one that doeth evil hateth the light, neither cometh to the light, lest his deeds should be reproved.', pt: 'Pois todo aquele que faz o mal odeia a luz e não vem para a luz, para que as suas obras não sejam reprovadas.' },
      { v: 21, en: 'But he that doeth truth cometh to the light, that his deeds may be made manifest, that they are wrought in God.', pt: 'Mas quem pratica a verdade vem para a luz, a fim de que as suas obras sejam manifestas, porque são feitas em Deus.' },
      { v: 22, en: 'After these things came Jesus and his disciples into the land of Judaea; and there he tarried with them, and baptized.', pt: 'Depois destas coisas veio Jesus com os seus discípulos para a terra da Judeia; e estava ali com eles e batizava.' },
      { v: 23, en: 'And John also was baptizing in Aenon near to Salim, because there was much water there: and they came, and were baptized.', pt: 'João também estava batizando em Enom, junto a Salim, porque havia ali muita água; e chegavam lá e eram batizados.' },
      { v: 24, en: 'For John was not yet cast into prison.', pt: 'Porque João não havia sido ainda posto em prisão.' },
      { v: 25, en: "Then there arose a question between some of John's disciples and the Jews about purifying.", pt: 'Levantou-se, pois, uma questão da parte dos discípulos de João com os judeus acerca da purificação.' },
      { v: 26, en: 'And they came unto John, and said unto him, Rabbi, he that was with thee beyond Jordan, to whom thou barest witness, behold, the same baptizeth, and all men come to him.', pt: 'E foram ter com João e disseram-lhe: Rabi, aquele que estava contigo além do Jordão e a quem deste testemunho, eis que batiza, e todos vão a ele.' },
      { v: 27, en: 'John answered and said, A man can receive nothing, except it be given him from heaven.', pt: 'João respondeu: O homem não pode receber coisa alguma se do céu lhe não for dada.' },
      { v: 28, en: 'Ye yourselves bear me witness, that I said, I am not the Christ, but that I am sent before him.', pt: 'Vós mesmos me sois testemunhas de que disse: Eu não sou o Cristo, mas fui enviado adiante dele.' },
      { v: 29, en: "He that hath the bride is the bridegroom: but the friend of the bridegroom, which standeth and heareth him, rejoiceth greatly because of the bridegroom's voice: this my joy therefore is fulfilled.", pt: 'O que tem a noiva é o noivo; mas o amigo do noivo, que está presente e o ouve, alegra-se muito com a voz do noivo; de sorte que esta minha alegria está cumprida.' },
      { v: 30, en: 'He must increase, but I must decrease.', pt: 'Convém que ele cresça e que eu diminua.' },
      { v: 31, en: 'He that cometh from above is above all: he that is of the earth is earthly, and speaketh of the earth: he that cometh from heaven is above all.', pt: 'Aquele que vem do alto é sobre todos; o que é da terra é terreno e fala da terra; aquele que vem do céu é sobre todos.' },
      { v: 32, en: 'And what he hath seen and heard, that he testifieth; and no man receiveth his testimony.', pt: 'E o que viu e ouviu, isso testifica; e ninguém recebe o seu testemunho.' },
      { v: 33, en: 'He that hath received his testimony hath set to his seal that God is true.', pt: 'Quem recebeu o seu testemunho assinou que Deus é verdadeiro.' },
      { v: 34, en: 'For he whom God hath sent speaketh the words of God: for God giveth not the Spirit by measure unto him.', pt: 'Porque aquele a quem Deus enviou fala as palavras de Deus; pois Deus lhe dá o Espírito sem medida.' },
      { v: 35, en: 'The Father loveth the Son, and hath given all things into his hand.', pt: 'O Pai ama o Filho e tudo entregou em sua mão.' },
      { v: 36, en: 'He that believeth on the Son hath everlasting life: and he that believeth not the Son shall not see life; but the wrath of God abideth on him.', pt: 'Quem crê no Filho tem a vida eterna; mas quem não obedece ao Filho não verá a vida, mas a ira de Deus permanece sobre ele.' },
    ],
    4: [
      { v: 1,  en: 'When therefore the Lord knew how the Pharisees had heard that Jesus made and baptized more disciples than John,', pt: 'Quando, pois, o Senhor entendeu que os fariseus tinham ouvido dizer que Jesus fazia e batizava mais discípulos do que João,' },
      { v: 2,  en: '(Though Jesus himself baptized not, but his disciples,)', pt: '(Ainda que Jesus mesmo não batizava, mas os seus discípulos),' },
      { v: 3,  en: 'He left Judaea, and departed again into Galilee.', pt: 'Deixou a Judeia e foi de novo para a Galileia.' },
      { v: 4,  en: 'And he must needs go through Samaria.', pt: 'E convinha que ele passasse pela Samaria.' },
      { v: 5,  en: 'Then cometh he to a city of Samaria, which is called Sychar, near to the parcel of ground that Jacob gave to his son Joseph.', pt: 'Chegou, pois, a uma cidade da Samaria chamada Sicar, junto da courela que Jacó dera a seu filho José.' },
      { v: 6,  en: "Now Jacob's well was there. Jesus therefore, being wearied with his journey, sat thus on the well: and it was about the sixth hour.", pt: 'E estava ali o poço de Jacó. Jesus, pois, cansado da jornada, assentou-se assim à beira do poço. Era quase a hora sexta.' },
      { v: 7,  en: 'There cometh a woman of Samaria to draw water: Jesus saith unto her, Give me to drink.', pt: 'Chegou uma mulher da Samaria a tirar água. Jesus disse-lhe: Dá-me de beber.' },
      { v: 8,  en: '(For his disciples were gone away unto the city to buy meat.)', pt: '(Porque os seus discípulos tinham ido à cidade comprar comida.)' },
      { v: 9,  en: 'Then saith the woman of Samaria unto him, How is it that thou, being a Jew, askest drink of me, which am a woman of Samaria? for the Jews have no dealings with the Samaritans.', pt: 'Disse-lhe então a mulher samaritana: Como, sendo tu judeu, me pedes de beber a mim, que sou mulher samaritana? Porque os judeus não se comunicam com os samaritanos.' },
      { v: 10, en: 'Jesus answered and said unto her, If thou knewest the gift of God, and who it is that saith to thee, Give me to drink; thou wouldest have asked of him, and he would have given thee living water.', pt: 'Jesus respondeu e disse-lhe: Se tu conhecesses o dom de Deus, e quem é aquele que te diz: Dá-me de beber, tu lhe pedirias, e ele te daria água viva.' },
      { v: 11, en: 'The woman saith unto him, Sir, thou hast nothing to draw with, and the well is deep: from whence then hast thou that living water?', pt: 'Disse-lhe a mulher: Senhor, não tens com que tirar água, e o poço é fundo; donde, pois, tens a água viva?' },
      { v: 12, en: 'Art thou greater than our father Jacob, which gave us the well, and drank thereof himself, and his children, and his cattle?', pt: 'Porventura és tu maior do que nosso pai Jacó, que nos deu este poço, e dele bebeu ele, e seus filhos, e seu gado?' },
      { v: 13, en: 'Jesus answered and said unto her, Whosoever drinketh of this water shall thirst again:', pt: 'Jesus respondeu e disse-lhe: Todo aquele que beber desta água tornará a ter sede.' },
      { v: 14, en: 'But whosoever drinketh of the water that I shall give him shall never thirst; but the water that I shall give him shall be in him a well of water springing up into everlasting life.', pt: 'Mas qualquer que beber da água que eu lhe der nunca terá sede; mas a água que eu lhe der será nele uma fonte de água que salte para a vida eterna.' },
      { v: 15, en: 'The woman saith unto him, Sir, give me this water, that I thirst not, neither come hither to draw.', pt: 'Disse-lhe a mulher: Senhor, dá-me dessa água, para que eu não tenha sede nem venha aqui tirá-la.' },
      { v: 16, en: 'Jesus saith unto her, Go, call thy husband, and come hither.', pt: 'Jesus disse-lhe: Vai, chama o teu marido e vem cá.' },
      { v: 17, en: 'The woman answered and said, I have no husband. Jesus said unto her, Thou hast well said, I have no husband:', pt: 'A mulher respondeu e disse: Não tenho marido. Jesus disse-lhe: Bem disseste que não tens marido;' },
      { v: 18, en: 'For thou hast had five husbands; and he whom thou now hast is not thy husband: in that saidst thou truly.', pt: 'Porque tiveste cinco maridos, e o que agora tens não é teu marido; nisto disseste com verdade.' },
      { v: 19, en: 'The woman saith unto him, Sir, I perceive that thou art a prophet.', pt: 'Disse-lhe a mulher: Senhor, vejo que és profeta.' },
      { v: 20, en: 'Our fathers worshipped in this mountain; and ye say, that in Jerusalem is the place where men ought to worship.', pt: 'Nossos pais adoraram neste monte, e vós dizeis que em Jerusalém é o lugar onde se deve adorar.' },
      { v: 21, en: 'Jesus saith unto her, Woman, believe me, the hour cometh, when ye shall neither in this mountain, nor yet at Jerusalem, worship the Father.', pt: 'Jesus disse-lhe: Mulher, crê-me que a hora vem quando nem neste monte nem em Jerusalém adorareis o Pai.' },
      { v: 22, en: 'Ye worship ye know not what: we know what we worship: for salvation is of the Jews.', pt: 'Vós adorais o que não sabeis; nós adoramos o que sabemos, porque a salvação vem dos judeus.' },
      { v: 23, en: 'But the hour cometh, and now is, when the true worshippers shall worship the Father in spirit and in truth: for the Father seeketh such to worship him.', pt: 'Mas a hora vem, e agora é, em que os verdadeiros adoradores adorarão o Pai em espírito e em verdade; porque o Pai procura os que assim o adorem.' },
      { v: 24, en: 'God is a Spirit: and they that worship him must worship him in spirit and in truth.', pt: 'Deus é Espírito, e importa que os que o adoram o adorem em espírito e em verdade.' },
      { v: 25, en: 'The woman saith unto him, I know that Messias cometh, which is called Christ: when he is come, he will tell us all things.', pt: 'Disse-lhe a mulher: Sei que o Messias vem (que se chama Cristo); quando ele vier, nos anunciará todas as coisas.' },
      { v: 26, en: 'Jesus saith unto her, I that speak unto thee am he.', pt: 'Jesus disse-lhe: Eu sou, eu que falo contigo.' },
      { v: 27, en: 'And upon this came his disciples, and marvelled that he talked with the woman: yet no man said, What seekest thou? or, Why talkest thou with her?', pt: 'E logo chegaram os seus discípulos, e maravilharam-se de que falasse com uma mulher; todavia nenhum disse: Que perguntas? ou: Por que falas com ela?' },
      { v: 28, en: 'The woman then left her waterpot, and went her way into the city, and saith to the men,', pt: 'Então a mulher deixou o seu cântaro e foi à cidade e disse aos homens:' },
      { v: 29, en: 'Come, see a man, which told me all things that ever I did: is not this the Christ?', pt: 'Vinde, vede um homem que me disse tudo quanto tenho feito. Porventura não é este o Cristo?' },
      { v: 30, en: 'Then they went out of the city, and came unto him.', pt: 'Então saíram da cidade e foram ter com ele.' },
      { v: 31, en: 'In the mean while his disciples prayed him, saying, Master, eat.', pt: 'Entretanto, os seus discípulos rogavam-lhe: Rabi, come.' },
      { v: 32, en: 'But he said unto them, I have meat to eat that ye know not of.', pt: 'Ele, porém, lhes disse: Tenho uma comida a comer que vós não conheceis.' },
      { v: 33, en: 'Therefore said the disciples one to another, Hath any man brought him ought to eat?', pt: 'Então os discípulos disseram uns aos outros: Terá alguém trazido que comer?' },
      { v: 34, en: 'Jesus saith unto them, My meat is to do the will of him that sent me, and to finish his work.', pt: 'Jesus disse-lhes: A minha comida é fazer a vontade daquele que me enviou e realizar a sua obra.' },
      { v: 35, en: 'Say not ye, There are yet four months, and then cometh harvest? behold, I say unto you, Lift up your eyes, and look on the fields; for they are white already to harvest.', pt: 'Não dizeis vós que ainda há quatro meses, e depois vem a ceifa? Eis que vos digo: Levantai os olhos e vede as regiões, que já estão brancas para a ceifa.' },
      { v: 36, en: 'And he that reapeth receiveth wages, and gathereth fruit unto life eternal: that both he that soweth and he that reapeth may rejoice together.', pt: 'E o que ceifa recebe galardão e ajunta fruto para a vida eterna, a fim de que tanto o que semeia como o que ceifa se regozijem juntamente.' },
      { v: 37, en: 'And herein is that saying true, One soweth, and another reapeth.', pt: 'E nisto é verdadeiro aquele dito: Um é o que semeia, e outro é o que ceifa.' },
      { v: 38, en: 'I sent you to reap that whereon ye bestowed no labour: other men laboured, and ye are entered into their labours.', pt: 'Eu vos enviei a ceifar o que não trabalhastes: outros trabalharam, e vós entrastes no trabalho deles.' },
      { v: 39, en: 'And many of the Samaritans of that city believed on him for the saying of the woman, which testified, He told me all that ever I did.', pt: 'E muitos dos samaritanos daquela cidade creram nele pela palavra da mulher, que dava testemunho: Disse-me tudo quanto tenho feito.' },
      { v: 40, en: 'So when the Samaritans were come unto him, they besought him that he would tarry with them: and he abode there two days.', pt: 'Quando, pois, os samaritanos chegaram a ele, rogaram-lhe que ficasse com eles; e ficou ali dois dias.' },
      { v: 41, en: 'And many more believed because of his own word;', pt: 'E muito mais creram pela sua própria palavra.' },
      { v: 42, en: 'And said unto the woman, Now we believe, not because of thy saying: for we have heard him ourselves, and know that this is indeed the Christ, the Saviour of the world.', pt: 'E disseram à mulher: Já não cremos por causa do que tu disseste, porque nós mesmos o ouvimos e sabemos que este é verdadeiramente o Cristo, o Salvador do mundo.' },
      { v: 43, en: 'Now after two days he departed thence, and went into Galilee.', pt: 'E depois de dois dias saiu dali e foi para a Galileia.' },
      { v: 44, en: 'For Jesus himself testified, that a prophet hath no honour in his own country.', pt: 'Porque o próprio Jesus testificou que um profeta não tem honra em sua pátria.' },
      { v: 45, en: 'Then when he was come into Galilee, the Galilaeans received him, having seen all the things that he did at Jerusalem at the feast: for they also went unto the feast.', pt: 'Quando chegou à Galileia, os galileus o receberam, tendo visto tudo o que tinha feito em Jerusalém na festa; porque também eles tinham ido à festa.' },
      { v: 46, en: 'So Jesus came again into Cana of Galilee, where he made the water wine. And there was a certain nobleman, whose son was sick at Capernaum.', pt: 'Jesus voltou de novo a Caná da Galileia, onde convertera a água em vinho. E havia um oficial do rei cujo filho estava enfermo em Cafarnaum.' },
      { v: 47, en: 'When he heard that Jesus was come out of Judaea into Galilee, he went unto him, and besought him that he would come down, and heal his son: for he was at the point of death.', pt: 'Este, tendo ouvido que Jesus vinha da Judeia para a Galileia, foi ter com ele e rogou-lhe que descesse e curasse o seu filho, porque estava à morte.' },
      { v: 48, en: 'Then said Jesus unto him, Except ye see signs and wonders, ye will not believe.', pt: 'Jesus, pois, lhe disse: Se não virdes sinais e prodígios, de maneira nenhuma crereis.' },
      { v: 49, en: 'The nobleman saith unto him, Sir, come down ere my child die.', pt: 'O oficial do rei disse-lhe: Senhor, desce antes que o meu filho morra.' },
      { v: 50, en: 'Jesus saith unto him, Go thy way; thy son liveth. And the man believed the word that Jesus had spoken unto him, and he went his way.', pt: 'Jesus disse-lhe: Vai, o teu filho vive. E o homem creu na palavra que Jesus lhe disse e foi.' },
      { v: 51, en: 'And as he was now going down, his servants met him, and told him, saying, Thy son liveth.', pt: 'E, indo já descendo, encontraram-no os seus servos e anunciaram-lhe: O teu filho vive.' },
      { v: 52, en: 'Then enquired he of them the hour when he began to amend. And they said unto him, Yesterday at the seventh hour the fever left him.', pt: 'Perguntou-lhes a hora em que melhorou. E eles disseram: Ontem, à hora sétima, a febre o largou.' },
      { v: 53, en: 'So the father knew that it was at the same hour, in the which Jesus said unto him, Thy son liveth: and himself believed, and his whole house.', pt: 'O pai ficou sabendo que foi àquela hora em que Jesus lhe dissera: O teu filho vive; e creu ele, e toda a sua casa.' },
      { v: 54, en: 'This is again the second miracle that Jesus did, when he was come out of Judaea into Galilee.', pt: 'Este é de novo o segundo milagre que Jesus fez quando veio da Judeia para a Galileia.' },
    ],
    5: [
      { v: 1,  en: 'After this there was a feast of the Jews; and Jesus went up to Jerusalem.', pt: 'Depois destas coisas havia uma festa dos judeus, e Jesus subiu a Jerusalém.' },
      { v: 2,  en: 'Now there is at Jerusalem by the sheep market a pool, which is called in the Hebrew tongue Bethesda, having five porches.', pt: 'Ora, há em Jerusalém, junto à porta das Ovelhas, um tanque chamado em hebraico Betesda, com cinco pórticos.' },
      { v: 3,  en: 'In these lay a great multitude of impotent folk, of blind, halt, withered, waiting for the moving of the water.', pt: 'Nesses pórticos estava deitada uma grande multidão de enfermos, cegos, coxos, paralíticos, esperando o movimento da água.' },
      { v: 4,  en: 'For an angel went down at a certain season into the pool, and troubled the water: whosoever then first after the troubling of the water stepped in was made whole of whatsoever disease he had.', pt: 'Porque um anjo descia em certo tempo ao tanque e agitava a água; e o primeiro que entrasse depois da agitação da água ficava são de qualquer enfermidade que tivesse.' },
      { v: 5,  en: 'And a certain man was there, which had an infirmity thirty and eight years.', pt: 'E estava ali um homem que havia trinta e oito anos tinha uma enfermidade.' },
      { v: 6,  en: 'When Jesus saw him lie, and knew that he had been now a long time in that case, he saith unto him, Wilt thou be made whole?', pt: 'Jesus, vendo-o deitado e sabendo que estava assim há muito tempo, disse-lhe: Queres ficar são?' },
      { v: 7,  en: 'The impotent man answered him, Sir, I have no man, when the water is troubled, to put me into the pool: but while I am coming, another steppeth down before me.', pt: 'O enfermo respondeu-lhe: Senhor, não tenho homem que me coloque no tanque quando a água é agitada; entretanto, enquanto eu vou, outro desce antes de mim.' },
      { v: 8,  en: 'Jesus saith unto him, Rise, take up thy bed, and walk.', pt: 'Jesus disse-lhe: Levanta-te, toma o teu leito e anda.' },
      { v: 9,  en: 'And immediately the man was made whole, and took up his bed, and walked: and on the same day was the sabbath.', pt: 'E logo aquele homem ficou são, tomou o seu leito e andou; ora, naquele dia era sábado.' },
      { v: 10, en: 'The Jews therefore said unto him that was cured, It is the sabbath day: it is not lawful for thee to carry thy bed.', pt: 'Então os judeus disseram ao que fora curado: É o dia de sábado; não te é lícito carregar o teu leito.' },
      { v: 11, en: 'He answered them, He that made me whole, the same said unto me, Take up thy bed, and walk.', pt: 'Ele respondeu-lhes: O que me curou disse-me: Toma o teu leito e anda.' },
      { v: 12, en: 'Then asked they him, What man is that which said unto thee, Take up thy bed, and walk?', pt: 'Perguntaram-lhe então: Quem é o homem que te disse: Toma o teu leito e anda?' },
      { v: 13, en: 'And he that was healed wist not who it was: for Jesus had conveyed himself away, a multitude being in that place.', pt: 'E o que fora curado não sabia quem era; porque Jesus desaparecera, por haver muita gente naquele lugar.' },
      { v: 14, en: 'Afterward Jesus findeth him in the temple, and said unto him, Behold, thou art made whole: sin no more, lest a worse thing come unto thee.', pt: 'Depois Jesus o achou no templo e disse-lhe: Eis que estás são; não peques mais, para que não te aconteça coisa pior.' },
      { v: 15, en: 'The man departed, and told the Jews that it was Jesus, which had made him whole.', pt: 'O homem foi e anunciou aos judeus que Jesus era quem o havia curado.' },
      { v: 16, en: 'And therefore did the Jews persecute Jesus, and sought to slay him, because he had done these things on the sabbath day.', pt: 'Por isso os judeus perseguiam Jesus, porque ele fazia estas coisas no sábado.' },
      { v: 17, en: 'But Jesus answered them, My Father worketh hitherto, and I work.', pt: 'Mas Jesus respondeu-lhes: Meu Pai trabalha até agora, e eu trabalho também.' },
      { v: 18, en: 'Therefore the Jews sought the more to kill him, because he not only had broken the sabbath, but said also that God was his Father, making himself equal with God.', pt: 'Por isso, pois, os judeus ainda mais procuravam matá-lo, porque não somente violava o sábado, mas também dizia que Deus era seu Pai próprio, fazendo-se igual a Deus.' },
      { v: 19, en: 'Then answered Jesus and said unto them, Verily, verily, I say unto you, The Son can do nothing of himself, but what he seeth the Father do: for what things soever he doeth, these also doeth the Son likewise.', pt: 'Jesus, pois, respondeu e disse-lhes: Em verdade, em verdade vos digo que o Filho não pode fazer nada por si mesmo, senão o que vir fazer o Pai; porque tudo o que ele faz, o Filho também o faz da mesma forma.' },
      { v: 20, en: 'For the Father loveth the Son, and sheweth him all things that himself doeth: and he will shew him greater works than these, that ye may marvel.', pt: 'Porque o Pai ama o Filho e mostra-lhe tudo o que faz; e maiores obras do que estas lhe mostrará, para que vós vos maravilheis.' },
      { v: 21, en: 'For as the Father raiseth up the dead, and quickeneth them; even so the Son quickeneth whom he will.', pt: 'Porque assim como o Pai ressuscita os mortos e os vivifica, assim também o Filho vivifica os que quer.' },
      { v: 22, en: 'For the Father judgeth no man, but hath committed all judgment unto the Son:', pt: 'Porque o Pai a ninguém julga, mas deu ao Filho todo o julgamento,' },
      { v: 23, en: 'That all men should honour the Son, even as they honour the Father. He that honoureth not the Son honoureth not the Father which hath sent him.', pt: 'Para que todos honrem o Filho como honram o Pai. Quem não honra o Filho não honra o Pai que o enviou.' },
      { v: 24, en: 'Verily, verily, I say unto you, He that heareth my word, and believeth on him that sent me, hath everlasting life, and shall not come into condemnation; but is passed from death unto life.', pt: 'Em verdade, em verdade vos digo que quem ouve a minha palavra e crê naquele que me enviou tem a vida eterna e não entrará em condenação, mas passou da morte para a vida.' },
      { v: 25, en: 'Verily, verily, I say unto you, The hour is coming, and now is, when the dead shall hear the voice of the Son of God: and they that hear shall live.', pt: 'Em verdade, em verdade vos digo que a hora vem, e agora é, em que os mortos ouvirão a voz do Filho de Deus; e os que ouvirem viverão.' },
      { v: 26, en: 'For as the Father hath life in himself; so hath he given to the Son to have life in himself;', pt: 'Porque assim como o Pai tem a vida em si mesmo, assim deu também ao Filho que tivesse a vida em si mesmo.' },
      { v: 27, en: 'And hath given him authority to execute judgment also, because he is the Son of man.', pt: 'E deu-lhe autoridade para exercer também o julgamento, porque é o Filho do homem.' },
      { v: 28, en: 'Marvel not at this: for the hour is coming, in the which all that are in the graves shall hear his voice,', pt: 'Não vos maravilheis disto, porque a hora vem em que todos os que estão nos túmulos ouvirão a sua voz,' },
      { v: 29, en: 'And shall come forth; they that have done good, unto the resurrection of life; and they that have done evil, unto the resurrection of damnation.', pt: 'E sairão; os que fizeram o bem, para a ressurreição da vida; e os que fizeram o mal, para a ressurreição da condenação.' },
      { v: 30, en: 'I can of mine own self do nothing: as I hear, I judge: and my judgment is just; because I seek not mine own will, but the will of the Father which hath sent me.', pt: 'Não posso eu fazer nada por mim mesmo; julgo segundo ouço, e o meu juízo é justo, porque não busco a minha própria vontade, mas a vontade do Pai que me enviou.' },
      { v: 31, en: 'If I bear witness of myself, my witness is not true.', pt: 'Se eu testifico de mim mesmo, o meu testemunho não é verdadeiro.' },
      { v: 32, en: 'There is another that beareth witness of me; and I know that the witness which he witnesseth of me is true.', pt: 'Há outro que testifica de mim, e sei que o testemunho que ele dá de mim é verdadeiro.' },
      { v: 33, en: 'Ye sent unto John, and he bare witness unto the truth.', pt: 'Vós enviastes a João, e ele testificou da verdade.' },
      { v: 34, en: 'But I receive not testimony from man: but these things I say, that ye might be saved.', pt: 'Ora, eu não recebo testemunho da parte dos homens; mas digo isto para que sejais salvos.' },
      { v: 35, en: 'He was a burning and a shining light: and ye were willing for a season to rejoice in his light.', pt: 'Ele era a lâmpada que ardia e alumiava; e vós quisestes regozijar-vos por um tempo na sua luz.' },
      { v: 36, en: 'But I have greater witness than that of John: for the works which the Father hath given me to finish, the same works that I do, bear witness of me, that the Father hath sent me.', pt: 'Mas eu tenho testemunho maior do que o de João; porque as obras que o Pai me deu para realizar, as mesmas obras que eu faço, testificam de mim que o Pai me enviou.' },
      { v: 37, en: 'And the Father himself, which hath sent me, hath borne witness of me. Ye have neither heard his voice at any time, nor seen his shape.', pt: 'E o próprio Pai que me enviou testificou de mim. Nunca ouvis a sua voz, nem vistes a sua face.' },
      { v: 38, en: 'And ye have not his word abiding in you: for whom he hath sent, him ye believe not.', pt: 'Nem tendes a sua palavra permanecendo em vós, pois não credes naquele que ele enviou.' },
      { v: 39, en: 'Search the scriptures; for in them ye think ye have eternal life: and they are they which testify of me.', pt: 'Examinais as Escrituras, porque vós julgais ter nelas a vida eterna; e são elas que de mim testificam.' },
      { v: 40, en: 'And ye will not come to me, that ye might have life.', pt: 'E não quereis vir a mim para terdes vida.' },
      { v: 41, en: 'I receive not honour from men.', pt: 'Não recebo glória dos homens.' },
      { v: 42, en: 'But I know you, that ye have not the love of God in you.', pt: 'Mas conheço-vos, que não tendes em vós o amor de Deus.' },
      { v: 43, en: 'I am come in my Father\'s name, and ye receive me not: if another shall come in his own name, him ye will receive.', pt: 'Eu vim em nome de meu Pai, e não me recebeis; se outro vier em seu próprio nome, a esse recebereis.' },
      { v: 44, en: 'How can ye believe, which receive honour one of another, and seek not the honour that cometh from God only?', pt: 'Como podeis vós crer, vós que recebeis glória uns dos outros e não buscais a glória que vem só de Deus?' },
      { v: 45, en: 'Do not think that I will accuse you to the Father: there is one that accuseth you, even Moses, in whom ye trust.', pt: 'Não penseis que eu vos acusarei diante do Pai; há quem vos acuse, Moisés, em quem tendes esperança.' },
      { v: 46, en: 'For had ye believed Moses, ye would have believed me: for he wrote of me.', pt: 'Porque se crêsseis em Moisés, creríeis em mim; porque ele escreveu a meu respeito.' },
      { v: 47, en: 'But if ye believe not his writings, how shall ye believe my words?', pt: 'Mas se não credes nos seus escritos, como crereis nas minhas palavras?' },
    ],
    6: [
      { v: 1,  en: 'After these things Jesus went over the sea of Galilee, which is the sea of Tiberias.', pt: 'Depois destas coisas foi Jesus para o outro lado do mar da Galileia, o de Tiberíades.' },
      { v: 2,  en: 'And a great multitude followed him, because they saw his miracles which he did on them that were diseased.', pt: 'E seguia-o uma grande multidão, porque via os sinais que ele fazia nos que eram enfermos.' },
      { v: 3,  en: 'And Jesus went up into a mountain, and there he sat with his disciples.', pt: 'Jesus subiu ao monte e assentou-se ali com os seus discípulos.' },
      { v: 4,  en: 'And the passover, a feast of the Jews, was nigh.', pt: 'E a páscoa, a festa dos judeus, estava próxima.' },
      { v: 5,  en: 'When Jesus then lifted up his eyes, and saw a great company come unto him, he saith unto Philip, Whence shall we buy bread, that these may eat?', pt: 'Então Jesus, levantando os olhos e vendo que uma grande multidão vinha a ele, disse a Filipe: Onde compraremos pão para que esta gente coma?' },
      { v: 6,  en: 'And this he said to prove him: for he himself knew what he would do.', pt: 'Mas disse isso para o provar; porque ele mesmo sabia o que havia de fazer.' },
      { v: 7,  en: 'Philip answered him, Two hundred pennyworth of bread is not sufficient for them, that every one of them may take a little.', pt: 'Filipe respondeu-lhe: Duzentos denários de pão não lhes chegam para que cada um deles tome um pouco.' },
      { v: 8,  en: "One of his disciples, Andrew, Simon Peter's brother, saith unto him,", pt: 'Um dos seus discípulos, André, irmão de Simão Pedro, disse-lhe:' },
      { v: 9,  en: 'There is a lad here, which hath five barley loaves, and two small fishes: but what are they among so many?', pt: 'Está aqui um rapaz que tem cinco pães de cevada e dois peixinhos; mas que é isso para tanta gente?' },
      { v: 10, en: 'And Jesus said, Make the men sit down. Now there was much grass in the place. So the men sat down, in number about five thousand.', pt: 'Disse Jesus: Fazei assentar a gente. E havia muita erva naquele lugar. Os homens assentaram-se; eram quase cinco mil.' },
      { v: 11, en: 'And Jesus took the loaves; and when he had given thanks, he distributed to the disciples, and the disciples to them that were set down; and likewise of the fishes as much as they would.', pt: 'Então Jesus tomou os pães e, havendo dado graças, os distribuiu aos que estavam assentados; do mesmo modo os peixinhos, tanto quanto queriam.' },
      { v: 12, en: 'When they were filled, he said unto his disciples, Gather up the fragments that remain, that nothing be lost.', pt: 'Quando já estavam satisfeitos, disse aos seus discípulos: Recolhei os pedaços que sobejaram, para que nada se perca.' },
      { v: 13, en: 'Therefore they gathered them together, and filled twelve baskets with the fragments of the five barley loaves, which remained over and above unto them that had eaten.', pt: 'Colheram-nos, pois, e encheram doze cestos de pedaços dos cinco pães de cevada que sobejaram aos que comeram.' },
      { v: 14, en: 'Then those men, when they had seen the miracle that Jesus did, said, This is of a truth that prophet that should come into the world.', pt: 'Então aqueles homens, tendo visto o sinal que Jesus fizera, diziam: Este é verdadeiramente o profeta que havia de vir ao mundo.' },
      { v: 15, en: 'When Jesus therefore perceived that they would come and take him by force, to make him a king, he departed again into a mountain himself alone.', pt: 'Jesus, pois, sabendo que iam tomar-lhe para o fazerem rei, retirou-se outra vez para o monte, ele sozinho.' },
      { v: 16, en: 'And when even was now come, his disciples went down unto the sea,', pt: 'E logo que anoiteceu desceram ao mar os seus discípulos,' },
      { v: 17, en: 'And entered into a ship, and went over the sea toward Capernaum. And it was now dark, and Jesus was not come to them.', pt: 'E, entrando num barco, iam atravessando o mar para Cafarnaum. Já era escuro, e Jesus ainda não tinha vindo ter com eles.' },
      { v: 18, en: 'And the sea arose by reason of a great wind that blew.', pt: 'E o mar se encrespava com um vento forte que soprava.' },
      { v: 19, en: 'So when they had rowed about five and twenty or thirty furlongs, they see Jesus walking on the sea, and drawing nigh unto the ship: and they were afraid.', pt: 'E, tendo remado uns vinte e cinco ou trinta estádios, viram Jesus andando sobre o mar e aproximando-se do barco; e ficaram com medo.' },
      { v: 20, en: 'But he saith unto them, It is I; be not afraid.', pt: 'Mas ele disse-lhes: Sou eu; não temais.' },
      { v: 21, en: 'Then they willingly received him into the ship: and immediately the ship was at the land whither they went.', pt: 'Então de boa vontade o receberam no barco; e logo o barco chegou à terra a que iam.' },
      { v: 22, en: 'The day following, when the people which stood on the other side of the sea saw that there was none other boat there, save that one whereinto his disciples were entered, and that Jesus went not with his disciples into the boat, but that his disciples were gone away alone;', pt: 'No dia seguinte, a multidão que ficara do outro lado do mar viu que não havia lá nenhum outro barco, senão aquele em que os seus discípulos tinham entrado, e que Jesus não entrara com eles, mas que os seus discípulos tinham partido sozinhos.' },
      { v: 23, en: '(Howbeit there came other boats from Tiberias nigh unto the place where they did eat bread, after that the Lord had given thanks:)', pt: '(Porém vieram barcos de Tiberíades para perto do lugar onde comeram o pão, depois de o Senhor ter dado graças.)' },
      { v: 24, en: 'When the people therefore saw that Jesus was not there, neither his disciples, they also took shipping, and came to Capernaum, seeking for Jesus.', pt: 'Quando, pois, a multidão viu que Jesus não estava ali, nem os seus discípulos, eles mesmos entraram nos barcos e foram a Cafarnaum à procura de Jesus.' },
      { v: 25, en: 'And when they had found him on the other side of the sea, they said unto him, Rabbi, when camest thou hither?', pt: 'E, encontrando-o do outro lado do mar, disseram-lhe: Rabi, quando chegaste aqui?' },
      { v: 26, en: 'Jesus answered them and said, Verily, verily, I say unto you, Ye seek me, not because ye saw the miracles, but because ye did eat of the loaves, and were filled.', pt: 'Jesus respondeu-lhes: Em verdade, em verdade vos digo que me procurais, não porque vistes sinais, mas porque comestes do pão e vos fartastes.' },
      { v: 27, en: 'Labour not for the meat which perisheth, but for that meat which endureth unto everlasting life, which the Son of man shall give unto you: for him hath God the Father sealed.', pt: 'Trabalhai, não pela comida que perece, mas pela comida que permanece para a vida eterna, a qual o Filho do homem vos dará; porque Deus Pai é quem nele pôs o seu selo.' },
      { v: 28, en: 'Then said they unto him, What shall we do, that we might work the works of God?', pt: 'Disseram-lhe então: Que faremos para executarmos as obras de Deus?' },
      { v: 29, en: 'Jesus answered and said unto them, This is the work of God, that ye believe on him whom he hath sent.', pt: 'Jesus respondeu-lhes: A obra de Deus é esta: que creiais naquele que ele enviou.' },
      { v: 30, en: 'They said therefore unto him, What sign shewest thou then, that we may see, and believe thee? what dost thou work?', pt: 'Disseram-lhe então: Que sinal fazes tu, pois, para que vejamos e te creiamos? Que obra realizas?' },
      { v: 31, en: 'Our fathers did eat manna in the desert; as it is written, He gave them bread from heaven to eat.', pt: 'Os nossos pais comeram o maná no deserto, como está escrito: Deu-lhes a comer o pão do céu.' },
      { v: 32, en: 'Then Jesus said unto them, Verily, verily, I say unto you, Moses gave you not that bread from heaven; but my Father giveth you the true bread from heaven.', pt: 'Então Jesus lhes disse: Em verdade, em verdade vos digo que Moisés não vos deu o pão do céu; mas meu Pai vos dá o verdadeiro pão do céu.' },
      { v: 33, en: 'For the bread of God is he which cometh down from heaven, and giveth life unto the world.', pt: 'Porque o pão de Deus é aquele que desce do céu e dá vida ao mundo.' },
      { v: 34, en: 'Then said they unto him, Lord, evermore give us this bread.', pt: 'Disseram-lhe então: Senhor, dá-nos sempre desse pão.' },
      { v: 35, en: 'And Jesus said unto them, I am the bread of life: he that cometh to me shall never hunger; and he that believeth on me shall never thirst.', pt: 'Disse-lhes Jesus: Eu sou o pão da vida; aquele que vem a mim nunca terá fome, e o que crê em mim nunca terá sede.' },
      { v: 36, en: 'But I said unto you, That ye also have seen me, and believe not.', pt: 'Mas já vos disse que me tendes visto, e todavia não credes.' },
      { v: 37, en: 'All that the Father giveth me shall come to me; and him that cometh to me I will in no wise cast out.', pt: 'Tudo o que o Pai me dá virá a mim; e o que vier a mim, de modo algum o lançarei fora.' },
      { v: 38, en: 'For I came down from heaven, not to do mine own will, but the will of him that sent me.', pt: 'Porque desci do céu, não para fazer a minha vontade, mas a vontade daquele que me enviou.' },
      { v: 39, en: 'And this is the Father\'s will which hath sent me, that of all which he hath given me I should lose nothing, but should raise it up again at the last day.', pt: 'E a vontade do Pai que me enviou é esta: que eu não perca nenhum de todos os que ele me deu, mas que os ressuscite no último dia.' },
      { v: 40, en: 'And this is the will of him that sent me, that every one which seeth the Son, and believeth on him, may have everlasting life: and I will raise him up at the last day.', pt: 'Porque a vontade daquele que me enviou é esta: que todo aquele que vê o Filho e crê nele tenha a vida eterna; e eu o ressuscitarei no último dia.' },
      { v: 41, en: 'The Jews then murmured at him, because he said, I am the bread which came down from heaven.', pt: 'Os judeus então murmuravam dele porque havia dito: Eu sou o pão que desceu do céu.' },
      { v: 42, en: 'And they said, Is not this Jesus, the son of Joseph, whose father and mother we know? how is it then that he saith, I came down from heaven?', pt: 'E diziam: Não é este Jesus, o filho de José, cujo pai e mãe conhecemos? Como diz ele pois: Desci do céu?' },
      { v: 43, en: 'Jesus therefore answered and said unto them, Murmur not among yourselves.', pt: 'Jesus respondeu-lhes: Não murmureis entre vós.' },
      { v: 44, en: 'No man can come to me, except the Father which hath sent me draw him: and I will raise him up at the last day.', pt: 'Ninguém pode vir a mim se o Pai que me enviou não o trouxer; e eu o ressuscitarei no último dia.' },
      { v: 45, en: 'It is written in the prophets, And they shall be all taught of God. Every man therefore that hath heard, and hath learned of the Father, cometh unto me.', pt: 'Está escrito nos profetas: E serão todos ensinados por Deus. Portanto, todo aquele que ouviu o Pai e aprendeu dele vem a mim.' },
      { v: 46, en: 'Not that any man hath seen the Father, save he which is of God, he hath seen the Father.', pt: 'Não que alguém haja visto o Pai, senão aquele que é de Deus; esse viu o Pai.' },
      { v: 47, en: 'Verily, verily, I say unto you, He that believeth on me hath everlasting life.', pt: 'Em verdade, em verdade vos digo que quem crê em mim tem a vida eterna.' },
      { v: 48, en: 'I am that bread of life.', pt: 'Eu sou o pão da vida.' },
      { v: 49, en: 'Your fathers did eat manna in the wilderness, and are dead.', pt: 'Os vossos pais comeram o maná no deserto e morreram.' },
      { v: 50, en: 'This is the bread which cometh down from heaven, that a man may eat thereof, and not die.', pt: 'Este é o pão que desce do céu, para que o homem coma dele e não morra.' },
      { v: 51, en: 'I am the living bread which came down from heaven: if any man eat of this bread, he shall live for ever: and the bread that I will give is my flesh, which I will give for the life of the world.', pt: 'Eu sou o pão vivo que desceu do céu; se alguém comer deste pão, viverá eternamente; e o pão que eu darei é a minha carne, que eu darei pela vida do mundo.' },
      { v: 52, en: 'The Jews therefore strove among themselves, saying, How can this man give us his flesh to eat?', pt: 'Os judeus contendiam, pois, entre si, dizendo: Como pode este homem dar-nos a sua carne a comer?' },
      { v: 53, en: 'Then Jesus said unto them, Verily, verily, I say unto you, Except ye eat the flesh of the Son of man, and drink his blood, ye have no life in you.', pt: 'Então Jesus lhes disse: Em verdade, em verdade vos digo que se não comerdes a carne do Filho do homem e não beberdes o seu sangue, não tendes vida em vós mesmos.' },
      { v: 54, en: 'Whoso eateth my flesh, and drinketh my blood, hath eternal life; and I will raise him up at the last day.', pt: 'Quem come a minha carne e bebe o meu sangue tem a vida eterna, e eu o ressuscitarei no último dia.' },
      { v: 55, en: 'For my flesh is meat indeed, and my blood is drink indeed.', pt: 'Porque a minha carne é verdadeiramente comida, e o meu sangue é verdadeiramente bebida.' },
      { v: 56, en: 'He that eateth my flesh, and drinketh my blood, dwelleth in me, and I in him.', pt: 'Quem come a minha carne e bebe o meu sangue permanece em mim, e eu nele.' },
      { v: 57, en: 'As the living Father hath sent me, and I live by the Father: so he that eateth me, even he shall live by me.', pt: 'Assim como o Pai vivente me enviou, e eu vivo pelo Pai, assim também aquele que me come viverá por mim.' },
      { v: 58, en: 'This is that bread which came down from heaven: not as your fathers did eat manna, and are dead: he that eateth of this bread shall live for ever.', pt: 'Este é o pão que desceu do céu, não como o maná que os vossos pais comeram e morreram; quem come este pão viverá eternamente.' },
      { v: 59, en: 'These things said he in the synagogue, as he taught in Capernaum.', pt: 'Estas coisas disse ele na sinagoga, ensinando em Cafarnaum.' },
      { v: 60, en: 'Many therefore of his disciples, when they had heard this, said, This is an hard saying; who can hear it?', pt: 'Muitos, pois, dos seus discípulos, ouvindo isto, disseram: Dura é esta palavra; quem a pode ouvir?' },
      { v: 61, en: 'When Jesus knew in himself that his disciples murmured at it, he said unto them, Doth this offend you?', pt: 'Mas Jesus, conhecendo em si mesmo que os seus discípulos murmuravam a respeito disto, disse-lhes: Isso vos ofende?' },
      { v: 62, en: 'What and if ye shall see the Son of man ascend up where he was before?', pt: 'E se virdes o Filho do homem subir para onde estava antes?' },
      { v: 63, en: 'It is the spirit that quickeneth; the flesh profiteth nothing: the words that I speak unto you, they are spirit, and they are life.', pt: 'É o Espírito que vivifica; a carne para nada aproveita; as palavras que eu vos disse são espírito e são vida.' },
      { v: 64, en: 'But there are some of you that believe not. For Jesus knew from the beginning who they were that believed not, and who should betray him.', pt: 'Mas há alguns dentre vós que não creem. Porque Jesus sabia desde o princípio quem eram os que não cria, e quem o havia de trair.' },
      { v: 65, en: 'And he said, Therefore said I unto you, that no man can come unto me, except it were given unto him of my Father.', pt: 'E dizia: Por isso vos disse que ninguém pode vir a mim se não lhe for dado pelo Pai.' },
      { v: 66, en: 'From that time many of his disciples went back, and walked no more with him.', pt: 'Desde então muitos dos seus discípulos se retiraram e já não andavam com ele.' },
      { v: 67, en: 'Then said Jesus unto the twelve, Will ye also go away?', pt: 'Disse então Jesus aos doze: Quereis vós também retirar-vos?' },
      { v: 68, en: 'Then Simon Peter answered him, Lord, to whom shall we go? thou hast the words of eternal life.', pt: 'Respondeu-lhe Simão Pedro: Senhor, para quem iremos? Tu tens as palavras da vida eterna.' },
      { v: 69, en: 'And we believe and are sure that thou art that Christ, the Son of the living God.', pt: 'E nós cremos e conhecemos que tu és o Cristo, o Filho do Deus vivo.' },
      { v: 70, en: 'Jesus answered them, Have not I chosen you twelve, and one of you is a devil?', pt: 'Jesus respondeu-lhes: Não escolhi eu a vós doze? E um de vós é diabo.' },
      { v: 71, en: 'He spake of Judas Iscariot the son of Simon: for he it was that should betray him, being one of the twelve.', pt: 'Ele falava de Judas Iscariotes, filho de Simão, porque este havia de traí-lo, sendo um dos doze.' },
    ],
    7: [
      { v: 1,  en: 'After these things Jesus walked in Galilee: for he would not walk in Jewry, because the Jews sought to kill him.', pt: 'Depois destas coisas andava Jesus pela Galileia; porque não queria andar pela Judeia, pois os judeus procuravam matá-lo.' },
      { v: 2,  en: 'Now the Jews\' feast of tabernacles was at hand.', pt: 'E estava próxima a festa dos judeus, a dos Tabernáculos.' },
      { v: 3,  en: 'His brethren therefore said unto him, Depart hence, and go into Judaea, that thy disciples also may see the works that thou doest.', pt: 'Os seus irmãos disseram-lhe então: Parte daqui e vai para a Judeia, para que também os teus discípulos vejam as obras que fazes.' },
      { v: 4,  en: 'For there is no man that doeth any thing in secret, and he himself seeketh to be known openly. If thou do these things, shew thyself to the world.', pt: 'Porque ninguém faz coisa alguma em segredo quando quer ser conhecido publicamente. Se fazes estas coisas, manifesta-te ao mundo.' },
      { v: 5,  en: 'For neither did his brethren believe in him.', pt: 'Porque nem os seus irmãos criam nele.' },
      { v: 6,  en: 'Then Jesus said unto them, My time is not yet come: but your time is alway ready.', pt: 'Disse-lhes então Jesus: O meu tempo ainda não chegou; mas o vosso tempo está sempre pronto.' },
      { v: 7,  en: 'The world cannot hate you; but me it hateth, because I testify of it, that the works thereof are evil.', pt: 'O mundo não vos pode odiar; a mim, porém, odeia-me, porque eu testifico a seu respeito que as suas obras são más.' },
      { v: 8,  en: 'Go ye up unto this feast: I go not up yet unto this feast; for my time is not yet full come.', pt: 'Subi vós a esta festa; eu não subo ainda a esta festa, porque o meu tempo ainda não está cumprido.' },
      { v: 9,  en: 'When he had said these words unto them, he abode still in Galilee.', pt: 'E, tendo dito isto, ficou na Galileia.' },
      { v: 10, en: 'But when his brethren were gone up, then went he also up unto the feast, not openly, but as it were in secret.', pt: 'Mas depois que os seus irmãos subiram à festa, então ele também subiu, não manifestamente, mas como em segredo.' },
      { v: 11, en: 'Then the Jews sought him at the feast, and said, Where is he?', pt: 'Os judeus, pois, procuravam-no na festa e diziam: Onde está ele?' },
      { v: 12, en: 'And there was much murmuring among the people concerning him: for some said, He is a good man: others said, Nay; but he deceiveth the people.', pt: 'E havia entre o povo muito murmúrio acerca dele; uns diziam: É bom; outros diziam: Não, antes engana o povo.' },
      { v: 13, en: 'Howbeit no man spake openly of him for fear of the Jews.', pt: 'Todavia ninguém falava abertamente nele, por medo dos judeus.' },
      { v: 14, en: 'Now about the midst of the feast Jesus went up into the temple, and taught.', pt: 'Ora, no meio da festa subiu Jesus ao templo e ensinava.' },
      { v: 15, en: 'And the Jews marvelled, saying, How knoweth this man letters, having never learned?', pt: 'E os judeus maravilhavam-se, dizendo: Como sabe este as Escrituras, não as tendo estudado?' },
      { v: 16, en: 'Jesus answered them, and said, My doctrine is not mine, but his that sent me.', pt: 'Jesus respondeu-lhes e disse: A minha doutrina não é minha, mas daquele que me enviou.' },
      { v: 17, en: 'If any man will do his will, he shall know of the doctrine, whether it be of God, or whether I speak of myself.', pt: 'Se alguém quiser fazer a sua vontade, conhecerá a respeito da doutrina se ela é de Deus ou se eu falo por mim mesmo.' },
      { v: 18, en: 'He that speaketh of himself seeketh his own glory: but he that seeketh his glory that sent him, the same is true, and no unrighteousness is in him.', pt: 'Quem fala por si mesmo busca a sua própria glória; mas quem busca a glória daquele que o enviou, esse é verdadeiro, e não há injustiça nele.' },
      { v: 19, en: 'Did not Moses give you the law, and yet none of you keepeth the law? Why go ye about to kill me?', pt: 'Não vos deu Moisés a lei? E nenhum de vós guarda a lei. Por que procurais matar-me?' },
      { v: 20, en: 'The people answered and said, Thou hast a devil: who goeth about to kill thee?', pt: 'A multidão respondeu: Tens demônio; quem procura matar-te?' },
      { v: 21, en: 'Jesus answered and said unto them, I have done one work, and ye all marvel.', pt: 'Jesus respondeu e disse-lhes: Fiz uma obra, e todos vós vos maravilhais.' },
      { v: 22, en: 'Moses therefore gave unto you circumcision; (not because it is of Moses, but of the fathers;) and ye on the sabbath day circumcise a man.', pt: 'Moisés vos deu a circuncisão (não que seja de Moisés, mas dos pais), e vós no sábado circuncidais um homem.' },
      { v: 23, en: 'If a man on the sabbath day receive circumcision, that the law of Moses should not be broken; are ye angry at me, because I have made a man every whit whole on the sabbath day?', pt: 'Se o homem recebe a circuncisão no sábado, para que não seja violada a lei de Moisés, por que vos indignais contra mim porque no sábado curei um homem todo inteiro?' },
      { v: 24, en: 'Judge not according to the appearance, but judge righteous judgment.', pt: 'Não julgueis segundo a aparência, mas julgai com juízo justo.' },
      { v: 25, en: 'Then said some of them of Jerusalem, Is not this he, whom they seek to kill?', pt: 'Diziam então alguns dos que eram de Jerusalém: Não é este aquele que procuram matar?' },
      { v: 26, en: 'But, lo, he speaketh boldly, and they say nothing unto him. Do the rulers know indeed that this is the very Christ?', pt: 'E eis que fala publicamente, e nada lhe dizem. Terão os príncipes reconhecido verdadeiramente que este é o Cristo?' },
      { v: 27, en: 'Howbeit we know this man whence he is: but when Christ cometh, no man knoweth whence he is.', pt: 'Mas este, sabemos de onde é; quando, porém, vier o Cristo, ninguém saberá de onde ele é.' },
      { v: 28, en: 'Then cried Jesus in the temple as he taught, saying, Ye both know me, and ye know whence I am: and I am not come of myself, but he that sent me is true, whom ye know not.', pt: 'Então Jesus exclamou no templo, ensinando e dizendo: Vós me conheceis, e sabeis de onde sou; e eu não vim por mim mesmo, mas aquele que me enviou é verdadeiro, o qual vós não conheceis.' },
      { v: 29, en: 'But I know him: for I am from him, and he hath sent me.', pt: 'Mas eu o conheço, porque sou dele, e ele me enviou.' },
      { v: 30, en: 'Then they sought to take him: but no man laid hands on him, because his hour was not yet come.', pt: 'Procuravam então prendê-lo; e ninguém pôs nele as mãos, porque ainda não era chegada a sua hora.' },
      { v: 31, en: 'And many of the people believed on him, and said, When Christ cometh, will he do more miracles than these which this man hath done?', pt: 'Mas muitos da multidão creram nele e diziam: O Cristo, quando vier, fará mais sinais do que os que este fez?' },
      { v: 32, en: 'The Pharisees heard that the people murmured such things concerning him; and the Pharisees and the chief priests sent officers to take him.', pt: 'Os fariseus ouviram a multidão murmurar estas coisas acerca dele; e os fariseus e os principais sacerdotes enviaram oficiais para o prender.' },
      { v: 33, en: 'Then said Jesus unto them, Yet a little while am I with you, and then I go unto him that sent me.', pt: 'Então disse Jesus: Ainda um pouco de tempo estou convosco e depois vou àquele que me enviou.' },
      { v: 34, en: 'Ye shall seek me, and shall not find me: and where I am, thither ye cannot come.', pt: 'Buscar-me-eis e não me achareis; e onde eu estiver, vós não podeis ir.' },
      { v: 35, en: 'Then said the Jews among themselves, Whither will he go, that we shall not find him? will he go unto the dispersed among the Gentiles, and teach the Gentiles?', pt: 'Os judeus, pois, disseram entre si: Para onde irá ele, que não o possamos encontrar? Irá para a dispersão entre os gregos e ensinará os gregos?' },
      { v: 36, en: 'What manner of saying is this that he said, Ye shall seek me, and shall not find me: and where I am, thither ye cannot come?', pt: 'Que palavra é esta que disse: Buscar-me-eis e não me achareis; e onde eu estiver, vós não podeis ir?' },
      { v: 37, en: 'In the last day, that great day of the feast, Jesus stood and cried, saying, If any man thirst, let him come unto me, and drink.', pt: 'No último dia, o grande dia da festa, Jesus pôs-se em pé e exclamou: Se alguém tem sede, venha a mim e beba.' },
      { v: 38, en: 'He that believeth on me, as the scripture hath said, out of his belly shall flow rivers of living water.', pt: 'Quem crê em mim, como diz a Escritura, rios de água viva correrão do seu interior.' },
      { v: 39, en: '(But this spake he of the Spirit, which they that believe on him should receive: for the Holy Ghost was not yet given; because that Jesus was not yet glorified.)', pt: '(Isto disse ele acerca do Espírito, que os que nele cressem deveriam receber; porque o Espírito Santo ainda não fora dado, pois Jesus não fora ainda glorificado.)' },
      { v: 40, en: 'Many of the people therefore, when they heard this saying, said, Of a truth this is the Prophet.', pt: 'Muitos pois da multidão, ouvindo estas palavras, diziam: Este é verdadeiramente o profeta.' },
      { v: 41, en: 'Others said, This is the Christ. But some said, Shall Christ come out of Galilee?', pt: 'Outros diziam: Este é o Cristo. Mas outros diziam: Não virá o Cristo da Galileia?' },
      { v: 42, en: 'Hath not the scripture said, That Christ cometh of the seed of David, and out of the town of Bethlehem, where David was?', pt: 'Não diz a Escritura que o Cristo há de vir da descendência de Davi e de Belém, a aldeia onde estava Davi?' },
      { v: 43, en: 'So there was a division among the people because of him.', pt: 'Houve pois divisão entre a multidão por causa dele.' },
      { v: 44, en: 'And some of them would have taken him; but no man laid hands on him.', pt: 'E alguns deles queriam prendê-lo; mas ninguém pôs nele as mãos.' },
      { v: 45, en: 'Then came the officers to the chief priests and Pharisees; and they said unto them, Why have ye not brought him?', pt: 'Então os oficiais foram ter com os principais sacerdotes e fariseus; e estes lhes perguntaram: Por que não o trouxestes?' },
      { v: 46, en: 'The officers answered, Never man spake like this man.', pt: 'Os oficiais responderam: Nunca homem algum falou como este homem.' },
      { v: 47, en: 'Then answered them the Pharisees, Are ye also deceived?', pt: 'Os fariseus lhes responderam: Porventura também vós fostes enganados?' },
      { v: 48, en: 'Have any of the rulers or of the Pharisees believed on him?', pt: 'Acaso algum dos príncipes creu nele, ou dos fariseus?' },
      { v: 49, en: 'But this people who knoweth not the law are cursed.', pt: 'Mas esta multidão, que não conhece a lei, é maldita.' },
      { v: 50, en: 'Nicodemus saith unto them, (he that came to Jesus by night, being one of them,)', pt: 'Nicodemos, que de noite viera ter com ele, sendo um deles, disse-lhes:' },
      { v: 51, en: 'Doth our law judge any man, before it hear him, and know what he doeth?', pt: 'Porventura condena a nossa lei o homem sem primeiro o ouvir e conhecer o que fez?' },
      { v: 52, en: 'They answered and said unto him, Art thou also of Galilee? Search, and look: for out of Galilee ariseth no prophet.', pt: 'Eles responderam e disseram-lhe: Porventura és tu também galileu? Pesquisa e vê que da Galileia não surge profeta.' },
      { v: 53, en: 'And every man went unto his own house.', pt: 'E cada um se foi para sua casa.' },
    ],
    8: [
      { v: 1,  en: 'Jesus went unto the mount of Olives.', pt: 'Jesus foi para o monte das Oliveiras.' },
      { v: 2,  en: 'And early in the morning he came again into the temple, and all the people came unto him; and he sat down, and taught them.', pt: 'E pela manhã cedo voltou ao templo, e todo o povo veio a ele; e, assentando-se, os ensinava.' },
      { v: 3,  en: 'And the scribes and Pharisees brought unto him a woman taken in adultery; and when they had set her in the midst,', pt: 'Então os escribas e fariseus trouxeram-lhe uma mulher apanhada em adultério, e, pondo-a no meio,' },
      { v: 4,  en: 'They say unto him, Master, this woman was taken in adultery, in the very act.', pt: 'Disseram-lhe: Mestre, esta mulher foi apanhada no próprio ato do adultério.' },
      { v: 5,  en: 'Now Moses in the law commanded us, that such should be stoned: but what sayest thou?', pt: 'Ora, na lei nos mandou Moisés que tais mulheres fossem apedrejadas; tu, pois, que dizes?' },
      { v: 6,  en: 'This they said, tempting him, that they might have to accuse him. But Jesus stooped down, and with his finger wrote on the ground, as though he heard them not.', pt: 'Isto diziam tentando-o, para que tivessem de que o acusar. Mas Jesus, inclinando-se, escrevia com o dedo na terra.' },
      { v: 7,  en: 'So when they continued asking him, he lifted up himself, and said unto them, He that is without sin among you, let him first cast a stone at her.', pt: 'Como, porém, insistissem em perguntar-lhe, endireitou-se e disse-lhes: Aquele que dentre vós está sem pecado seja o primeiro que lhe atire uma pedra.' },
      { v: 8,  en: 'And again he stooped down, and wrote on the ground.', pt: 'E, tornando a inclinar-se, escrevia na terra.' },
      { v: 9,  en: 'And they which heard it, being convicted by their own conscience, went out one by one, beginning at the eldest, even unto the last: and Jesus was left alone, and the woman standing in the midst.', pt: 'Eles, porém, ouvindo isto e acusados pela consciência, foram saindo um a um, a começar pelos mais velhos; e ficou só Jesus, com a mulher que estava no meio.' },
      { v: 10, en: 'When Jesus had lifted up himself, and saw none but the woman, he said unto her, Woman, where are those thine accusers? hath no man condemned thee?', pt: 'Levantando-se Jesus, e não vendo ninguém senão a mulher, disse-lhe: Mulher, onde estão os teus acusadores? Ninguém te condenou?' },
      { v: 11, en: 'She said, No man, Lord. And Jesus said unto her, Neither do I condemn thee: go, and sin no more.', pt: 'Disse ela: Ninguém, Senhor. E Jesus disse-lhe: Nem eu te condeno; vai e não peques mais.' },
      { v: 12, en: 'Then spake Jesus again unto them, saying, I am the light of the world: he that followeth me shall not walk in darkness, but shall have the light of life.', pt: 'Jesus, pois, falou-lhes de novo: Eu sou a luz do mundo; quem me segue não andará em trevas, mas terá a luz da vida.' },
      { v: 13, en: 'The Pharisees therefore said unto him, Thou bearest record of thyself; thy record is not true.', pt: 'Os fariseus disseram-lhe então: Tu testemunhas de ti mesmo; o teu testemunho não é verdadeiro.' },
      { v: 14, en: 'Jesus answered and said unto them, Though I bear record of myself, yet my record is true: for I know whence I came, and whither I go; but ye cannot tell whence I come, and whither I go.', pt: 'Jesus respondeu e disse-lhes: Ainda que eu testifico de mim mesmo, o meu testemunho é verdadeiro, porque sei de onde vim e para onde vou; mas vós não sabeis de onde venho, nem para onde vou.' },
      { v: 15, en: 'Ye judge after the flesh; I judge no man.', pt: 'Vós julgais segundo a carne; eu não julgo ninguém.' },
      { v: 16, en: 'And yet if I judge, my judgment is true: for I am not alone, but I and the Father that sent me.', pt: 'E, ainda que eu julgue, o meu juízo é verdadeiro, porque não estou só, mas eu e o Pai que me enviou.' },
      { v: 17, en: 'It is also written in your law, that the testimony of two men is true.', pt: 'Também está escrito na vossa lei que o testemunho de dois homens é verdadeiro.' },
      { v: 18, en: 'I am one that bear witness of myself, and the Father that sent me beareth witness of me.', pt: 'Sou eu que de mim mesmo testifico, e o Pai que me enviou testifica de mim.' },
      { v: 19, en: 'Then said they unto him, Where is thy Father? Jesus answered, Ye neither know me, nor my Father: if ye had known me, ye should have known my Father also.', pt: 'Disseram-lhe então: Onde está o teu Pai? Jesus respondeu: Não me conheceis a mim, nem a meu Pai; se me conhecêsseis a mim, também conheceríeis a meu Pai.' },
      { v: 20, en: 'These words spake Jesus in the treasury, as he taught in the temple: and no man laid hands on him; for his hour was not yet come.', pt: 'Estas palavras disse Jesus junto ao local dos cofres do tesouro, ensinando no templo; e ninguém o prendeu, porque ainda não era chegada a sua hora.' },
      { v: 21, en: 'Then said Jesus again unto them, I go my way, and ye shall seek me, and shall die in your sins: whither I go, ye cannot come.', pt: 'Então disse-lhes Jesus de novo: Eu vou, e vós me buscareis, e morrereis no vosso pecado; para onde eu vou, vós não podeis ir.' },
      { v: 22, en: 'Then said the Jews, Will he kill himself? because he saith, Whither I go, ye cannot come.', pt: 'Diziam pois os judeus: Porventura se matará, pois diz: Para onde eu vou, vós não podeis ir?' },
      { v: 23, en: 'And he said unto them, Ye are from beneath; I am from above: ye are of this world; I am not of this world.', pt: 'E dizia-lhes: Vós sois de baixo; eu sou de cima. Vós sois deste mundo; eu não sou deste mundo.' },
      { v: 24, en: 'I said therefore unto you, that ye shall die in your sins: for if ye believe not that I am he, ye shall die in your sins.', pt: 'Por isso vos disse que morrereis nos vossos pecados; porque, se não credes que Eu Sou, morrereis nos vossos pecados.' },
      { v: 25, en: 'Then said they unto him, Who art thou? And Jesus saith unto them, Even the same that I said unto you from the beginning.', pt: 'Disseram-lhe então: Quem és tu? Jesus disse-lhes: Mesmo o que desde o princípio vos tenho dito.' },
      { v: 26, en: 'I have many things to say and to judge of you: but he that sent me is true; and I speak to the world those things which I have heard of him.', pt: 'Tenho muitas coisas a dizer e a julgar acerca de vós; mas aquele que me enviou é verdadeiro; e o que dele ouvi isso digo ao mundo.' },
      { v: 27, en: 'They understood not that he spake to them of the Father.', pt: 'Eles não entenderam que lhes falava do Pai.' },
      { v: 28, en: 'Then said Jesus unto them, When ye have lifted up the Son of man, then shall ye know that I am he, and that I do nothing of myself; but as my Father hath taught me, I speak these things.', pt: 'Disse-lhes então Jesus: Quando levantardes o Filho do homem, então conhecereis que Eu Sou, e que nada faço por mim mesmo, mas que falo estas coisas como meu Pai me ensinou.' },
      { v: 29, en: 'And he that sent me is with me: the Father hath not left me alone; for I do always those things that please him.', pt: 'E aquele que me enviou está comigo; o Pai não me deixou só, porque eu faço sempre as coisas que lhe agradam.' },
      { v: 30, en: 'As he spake these words, many believed on him.', pt: 'Dizendo ele estas coisas, muitos creram nele.' },
      { v: 31, en: 'Then said Jesus to those Jews which believed on him, If ye continue in my word, then are ye my disciples indeed;', pt: 'Disse então Jesus aos judeus que creram nele: Se vós permanecerdes na minha palavra, verdadeiramente sereis meus discípulos;' },
      { v: 32, en: 'And ye shall know the truth, and the truth shall make you free.', pt: 'E conhecereis a verdade, e a verdade vos libertará.' },
      { v: 33, en: 'They answered him, We be Abraham\'s seed, and were never in bondage to any man: how sayest thou, Ye shall be made free?', pt: 'Responderam-lhe: Somos descendência de Abraão e jamais fomos escravos de ninguém; como dizes tu: Sereis livres?' },
      { v: 34, en: 'Jesus answered them, Verily, verily, I say unto you, Whosoever committeth sin is the servant of sin.', pt: 'Jesus respondeu-lhes: Em verdade, em verdade vos digo que todo aquele que comete pecado é escravo do pecado.' },
      { v: 35, en: 'And the servant abideth not in the house for ever: but the Son abideth ever.', pt: 'Ora, o escravo não fica para sempre em casa; mas o filho fica para sempre.' },
      { v: 36, en: 'If the Son therefore shall make you free, ye shall be free indeed.', pt: 'Portanto, se o Filho vos libertar, verdadeiramente sereis livres.' },
      { v: 37, en: 'I know that ye are Abraham\'s seed; but ye seek to kill me, because my word hath no place in you.', pt: 'Sei que sois descendência de Abraão; mas procurais matar-me, porque a minha palavra não tem lugar em vós.' },
      { v: 38, en: 'I speak that which I have seen with my Father: and ye do that which ye have seen with your father.', pt: 'Eu falo o que vi junto de meu Pai; e vós fazeis o que ouvistes de vosso pai.' },
      { v: 39, en: 'They answered and said unto him, Abraham is our father. Jesus saith unto them, If ye were Abraham\'s children, ye would do the works of Abraham.', pt: 'Responderam e disseram-lhe: Nosso pai é Abraão. Jesus disse-lhes: Se fôsseis filhos de Abraão, faríeis as obras de Abraão.' },
      { v: 40, en: 'But now ye seek to kill me, a man that hath told you the truth, which I have heard of God: this did not Abraham.', pt: 'Mas agora procurais matar-me, a mim, homem que vos disse a verdade, a qual ouvi de Deus; Abraão não fez isto.' },
      { v: 41, en: 'Ye do the deeds of your father. Then said they to him, We be not born of fornication; we have one Father, even God.', pt: 'Vós fazeis as obras de vosso pai. Disseram-lhe então: Nós não somos nascidos de prostituição; temos um só Pai, que é Deus.' },
      { v: 42, en: 'Jesus said unto them, If God were your Father, ye would love me: for I proceeded forth and came from God; neither came I of myself, but he sent me.', pt: 'Jesus lhes disse: Se Deus fosse o vosso Pai, certamente me amaríeis, porque eu saí de Deus e de Deus vim; pois não vim por mim mesmo, mas ele me enviou.' },
      { v: 43, en: 'Why do ye not understand my speech? even because ye cannot hear my word.', pt: 'Por que não compreendeis a minha linguagem? Porque não podeis ouvir a minha palavra.' },
      { v: 44, en: 'Ye are of your father the devil, and the lusts of your father ye will do. He was a murderer from the beginning, and abode not in the truth, because there is no truth in him. When he speaketh a lie, he speaketh of his own: for he is a liar, and the father of it.', pt: 'Vós tendes por pai o diabo, e quereis satisfazer os seus desejos. Ele era homicida desde o princípio e não se firmou na verdade, porque não há verdade nele. Quando ele profere mentira, fala do que lhe é próprio, porque é mentiroso e pai da mentira.' },
      { v: 45, en: 'And because I tell you the truth, ye believe me not.', pt: 'E porque eu digo a verdade, não me credes.' },
      { v: 46, en: 'Which of you convinceth me of sin? And if I say the truth, why do ye not believe me?', pt: 'Quem dentre vós me convence de pecado? Se digo a verdade, por que não me credes?' },
      { v: 47, en: 'He that is of God heareth God\'s words: ye therefore hear them not, because ye are not of God.', pt: 'Quem é de Deus ouve as palavras de Deus; por isso vós não as ouvis, porque não sois de Deus.' },
      { v: 48, en: 'Then answered the Jews, and said unto him, Say we not well that thou art a Samaritan, and hast a devil?', pt: 'Os judeus responderam-lhe: Não dizemos nós bem que és samaritano e que tens demônio?' },
      { v: 49, en: 'Jesus answered, I have not a devil; but I honour my Father, and ye do dishonour me.', pt: 'Jesus respondeu: Eu não tenho demônio; antes honro a meu Pai, e vós me desonrais.' },
      { v: 50, en: 'And I seek not mine own glory: there is one that seeketh and judgeth.', pt: 'Não busco a minha própria glória; há quem a busque e julgue.' },
      { v: 51, en: 'Verily, verily, I say unto you, If a man keep my saying, he shall never see death.', pt: 'Em verdade, em verdade vos digo que se alguém guardar a minha palavra, não verá a morte eternamente.' },
      { v: 52, en: 'Then said the Jews unto him, Now we know that thou hast a devil. Abraham is dead, and the prophets; and thou sayest, If a man keep my saying, he shall never taste of death.', pt: 'Os judeus disseram-lhe então: Agora conhecemos que tens demônio. Abraão morreu, e os profetas; e tu dizes: Se alguém guardar a minha palavra, não provará a morte eternamente.' },
      { v: 53, en: 'Art thou greater than our father Abraham, which is dead? and the prophets are dead: whom makest thou thyself?', pt: 'Porventura és tu maior do que nosso pai Abraão, que morreu? E os profetas também morreram. Quem te fazes tu?' },
      { v: 54, en: 'Jesus answered, If I honour myself, my honour is nothing: it is my Father that honoureth me; of whom ye say, that he is your God:', pt: 'Jesus respondeu: Se eu me glorifico a mim mesmo, a minha glória nada é; é o meu Pai que me glorifica, aquele de quem vós dizeis que é o vosso Deus.' },
      { v: 55, en: 'Yet ye have not known him; but I know him: and if I should say, I know him not, I shall be a liar like unto you: but I know him, and keep his saying.', pt: 'E vós não o conheceis, mas eu o conheço; e se dissesse que não o conheço, seria mentiroso como vós; mas eu o conheço e guardo a sua palavra.' },
      { v: 56, en: 'Your father Abraham rejoiced to see my day: and he saw it, and was glad.', pt: 'Abraão, vosso pai, exultou por ver o meu dia; viu-o e alegrou-se.' },
      { v: 57, en: 'Then said the Jews unto him, Thou art not yet fifty years old, and hast thou seen Abraham?', pt: 'Disseram-lhe então os judeus: Ainda não tens cinquenta anos e viste Abraão?' },
      { v: 58, en: 'Jesus said unto them, Verily, verily, I say unto you, Before Abraham was, I am.', pt: 'Disse-lhes Jesus: Em verdade, em verdade vos digo que antes que Abraão existisse, Eu Sou.' },
      { v: 59, en: 'Then took they up stones to cast at him: but Jesus hid himself, and went out of the temple, going through the midst of them, and so passed by.', pt: 'Então pegaram em pedras para lhe atirarem; mas Jesus ocultou-se e saiu do templo, passando pelo meio deles.' },
    ],
    9: [
      { v: 1,  en: 'And as Jesus passed by, he saw a man which was blind from his birth.', pt: 'E, passando Jesus, viu um homem cego de nascença.' },
      { v: 2,  en: 'And his disciples asked him, saying, Master, who did sin, this man, or his parents, that he was born blind?', pt: 'E os seus discípulos lhe perguntaram: Rabi, quem pecou, este ou seus pais, para que nascesse cego?' },
      { v: 3,  en: 'Jesus answered, Neither hath this man sinned, nor his parents: but that the works of God should be made manifest in him.', pt: 'Jesus respondeu: Nem este pecou, nem seus pais; mas foi assim para que se manifestem nele as obras de Deus.' },
      { v: 4,  en: 'I must work the works of him that sent me, while it is day: the night cometh, when no man can work.', pt: 'Importa que eu realize as obras daquele que me enviou, enquanto é dia; a noite vem quando ninguém pode trabalhar.' },
      { v: 5,  en: 'As long as I am in the world, I am the light of the world.', pt: 'Enquanto estou no mundo, sou a luz do mundo.' },
      { v: 6,  en: 'When he had thus spoken, he spat on the ground, and made clay of the spittle, and he anointed the eyes of the blind man with the clay,', pt: 'Dito isto, cuspiu na terra, fez lama com a saliva e untou os olhos do cego com a lama,' },
      { v: 7,  en: 'And said unto him, Go, wash in the pool of Siloam, (which is by interpretation, Sent.) He went his way therefore, and washed, and came seeing.', pt: 'E disse-lhe: Vai, lava-te no tanque de Siloé (que se traduz, Enviado). Foi pois, lavou-se, e voltou vendo.' },
      { v: 8,  en: 'The neighbours therefore, and they which before had seen him that he was blind, said, Is not this he that sat and begged?', pt: 'Os vizinhos, pois, e os que o tinham visto de antes, que era cego, diziam: Não é este aquele que estava assentado e mendigava?' },
      { v: 9,  en: 'Some said, This is he: others said, He is like him: but he said, I am he.', pt: 'Uns diziam: É este. Outros diziam: É semelhante a ele. Ele dizia: Sou eu.' },
      { v: 10, en: 'Therefore said they unto him, How were thine eyes opened?', pt: 'Disseram-lhe então: Como se te abriram os olhos?' },
      { v: 11, en: 'He answered and said, A man that is called Jesus made clay, and anointed mine eyes, and said unto me, Go to the pool of Siloam, and wash: and I went and washed, and I received sight.', pt: 'Ele respondeu: O homem chamado Jesus fez lama, untou os meus olhos e disse-me: Vai ao tanque de Siloé e lava-te. Fui, lavei-me e recebi a vista.' },
      { v: 12, en: 'Then said they unto him, Where is he? He said, I know not.', pt: 'Disseram-lhe: Onde está ele? Respondeu: Não sei.' },
      { v: 13, en: 'They brought to the Pharisees him that aforetime was blind.', pt: 'Levaram aos fariseus aquele que fora cego.' },
      { v: 14, en: 'And it was the sabbath day when Jesus made the clay, and opened his eyes.', pt: 'Ora, era sábado quando Jesus fez a lama e lhe abriu os olhos.' },
      { v: 15, en: 'Then again the Pharisees also asked him how he had received his sight. He said unto them, He put clay upon mine eyes, and I washed, and do see.', pt: 'Os fariseus pois perguntaram-lhe também como recebera a vista. Ele disse-lhes: Pôs-me lama sobre os olhos, lavei-me e vejo.' },
      { v: 16, en: 'Therefore said some of the Pharisees, This man is not of God, because he keepeth not the sabbath day. Others said, How can a man that is a sinner do such miracles? And there was a division among them.', pt: 'Então alguns dos fariseus diziam: Este homem não é de Deus, porque não guarda o sábado. Outros, porém, diziam: Como pode um homem pecador fazer tais sinais? E havia divisão entre eles.' },
      { v: 17, en: 'They say unto the blind man again, What sayest thou of him, that he hath opened thine eyes? He said, He is a prophet.', pt: 'Perguntaram de novo ao cego: Tu que dizes dele, pois te abriu os olhos? Disse ele: É um profeta.' },
      { v: 18, en: 'But the Jews did not believe concerning him, that he had been blind, and received his sight, until they called the parents of him that had received his sight.', pt: 'Os judeus, pois, não creram a respeito dele que fora cego e recebera a vista, até que chamaram os pais do que recebera a vista.' },
      { v: 19, en: 'And they asked them, saying, Is this your son, who ye say was born blind? how then doth he now see?', pt: 'E lhes perguntaram: É este o vosso filho de quem dizeis que nasceu cego? Como é que agora vê?' },
      { v: 20, en: 'His parents answered them and said, We know that this is our son, and that he was born blind:', pt: 'Responderam-lhes os seus pais: Sabemos que este é o nosso filho e que nasceu cego;' },
      { v: 21, en: 'But by what means he now seeth, we know not; or who hath opened his eyes, we know not: he is of age; ask him: he shall speak for himself.', pt: 'Mas como agora vê, não o sabemos; nem sabemos quem lhe abriu os olhos; perguntai-lhe a ele; tem idade, falará por si mesmo.' },
      { v: 22, en: 'These words spake his parents, because they feared the Jews: for the Jews had agreed already, that if any man did confess that he was Christ, he should be put out of the synagogue.', pt: 'Isto disseram seus pais porque temiam os judeus; pois os judeus já tinham estabelecido que, se alguém o confessasse como Cristo, fosse expulso da sinagoga.' },
      { v: 23, en: 'Therefore said his parents, He is of age; ask him.', pt: 'Por isso os seus pais disseram: Tem idade; perguntai-lhe a ele.' },
      { v: 24, en: 'Then again called they the man that was blind, and said unto him, Give God the praise: we know that this man is a sinner.', pt: 'Chamaram de novo o homem que fora cego e disseram-lhe: Dá glória a Deus; nós sabemos que esse homem é pecador.' },
      { v: 25, en: 'He answered and said, Whether he be a sinner or no, I know not: one thing I know, that, whereas I was blind, now I see.', pt: 'Ele respondeu: Se é pecador, não sei; uma coisa sei: que era cego e agora vejo.' },
      { v: 26, en: 'Then said they to him again, What did he to thee? how opened he thine eyes?', pt: 'Disseram-lhe então: Que te fez ele? Como te abriu os olhos?' },
      { v: 27, en: 'He answered them, I have told you already, and ye did not hear: wherefore would ye hear it again? will ye also be his disciples?', pt: 'Respondeu-lhes: Já vo-lo disse, e não escutastes; por que quereis ouvi-lo de novo? Porventura quereis também vós tornar-vos seus discípulos?' },
      { v: 28, en: 'Then they reviled him, and said, Thou art his disciple; but we are Moses\' disciples.', pt: 'Então o injuriaram e disseram: Tu és discípulo dele; nós somos discípulos de Moisés.' },
      { v: 29, en: 'We know that God spake unto Moses: as for this fellow, we know not from whence he is.', pt: 'Sabemos que Deus falou a Moisés; mas este, não sabemos de onde é.' },
      { v: 30, en: 'The man answered and said unto them, Why herein is a marvellous thing, that ye know not from whence he is, and yet he hath opened mine eyes.', pt: 'Respondeu-lhes o homem: Ora, nisso está o espantoso: que vós não sabeis de onde ele é, e todavia me abriu os olhos.' },
      { v: 31, en: 'Now we know that God heareth not sinners: but if any man be a worshipper of God, and doeth his will, him he heareth.', pt: 'Ora, sabemos que Deus não ouve os pecadores; mas, se alguém é temente a Deus e faz a sua vontade, a esse ouve.' },
      { v: 32, en: 'Since the world began was it not heard that any man opened the eyes of one that was born blind.', pt: 'Desde o princípio do mundo não se ouviu que alguém abrisse os olhos a um homem que nasceu cego.' },
      { v: 33, en: 'If this man were not of God, he could do nothing.', pt: 'Se este não fosse de Deus, não poderia fazer nada.' },
      { v: 34, en: 'They answered and said unto him, Thou wast altogether born in sins, and dost thou teach us? And they cast him out.', pt: 'Responderam-lhe: Tu nasceste em pecados totalmente, e nos ensinas? E o expulsaram.' },
      { v: 35, en: 'Jesus heard that they had cast him out; and when he had found him, he said unto him, Dost thou believe on the Son of God?', pt: 'Ouviu Jesus que o haviam expulsado; e, achando-o, disse-lhe: Crês tu no Filho de Deus?' },
      { v: 36, en: 'He answered and said, Who is he, Lord, that I might believe on him?', pt: 'Respondeu ele: Quem é, Senhor, para que eu creia nele?' },
      { v: 37, en: 'And Jesus said unto him, Thou hast both seen him, and it is he that talketh with thee.', pt: 'Disse-lhe Jesus: Tu já o viste, e o que fala contigo é ele mesmo.' },
      { v: 38, en: 'And he said, Lord, I believe. And he worshipped him.', pt: 'E ele disse: Creio, Senhor. E o adorou.' },
      { v: 39, en: 'And Jesus said, For judgment I am come into this world, that they which see not might see; and that they which see might be made blind.', pt: 'E Jesus disse: Eu vim a este mundo para juízo, para que os que não vêem vejam e os que vêem se tornem cegos.' },
      { v: 40, en: 'And some of the Pharisees which were with him heard these words, and said unto him, Are we blind also?', pt: 'E alguns dos fariseus, que estavam com ele, ouviram estas coisas e disseram-lhe: Porventura somos nós também cegos?' },
      { v: 41, en: 'Jesus said unto them, If ye were blind, ye should have no sin: but now ye say, We see; therefore your sin remaineth.', pt: 'Jesus disse-lhes: Se fôsseis cegos, não teríeis pecado; mas agora dizeis: Vemos; por isso o vosso pecado permanece.' },
    ],
    10: [
      { v: 1,  en: 'Verily, verily, I say unto you, He that entereth not by the door into the sheepfold, but climbeth up some other way, the same is a thief and a robber.', pt: 'Em verdade, em verdade vos digo que aquele que não entra pela porta no aprisco das ovelhas, mas sobe por outro lugar, é ladrão e assaltante.' },
      { v: 2,  en: 'But he that entereth in by the door is the shepherd of the sheep.', pt: 'Mas aquele que entra pela porta é o pastor das ovelhas.' },
      { v: 3,  en: 'To him the porter openeth; and the sheep hear his voice: and he calleth his own sheep by name, and leadeth them out.', pt: 'O porteiro abre-lhe a porta, e as ovelhas ouvem a sua voz; e ele chama as suas próprias ovelhas pelo nome e as conduz para fora.' },
      { v: 4,  en: 'And when he putteth forth his own sheep, he goeth before them, and the sheep follow him: for they know his voice.', pt: 'E, quando tiver tirado as suas próprias ovelhas, vai adiante delas, e as ovelhas o seguem, porque conhecem a sua voz.' },
      { v: 5,  en: 'And a stranger will they not follow, but will flee from him: for they know not the voice of strangers.', pt: 'Mas não seguirão um estranho, antes fugirão dele, porque não conhecem a voz dos estranhos.' },
      { v: 6,  en: 'This parable spake Jesus unto them: but they understood not what things they were which he spake unto them.', pt: 'Jesus disse-lhes esta parábola; mas eles não entenderam o que lhes dizia.' },
      { v: 7,  en: 'Then said Jesus unto them again, Verily, verily, I say unto you, I am the door of the sheep.', pt: 'Disse-lhes, pois, Jesus de novo: Em verdade, em verdade vos digo que eu sou a porta das ovelhas.' },
      { v: 8,  en: 'All that ever came before me are thieves and robbers: but the sheep did not hear them.', pt: 'Todos quantos vieram antes de mim são ladrões e assaltantes; mas as ovelhas não os ouviram.' },
      { v: 9,  en: 'I am the door: by me if any man enter in, he shall be saved, and shall go in and out, and find pasture.', pt: 'Eu sou a porta; se alguém entrar por mim, será salvo, e entrará, e sairá, e achará pasto.' },
      { v: 10, en: 'The thief cometh not, but for to steal, and to kill, and to destroy: I am come that they might have life, and that they might have it more abundantly.', pt: 'O ladrão não vem senão a roubar, e a matar, e a destruir; eu vim para que tenham vida e a tenham com abundância.' },
      { v: 11, en: 'I am the good shepherd: the good shepherd giveth his life for the sheep.', pt: 'Eu sou o bom pastor; o bom pastor dá a sua vida pelas ovelhas.' },
      { v: 12, en: 'But he that is an hireling, and not the shepherd, whose own the sheep are not, seeth the wolf coming, and leaveth the sheep, and fleeth: and the wolf catcheth them, and scattereth the sheep.', pt: 'Mas o assalariado, e o que não é o pastor, de quem não são próprias as ovelhas, vê chegar o lobo e abandona as ovelhas e foge; e o lobo as arrebata e dispersa.' },
      { v: 13, en: 'The hireling fleeth, because he is an hireling, and careth not for the sheep.', pt: 'O assalariado foge porque é assalariado e não tem cuidado das ovelhas.' },
      { v: 14, en: 'I am the good shepherd, and know my sheep, and am known of mine.', pt: 'Eu sou o bom pastor, e conheço as minhas ovelhas, e as minhas ovelhas me conhecem a mim.' },
      { v: 15, en: 'As the Father knoweth me, even so know I the Father: and I lay down my life for the sheep.', pt: 'Assim como o Pai me conhece, também eu conheço o Pai; e dou a minha vida pelas ovelhas.' },
      { v: 16, en: 'And other sheep I have, which are not of this fold: them also I must bring, and they shall hear my voice; and there shall be one fold, and one shepherd.', pt: 'Tenho também outras ovelhas que não são deste aprisco; também essas me importa trazer, e ouvirão a minha voz; e haverá um só rebanho e um só pastor.' },
      { v: 17, en: 'Therefore doth my Father love me, because I lay down my life, that I might take it again.', pt: 'O Pai me ama por isso: porque dou a minha vida para a tornar a tomar.' },
      { v: 18, en: 'No man taketh it from me, but I lay it down of myself. I have power to lay it down, and I have power to take it again. This commandment have I received of my Father.', pt: 'Ninguém ma tira, mas eu a dou por mim mesmo; tenho poder para a dar, e poder para tornar a tomá-la. Este mandamento recebi de meu Pai.' },
      { v: 19, en: 'There was a division therefore again among the Jews for these sayings.', pt: 'Houve novamente divisão entre os judeus por causa destas palavras.' },
      { v: 20, en: 'And many of them said, He hath a devil, and is mad; why hear ye him?', pt: 'E muitos deles diziam: Tem demônio e está louco; por que o ouvis?' },
      { v: 21, en: 'Others said, These are not the words of him that hath a devil. Can a devil open the eyes of the blind?', pt: 'Outros diziam: Estas palavras não são de um endemoninhado. Pode um demônio abrir os olhos dos cegos?' },
      { v: 22, en: 'And it was at Jerusalem the feast of the dedication, and it was winter.', pt: 'Realizou-se então em Jerusalém a festa da Dedicação; era inverno.' },
      { v: 23, en: 'And Jesus walked in the temple in Solomon\'s porch.', pt: 'E Jesus andava no templo, no pórtico de Salomão.' },
      { v: 24, en: 'Then came the Jews round about him, and said unto him, How long dost thou make us to doubt? If thou be the Christ, tell us plainly.', pt: 'Rodearam-no pois os judeus e disseram-lhe: Até quando nos deixarás em suspenso? Se tu és o Cristo, dize-nos francamente.' },
      { v: 25, en: 'Jesus answered them, I told you, and ye believed not: the works that I do in my Father\'s name, they bear witness of me.', pt: 'Jesus respondeu-lhes: Disse-vos, e não credes; as obras que faço em nome de meu Pai, essas testificam de mim.' },
      { v: 26, en: 'But ye believe not, because ye are not of my sheep, as I said unto you.', pt: 'Mas vós não credes, porque não sois das minhas ovelhas, como vos disse.' },
      { v: 27, en: 'My sheep hear my voice, and I know them, and they follow me:', pt: 'As minhas ovelhas ouvem a minha voz, e eu as conheço, e elas me seguem.' },
      { v: 28, en: 'And I give unto them eternal life; and they shall never perish, neither shall any man pluck them out of my hand.', pt: 'E eu lhes dou a vida eterna, e nunca hão de perecer, e ninguém as arrebatará da minha mão.' },
      { v: 29, en: 'My Father, which gave them me, is greater than all; and no man is able to pluck them out of my Father\'s hand.', pt: 'Meu Pai, que mas deu, é maior de todos, e ninguém pode arrebatá-las da mão de meu Pai.' },
      { v: 30, en: 'I and my Father are one.', pt: 'Eu e o Pai somos um.' },
      { v: 31, en: 'Then the Jews took up stones again to stone him.', pt: 'Os judeus novamente pegaram em pedras para o apedrejar.' },
      { v: 32, en: 'Jesus answered them, Many good works have I shewed you from my Father; for which of those works do ye stone me?', pt: 'Jesus respondeu-lhes: Mostrei-vos muitas boas obras da parte de meu Pai; por qual dessas obras me apedrejais?' },
      { v: 33, en: 'The Jews answered him, saying, For a good work we stone thee not; but for blasphemy; and because that thou, being a man, makest thyself God.', pt: 'Responderam-lhe os judeus: Por boa obra não te apedrejamos, mas por blasfêmia e porque tu, sendo homem, te fazes Deus.' },
      { v: 34, en: 'Jesus answered them, Is it not written in your law, I said, Ye are gods?', pt: 'Jesus respondeu-lhes: Não está escrito na vossa lei: Eu disse: Sois deuses?' },
      { v: 35, en: 'If he called them gods, unto whom the word of God came, and the scripture cannot be broken;', pt: 'Se ele chamou deuses àqueles a quem a palavra de Deus foi dirigida (e a Escritura não pode ser anulada),' },
      { v: 36, en: 'Say ye of him, whom the Father hath sanctified, and sent into the world, Thou blasphemest; because I said, I am the Son of God?', pt: 'Dizeis vós ao que o Pai santificou e enviou ao mundo: Blasfemas! Porque disse: Sou o Filho de Deus?' },
      { v: 37, en: 'If I do not the works of my Father, believe me not.', pt: 'Se não faço as obras de meu Pai, não me creiais.' },
      { v: 38, en: 'But if I do, though ye believe not me, believe the works: that ye may know, and believe, that the Father is in me, and I in him.', pt: 'Mas se as faço, ainda que não me creieis a mim, crede nas obras, para que saibais e reconheçais que o Pai está em mim e eu no Pai.' },
      { v: 39, en: 'Therefore they sought again to take him: but he escaped out of their hand,', pt: 'Procuravam então prendê-lo de novo; mas ele escapou das suas mãos,' },
      { v: 40, en: 'And went away again beyond Jordan into the place where John at first baptized; and there he abode.', pt: 'E foi de novo para além do Jordão, ao lugar onde João primeiro batizou; e ficou ali.' },
      { v: 41, en: 'And many resorted unto him, and said, John did no miracle: but all things that John spake of this man were true.', pt: 'E muitos vieram a ele e diziam: João não fez nenhum sinal; mas tudo o que João disse acerca deste era verdade.' },
      { v: 42, en: 'And many believed on him there.', pt: 'E muitos ali creram nele.' },
    ],
    11: [
      { v: 1,  en: 'Now a certain man was sick, named Lazarus, of Bethany, the town of Mary and her sister Martha.', pt: 'Estava enfermo um certo Lázaro, de Betânia, da aldeia de Maria e de sua irmã Marta.' },
      { v: 2,  en: 'It was that Mary which anointed the Lord with ointment, and wiped his feet with her hair, whose brother Lazarus was sick.', pt: '(Maria era aquela que ungiu o Senhor com ungüento e lhe enxugou os pés com seus cabelos, cujo irmão Lázaro estava enfermo.)' },
      { v: 3,  en: 'Therefore his sisters sent unto him, saying, Lord, behold, he whom thou lovest is sick.', pt: 'As irmãs, pois, mandaram dizer-lhe: Senhor, eis que aquele que amas está enfermo.' },
      { v: 4,  en: 'When Jesus heard that, he said, This sickness is not unto death, but for the glory of God, that the Son of God might be glorified thereby.', pt: 'Jesus, tendo ouvido isso, disse: Esta enfermidade não é para morte, mas para a glória de Deus, para que o Filho de Deus seja glorificado por ela.' },
      { v: 5,  en: 'Now Jesus loved Martha, and her sister, and Lazarus.', pt: 'E Jesus amava a Marta, e a sua irmã, e Lázaro.' },
      { v: 6,  en: 'When he had heard therefore that he was sick, he abode two days still in the same place where he was.', pt: 'Quando ouviu, pois, que estava doente, ficou ainda dois dias no lugar onde estava.' },
      { v: 7,  en: 'Then after that saith he to his disciples, Let us go into Judaea again.', pt: 'Depois disto disse aos discípulos: Tornemos à Judeia.' },
      { v: 8,  en: 'His disciples say unto him, Master, the Jews of late sought to stone thee; and goest thou thither again?', pt: 'Os discípulos disseram-lhe: Rabi, há pouco os judeus procuravam apedrejar-te, e tornas para lá?' },
      { v: 9,  en: 'Jesus answered, Are there not twelve hours in the day? If any man walk in the day, he stumbleth not, because he seeth the light of this world.', pt: 'Jesus respondeu: Não são doze as horas do dia? Se alguém andar de dia, não tropeça, porque vê a luz deste mundo.' },
      { v: 10, en: 'But if a man walk in the night, he stumbleth, because there is no light in him.', pt: 'Mas se andar de noite, tropeça, porque não há nele luz.' },
      { v: 11, en: 'These things said he: and after that he saith unto them, Our friend Lazarus sleepeth; but I go, that I may awake him out of sleep.', pt: 'Disse estas coisas; e depois acrescentou: O nosso amigo Lázaro dorme; mas vou despertá-lo.' },
      { v: 12, en: 'Then said his disciples, Lord, if he sleep, he shall do well.', pt: 'Disseram-lhe então os discípulos: Senhor, se dorme, ficará bom.' },
      { v: 13, en: 'Howbeit Jesus spake of his death: but they thought that he had spoken of taking of rest in sleep.', pt: 'Jesus, porém, dissera isso da morte dele; mas eles julgavam que falara do repouso do sono.' },
      { v: 14, en: 'Then said Jesus unto them plainly, Lazarus is dead.', pt: 'Então Jesus lhes disse abertamente: Lázaro morreu.' },
      { v: 15, en: 'And I am glad for your sakes that I was not there, to the intent ye may believe; nevertheless let us go unto him.', pt: 'E folgo por vossa causa de não ter estado lá, para que creiais; mas vamos ter com ele.' },
      { v: 16, en: 'Then said Thomas, which is called Didymus, unto his fellowdisciples, Let us also go, that we may die with him.', pt: 'Então Tomé, chamado Dídimo, disse aos condiscípulos: Vamos também nós, para que morramos com ele.' },
      { v: 17, en: 'Then when Jesus came, he found that he had lain in the grave four days already.', pt: 'Quando Jesus chegou, achou que Lázaro já estava há quatro dias no sepulcro.' },
      { v: 18, en: 'Now Bethany was nigh unto Jerusalem, about fifteen furlongs off:', pt: 'Ora, Betânia ficava perto de Jerusalém, a uns quinze estádios.' },
      { v: 19, en: 'And many of the Jews came to Martha and Mary, to comfort them concerning their brother.', pt: 'E muitos dos judeus tinham vindo ter com Marta e Maria para as consolarem acerca do irmão.' },
      { v: 20, en: 'Then Martha, as soon as she heard that Jesus was coming, went and met him: but Mary sat still in the house.', pt: 'Logo que Marta ouviu que Jesus vinha, foi ao seu encontro; mas Maria ficou em casa.' },
      { v: 21, en: 'Then said Martha unto Jesus, Lord, if thou hadst been here, my brother had not died.', pt: 'Disse então Marta a Jesus: Senhor, se tu estiveras aqui, meu irmão não morreria.' },
      { v: 22, en: 'But I know, that even now, whatsoever thou wilt ask of God, God will give it thee.', pt: 'Mas também sei que tudo quanto pedires a Deus, Deus to dará.' },
      { v: 23, en: 'Jesus saith unto her, Thy brother shall rise again.', pt: 'Jesus disse-lhe: O teu irmão ressuscitará.' },
      { v: 24, en: 'Martha saith unto him, I know that he shall rise again in the resurrection at the last day.', pt: 'Marta disse-lhe: Sei que ressuscitará na ressurreição, no último dia.' },
      { v: 25, en: 'Jesus said unto her, I am the resurrection, and the life: he that believeth in me, though he were dead, yet shall he live:', pt: 'Jesus disse-lhe: Eu sou a ressurreição e a vida; quem crê em mim, ainda que morra, viverá.' },
      { v: 26, en: 'And whosoever liveth and believeth in me shall never die. Believest thou this?', pt: 'E todo aquele que vive e crê em mim não morrerá eternamente. Crês isto?' },
      { v: 27, en: 'She saith unto him, Yea, Lord: I believe that thou art the Christ, the Son of God, which should come into the world.', pt: 'Disse-lhe: Sim, Senhor; eu creio que tu és o Cristo, o Filho de Deus, que havia de vir ao mundo.' },
      { v: 28, en: 'And when she had so said, she went her way, and called Mary her sister secretly, saying, The Master is come, and calleth for thee.', pt: 'E, dizendo isto, foi chamar em segredo a Maria, sua irmã, dizendo: O Mestre está aqui e chama por ti.' },
      { v: 29, en: 'As soon as she heard that, she arose quickly, and came unto him.', pt: 'Ela, quando ouviu isso, levantou-se depressa e foi ter com ele.' },
      { v: 30, en: 'Now Jesus was not yet come into the town, but was in that place where Martha met him.', pt: 'Jesus ainda não havia entrado na aldeia, mas estava ainda no lugar onde Marta o encontrara.' },
      { v: 31, en: 'The Jews then which were with her in the house, and comforted her, when they saw Mary, that she rose up hastily and went out, followed her, saying, She goeth unto the grave to weep there.', pt: 'Os judeus, pois, que estavam com ela em casa e a consolavam, vendo que Maria se levantara apressadamente e saíra, seguiram-na, dizendo: Vai ao sepulcro chorar.' },
      { v: 32, en: 'Then when Mary was come where Jesus was, and saw him, she fell down at his feet, saying unto him, Lord, if thou hadst been here, my brother had not died.', pt: 'Maria, pois, quando chegou onde estava Jesus, e o viu, prostrou-se a seus pés, dizendo-lhe: Senhor, se tu estiveras aqui, não teria morrido o meu irmão.' },
      { v: 33, en: 'When Jesus therefore saw her weeping, and the Jews also weeping which came with her, he groaned in the spirit, and was troubled,', pt: 'Quando Jesus a viu chorando, e os judeus que vieram com ela também chorando, indignou-se no espírito e conturbou-se,' },
      { v: 34, en: 'And said, Where have ye laid him? They said unto him, Lord, come and see.', pt: 'E disse: Onde o pusestes? Disseram-lhe: Senhor, vem e vê.' },
      { v: 35, en: 'Jesus wept.', pt: 'Jesus chorou.' },
      { v: 36, en: 'Then said the Jews, Behold how he loved him!', pt: 'Diziam então os judeus: Vede como o amava!' },
      { v: 37, en: 'And some of them said, Could not this man, which opened the eyes of the blind, have caused that even this man should not have died?', pt: 'Mas alguns deles disseram: Não podia este, que abriu os olhos ao cego, fazer também que este não morresse?' },
      { v: 38, en: 'Jesus therefore again groaning in himself cometh to the sepulchre. It was a cave, and a stone lay upon it.', pt: 'Jesus, pois, novamente indignado em si mesmo, veio ao sepulcro. Era uma gruta, e sobre ela estava posta uma pedra.' },
      { v: 39, en: 'Jesus said, Take ye away the stone. Martha, the sister of him that was dead, saith unto him, Lord, by this time he stinketh: for he hath been dead four days.', pt: 'Disse Jesus: Tirai a pedra. Disse-lhe Marta, irmã do morto: Senhor, já cheira mal, pois há quatro dias que está sepultado.' },
      { v: 40, en: 'Jesus saith unto her, Said I not unto thee, that, if thou wouldest believe, thou shouldest see the glory of God?', pt: 'Disse-lhe Jesus: Não te disse eu que, se creres, verás a glória de Deus?' },
      { v: 41, en: 'Then they took away the stone from the place where the dead was laid. And Jesus lifted up his eyes, and said, Father, I thank thee that thou hast heard me.', pt: 'Tiraram então a pedra. E Jesus levantou os olhos para o alto e disse: Pai, graças te dou porque me ouviste.' },
      { v: 42, en: 'And I knew that thou hearest me always: but because of the people which stand by I said it, that they may believe that thou hast sent me.', pt: 'E eu sabia que sempre me ouves; mas disse-o por causa da multidão que está em redor, para que creiam que tu me enviaste.' },
      { v: 43, en: 'And when he thus had spoken, he cried with a loud voice, Lazarus, come forth.', pt: 'E dito isto, clamou com grande voz: Lázaro, vem para fora.' },
      { v: 44, en: 'And he that was dead came forth, bound hand and foot with graveclothes: and his face was bound about with a napkin. Jesus saith unto them, Loose him, and let him go.', pt: 'E saiu o que estava morto, com as mãos e os pés atados com faixas, e o seu rosto envolto num sudário. Jesus disse-lhes: Desatai-o e deixai-o ir.' },
      { v: 45, en: 'Then many of the Jews which came to Mary, and had seen the things which Jesus did, believed on him.', pt: 'Muitos dos judeus, pois, que vieram ter com Maria e viram o que Jesus fez, creram nele.' },
      { v: 46, en: 'But some of them went their ways to the Pharisees, and told them what things Jesus had done.', pt: 'Mas alguns deles foram ter com os fariseus e contaram-lhes o que Jesus tinha feito.' },
      { v: 47, en: 'Then gathered the chief priests and the Pharisees a council, and said, What do we? for this man doeth many miracles.', pt: 'Então os principais sacerdotes e os fariseus convocaram o conselho e disseram: Que fazemos? Porque este homem faz muitos sinais.' },
      { v: 48, en: 'If we let him thus alone, all men will believe on him: and the Romans shall come and take away both our place and nation.', pt: 'Se o deixarmos assim, todos crerão nele; e virão os romanos e destruirão tanto o nosso lugar como a nação.' },
      { v: 49, en: 'And one of them, named Caiaphas, being the high priest that same year, said unto them, Ye know nothing at all,', pt: 'Mas um deles, Caifás, que era sumo sacerdote naquele ano, disse-lhes: Vós não sabeis nada,' },
      { v: 50, en: 'Nor consider that it is expedient for us, that one man should die for the people, and that the whole nation perish not.', pt: 'Nem ponderais que nos convém que um só homem morra pelo povo, e que não pereça toda a nação.' },
      { v: 51, en: 'And this spake he not of himself: but being high priest that year, he prophesied that Jesus should die for that nation;', pt: 'Ora, ele não disse isso por si mesmo; mas, sendo sumo sacerdote naquele ano, profetizou que Jesus havia de morrer pela nação;' },
      { v: 52, en: 'And not for that nation only, but that also he should gather together in one the children of God that were scattered abroad.', pt: 'E não somente pela nação, mas também para reunir em um só corpo os filhos de Deus que andavam dispersos.' },
      { v: 53, en: 'Then from that day forth they took counsel together for to put him to death.', pt: 'Desde aquele dia, pois, deliberaram que o matassem.' },
      { v: 54, en: 'Jesus therefore walked no more openly among the Jews; but went thence unto a country near to the wilderness, into a city called Ephraim, and there continued with his disciples.', pt: 'Por isso Jesus não andava mais publicamente entre os judeus; mas retirou-se dali para uma cidade chamada Efraim, numa região perto do deserto, e ali permaneceu com os seus discípulos.' },
      { v: 55, en: 'And the Jews\' passover was nigh at hand: and many went out of the country up to Jerusalem before the passover, to purify themselves.', pt: 'E estava próxima a páscoa dos judeus, e muitos da região subiram a Jerusalém antes da páscoa para se purificarem.' },
      { v: 56, en: 'Then sought they for Jesus, and spake among themselves, as they stood in the temple, What think ye, that he will not come to the feast?', pt: 'Buscavam, pois, a Jesus e, estando no templo, diziam uns aos outros: Que vos parece? Não virá ele à festa?' },
      { v: 57, en: 'Now both the chief priests and the Pharisees had given a commandment, that, if any man knew where he were, he should shew it, that they might take him.', pt: 'Ora, os principais sacerdotes e os fariseus tinham dado ordens de que, se alguém soubesse onde ele estava, o denunciasse, para que o prendessem.' },
    ],
    12: [
      { v: 1,  en: 'Then Jesus six days before the passover came to Bethany, where Lazarus was which had been dead, whom he raised from the dead.', pt: 'Jesus, pois, seis dias antes da páscoa, veio a Betânia, onde estava Lázaro, a quem Jesus ressuscitara dos mortos.' },
      { v: 2,  en: 'There they made him a supper; and Martha served: but Lazarus was one of them that sat at the table with him.', pt: 'Ali fizeram-lhe uma ceia; e Marta servia; e Lázaro era um dos que estavam à mesa com ele.' },
      { v: 3,  en: 'Then took Mary a pound of ointment of spikenard, very costly, and anointed the feet of Jesus, and wiped his feet with her hair: and the house was filled with the odour of the ointment.', pt: 'Maria então tomou uma libra de ungüento de nardo puro, de muito valor, e ungiu os pés de Jesus, e enxugou-lhos com os seus cabelos; e a casa encheu-se com o odor do ungüento.' },
      { v: 4,  en: 'Then saith one of his disciples, Judas Iscariot, Simon\'s son, which should betray him,', pt: 'Então disse Judas Iscariotes, um dos seus discípulos, aquele que o havia de trair:' },
      { v: 5,  en: 'Why was not this ointment sold for three hundred pence, and given to the poor?', pt: 'Por que não se vendeu este ungüento por trezentos denários para se dar aos pobres?' },
      { v: 6,  en: 'This he said, not that he cared for the poor; but because he was a thief, and had the bag, and bare what was put therein.', pt: 'Ora, disse isto não porque se importasse com os pobres, mas porque era ladrão, e, tendo a bolsa, furtava o que nela se lançava.' },
      { v: 7,  en: 'Then said Jesus, Let her alone: against the day of my burying hath she kept this.', pt: 'Disse então Jesus: Deixa-a; ela guardou isto para o dia da minha sepultura.' },
      { v: 8,  en: 'For the poor always ye have with you; but me ye have not always.', pt: 'Porque os pobres sempre os tendes convosco, mas a mim não me tendes sempre.' },
      { v: 9,  en: 'Much people of the Jews therefore knew that he was there: and they came not for Jesus\' sake only, but that they might see Lazarus also, whom he had raised from the dead.', pt: 'Uma grande multidão dos judeus soube que ele estava ali; e vieram, não somente por causa de Jesus, mas também para verem Lázaro, a quem ressuscitara dos mortos.' },
      { v: 10, en: 'But the chief priests consulted that they might put Lazarus also to death;', pt: 'Os principais sacerdotes, porém, deliberaram matar também Lázaro,' },
      { v: 11, en: 'Because that by reason of him many of the Jews went away, and believed on Jesus.', pt: 'Porque por causa dele muitos dos judeus se retiravam e criam em Jesus.' },
      { v: 12, en: 'On the next day much people that were come to the feast, when they heard that Jesus was coming to Jerusalem,', pt: 'No dia seguinte, uma grande multidão que viera para a festa, ouvindo que Jesus vinha a Jerusalém,' },
      { v: 13, en: 'Took branches of palm trees, and went forth to meet him, and cried, Hosanna: Blessed is the King of Israel that cometh in the name of the Lord.', pt: 'Tomou ramos de palmeiras e saiu a recebê-lo, e clamava: Hosana! Bendito o que vem em nome do Senhor, o rei de Israel!' },
      { v: 14, en: 'And Jesus, when he had found a young ass, sat thereon; as it is written,', pt: 'E Jesus, achando um jumentinho, montou nele, como está escrito:' },
      { v: 15, en: 'Fear not, daughter of Sion: behold, thy King cometh, sitting on an ass\'s colt.', pt: 'Não temas, ó filha de Sião; eis que o teu Rei vem montado num jumentinho.' },
      { v: 16, en: 'These things understood not his disciples at the first: but when Jesus was glorified, then remembered they that these things were written of him, and that they had done these things unto him.', pt: 'Os seus discípulos não entenderam estas coisas a princípio; mas quando Jesus foi glorificado, então se lembraram de que estas coisas estavam escritas a respeito dele e que lhas tinham feito.' },
      { v: 17, en: 'The people therefore that was with him when he called Lazarus out of his grave, and raised him from the dead, bare record.', pt: 'A multidão, pois, que estava com ele quando chamara Lázaro do sepulcro e o ressuscitara dos mortos, dava testemunho.' },
      { v: 18, en: 'For this cause the people also met him, for that they heard that he had done this miracle.', pt: 'Por isso também a multidão foi recebê-lo, porque tinham ouvido que ele fizera este sinal.' },
      { v: 19, en: 'The Pharisees therefore said among themselves, Perceive ye how ye prevail nothing? behold, the world is gone after him.', pt: 'Os fariseus disseram então entre si: Vedes que nada aproveitais? Eis que o mundo foi após ele.' },
      { v: 20, en: 'And there were certain Greeks among them that came up to worship at the feast:', pt: 'Ora, havia alguns gregos entre os que tinham subido para adorar na festa.' },
      { v: 21, en: 'The same came therefore to Philip, which was of Bethsaida of Galilee, and desired him, saying, Sir, we would see Jesus.', pt: 'Esses foram ter com Filipe, que era de Betsaida da Galileia, e rogaram-lhe, dizendo: Senhor, queremos ver Jesus.' },
      { v: 22, en: 'Philip cometh and telleth Andrew: and again Andrew and Philip tell Jesus.', pt: 'Filipe foi e disse a André; e André e Filipe foram dizer a Jesus.' },
      { v: 23, en: 'And Jesus answered them, saying, The hour is come, that the Son of man should be glorified.', pt: 'Jesus respondeu-lhes, dizendo: É chegada a hora em que o Filho do homem deve ser glorificado.' },
      { v: 24, en: 'Verily, verily, I say unto you, Except a corn of wheat fall into the ground and die, it abideth alone: but if it die, it bringeth forth much fruit.', pt: 'Em verdade, em verdade vos digo que se o grão de trigo, caindo na terra, não morrer, fica sozinho; mas se morrer, dá muito fruto.' },
      { v: 25, en: 'He that loveth his life shall lose it; and he that hateth his life in this world shall keep it unto life eternal.', pt: 'Quem ama a sua vida perde-a; e quem odeia a sua vida neste mundo a guardará para a vida eterna.' },
      { v: 26, en: 'If any man serve me, let him follow me; and where I am, there shall also my servant be: if any man serve me, him will my Father honour.', pt: 'Se alguém me serve, siga-me; e onde eu estiver, ali estará também o meu servo; se alguém me servir, meu Pai o honrará.' },
      { v: 27, en: 'Now is my soul troubled; and what shall I say? Father, save me from this hour: but for this cause came I unto this hour.', pt: 'Agora a minha alma está perturbada; e que direi? Pai, salva-me desta hora! Mas foi para isto que cheguei a esta hora.' },
      { v: 28, en: 'Father, glorify thy name. Then came there a voice from heaven, saying, I have both glorified it, and will glorify it again.', pt: 'Pai, glorifica o teu nome. Veio então uma voz do céu: Já o glorifiquei e novamente o glorificarei.' },
      { v: 29, en: 'The people therefore, that stood by, and heard it, said that it thundered: others said, An angel spake to him.', pt: 'A multidão, pois, que estava ali e ouviu, dizia que tinha sido um trovão; outros diziam: Um anjo lhe falou.' },
      { v: 30, en: 'Jesus answered and said, This voice came not because of me, but for your sakes.', pt: 'Jesus respondeu: Esta voz não veio por minha causa, mas por causa de vós.' },
      { v: 31, en: 'Now is the judgment of this world: now shall the prince of this world be cast out.', pt: 'Agora é o juízo deste mundo; agora será lançado fora o príncipe deste mundo.' },
      { v: 32, en: 'And I, if I be lifted up from the earth, will draw all men unto me.', pt: 'E eu, quando for levantado da terra, todos atrairei a mim.' },
      { v: 33, en: 'This he said, signifying what death he should die.', pt: 'Ora, disse isto para significar de que morte havia de morrer.' },
      { v: 34, en: 'The people answered him, We have heard out of the law that Christ abideth for ever: and how sayest thou, The Son of man must be lifted up? who is this Son of man?', pt: 'A multidão respondeu-lhe: Nós ouvimos da lei que o Cristo permanece para sempre; como, pois, dizes tu que o Filho do homem deve ser levantado? Quem é este Filho do homem?' },
      { v: 35, en: 'Then Jesus said unto them, Yet a little while is the light with you. Walk while ye have the light, lest darkness come upon you: for he that walketh in darkness knoweth not whither he goeth.', pt: 'Disse-lhes então Jesus: Ainda por um pouco está a luz convosco. Andai enquanto tendes a luz, para que as trevas não vos surpreendam; pois o que anda nas trevas não sabe para onde vai.' },
      { v: 36, en: 'While ye have light, believe in the light, that ye may be the children of light. These things spake Jesus, and departed, and did hide himself from them.', pt: 'Enquanto tendes a luz, crede na luz, para que sejais filhos da luz. Jesus disse estas coisas, foi-se e ocultou-se deles.' },
      { v: 37, en: 'But though he had done so many miracles before them, yet they believed not on him:', pt: 'Mas, apesar de ter feito tantos sinais diante deles, não criam nele,' },
      { v: 38, en: 'That the saying of Esaias the prophet might be fulfilled, which he spake, Lord, who hath believed our report? and to whom hath the arm of the Lord been revealed?', pt: 'Para que se cumprisse a palavra do profeta Isaías, que disse: Senhor, quem creu na nossa pregação? E a quem foi revelado o braço do Senhor?' },
      { v: 39, en: 'Therefore they could not believe, because that Esaias said again,', pt: 'Por isso não podiam crer, porque disse ainda Isaías:' },
      { v: 40, en: 'He hath blinded their eyes, and hardened their heart; that they should not see with their eyes, nor understand with their heart, and be converted, and I should heal them.', pt: 'Cegou-lhes os olhos e endureceu-lhes o coração, para que não vejam com os olhos, nem com o coração entendam, nem se convertam, e eu os cure.' },
      { v: 41, en: 'These things said Esaias, when he saw his glory, and spake of him.', pt: 'Isaías disse estas coisas quando viu a sua glória e falou a respeito dele.' },
      { v: 42, en: 'Nevertheless among the chief rulers also many believed on him; but because of the Pharisees they did not confess him, lest they should be put out of the synagogue:', pt: 'No entanto, muitos até dos principais creram nele; mas por causa dos fariseus não o confessavam, para não serem expulsos da sinagoga;' },
      { v: 43, en: 'For they loved the praise of men more than the praise of God.', pt: 'Porque amavam mais a glória dos homens do que a glória de Deus.' },
      { v: 44, en: 'Jesus cried and said, He that believeth on me, believeth not on me, but on him that sent me.', pt: 'Jesus exclamou: Quem crê em mim não crê em mim, mas naquele que me enviou.' },
      { v: 45, en: 'And he that seeth me seeth him that sent me.', pt: 'E quem me vê vê aquele que me enviou.' },
      { v: 46, en: 'I am come a light into the world, that whosoever believeth on me should not abide in darkness.', pt: 'Eu vim ao mundo como luz, para que todo aquele que crê em mim não permaneça nas trevas.' },
      { v: 47, en: 'And if any man hear my words, and believe not, I judge him not: for I came not to judge the world, but to save the world.', pt: 'E se alguém ouvir as minhas palavras e não as guardar, eu não o julgo; pois não vim para julgar o mundo, mas para salvar o mundo.' },
      { v: 48, en: 'He that rejecteth me, and receiveth not my words, hath one that judgeth him: the word that I have spoken, the same shall judge him in the last day.', pt: 'Quem me rejeita e não recebe as minhas palavras tem quem o julgue: a palavra que tenho falado essa o julgará no último dia.' },
      { v: 49, en: 'For I have not spoken of myself; but the Father which sent me, he gave me a commandment, what I should say, and what I should speak.', pt: 'Porque eu não falei por mim mesmo; mas o Pai que me enviou, ele me deu mandamento sobre o que devo dizer e falar.' },
      { v: 50, en: 'And I know that his commandment is life everlasting: whatsoever I speak therefore, even as the Father said unto me, so I speak.', pt: 'E sei que o seu mandamento é a vida eterna; portanto, o que eu falo, falo-o como o Pai mo disse.' },
    ],
    13: [
      { v: 1,  en: 'Now before the feast of the passover, when Jesus knew that his hour was come that he should depart out of this world unto the Father, having loved his own which were in the world, he loved them unto the end.', pt: 'Ora, antes da festa da páscoa, sabendo Jesus que era chegada a sua hora de passar deste mundo para o Pai, como havia amado os seus que estavam no mundo, amou-os até ao fim.' },
      { v: 2,  en: 'And supper being ended, the devil having now put into the heart of Judas Iscariot, Simon\'s son, to betray him;', pt: 'E, havendo uma ceia, e tendo já o diabo posto no coração de Judas Iscariotes, filho de Simão, que o traísse,' },
      { v: 3,  en: 'Jesus knowing that the Father had given all things into his hands, and that he was come from God, and went to God;', pt: 'Jesus, sabendo que o Pai lhe havia dado tudo nas mãos, e que saíra de Deus e ia para Deus,' },
      { v: 4,  en: 'He riseth from supper, and laid aside his garments; and took a towel, and girded himself.', pt: 'Levantou-se da ceia e depôs as vestes; e, tomando uma toalha, cingiu-se com ela.' },
      { v: 5,  en: 'After that he poureth water into a bason, and began to wash the disciples\' feet, and to wipe them with the towel wherewith he was girded.', pt: 'Em seguida deitou água numa bacia e começou a lavar os pés dos discípulos e a enxugá-los com a toalha com que estava cingido.' },
      { v: 6,  en: 'Then cometh he to Simon Peter: and Peter saith unto him, Lord, dost thou wash my feet?', pt: 'Chegou então a Simão Pedro; e Pedro disse-lhe: Senhor, tu lavas os meus pés?' },
      { v: 7,  en: 'Jesus answered and said unto him, What I do thou knowest not now; but thou shalt know hereafter.', pt: 'Jesus respondeu-lhe: O que eu faço, tu não o sabes agora; mas depois compreenderás.' },
      { v: 8,  en: 'Peter saith unto him, Thou shalt never wash my feet. Jesus answered him, If I wash thee not, thou hast no part with me.', pt: 'Pedro disse-lhe: Nunca me lavarás os pés. Jesus respondeu-lhe: Se eu não te lavar, não terás parte comigo.' },
      { v: 9,  en: 'Simon Peter saith unto him, Lord, not my feet only, but also my hands and my head.', pt: 'Disse-lhe Simão Pedro: Senhor, não somente os pés, mas também as mãos e a cabeça.' },
      { v: 10, en: 'Jesus saith to him, He that is washed needeth not save to wash his feet, but is clean every whit: and ye are clean, but not all.', pt: 'Jesus disse-lhe: O que está lavado não necessita de lavar senão os pés, pois está todo limpo; e vós estais limpos, mas não todos.' },
      { v: 11, en: 'For he knew who should betray him; therefore said he, Ye are not all clean.', pt: 'Porque sabia quem o havia de trair; por isso disse: Não estais todos limpos.' },
      { v: 12, en: 'So after he had washed their feet, and had taken his garments, and was set down again, he said unto them, Know ye what I have done to you?', pt: 'Depois que lhes lavou os pés e tomou as suas vestes e voltou a assentar-se, disse-lhes: Sabeis o que vos fiz?' },
      { v: 13, en: 'Ye call me Master and Lord: and ye say well; for so I am.', pt: 'Vós me chamais Mestre e Senhor; e dizeis bem, porque eu o sou.' },
      { v: 14, en: 'If I then, your Lord and Master, have washed your feet; ye also ought to wash one another\'s feet.', pt: 'Se eu, pois, sendo o Senhor e o Mestre, vos lavei os pés, também vós deveis lavar os pés uns aos outros.' },
      { v: 15, en: 'For I have given you an example, that ye should do as I have done to you.', pt: 'Porque eu vos dei o exemplo, para que, como eu vos fiz, vós façais também.' },
      { v: 16, en: 'Verily, verily, I say unto you, The servant is not greater than his lord; neither he that is sent greater than he that sent him.', pt: 'Em verdade, em verdade vos digo que o servo não é maior do que o seu senhor, nem o enviado é maior do que aquele que o enviou.' },
      { v: 17, en: 'If ye know these things, happy are ye if ye do them.', pt: 'Se sabeis estas coisas, bem-aventurados sois se as fizerdes.' },
      { v: 18, en: 'I speak not of you all: I know whom I have chosen: but that the scripture may be fulfilled, He that eateth bread with me hath lifted up his heel against me.', pt: 'Não falo de todos vós; eu sei os que escolhi; mas para que se cumpra a Escritura: O que come o pão comigo levantou contra mim o seu calcanhar.' },
      { v: 19, en: 'Now I tell you before it come, that, when it is come to pass, ye may believe that I am he.', pt: 'Desde já vo-lo digo, antes que aconteça, para que, quando acontecer, creiais que Eu Sou.' },
      { v: 20, en: 'Verily, verily, I say unto you, He that receiveth whomsoever I send receiveth me; and he that receiveth me receiveth him that sent me.', pt: 'Em verdade, em verdade vos digo que quem recebe aquele que eu enviar, recebe-me a mim; e quem me recebe a mim recebe aquele que me enviou.' },
      { v: 21, en: 'When Jesus had thus said, he was troubled in spirit, and testified, and said, Verily, verily, I say unto you, that one of you shall betray me.', pt: 'Dito isto, Jesus perturbou-se em espírito e declarou: Em verdade, em verdade vos digo que um de vós me há de trair.' },
      { v: 22, en: 'Then the disciples looked one on another, doubting of whom he spake.', pt: 'Os discípulos olhavam uns para os outros, sem saber de quem falava.' },
      { v: 23, en: 'Now there was leaning on Jesus\' bosom one of his disciples, whom Jesus loved.', pt: 'Ora, estava reclinado no seio de Jesus um dos seus discípulos, aquele que Jesus amava.' },
      { v: 24, en: 'Simon Peter therefore beckoned to him, that he should ask who it should be of whom he spake.', pt: 'Simão Pedro acenou-lhe que perguntasse quem era aquele de quem falava.' },
      { v: 25, en: 'He then lying on Jesus\' breast saith unto him, Lord, who is it?', pt: 'Ele, recostando-se sobre o peito de Jesus, disse-lhe: Senhor, quem é?' },
      { v: 26, en: 'Jesus answered, He it is, to whom I shall give a sop, when I have dipped it. And when he had dipped the sop, he gave it to Judas Iscariot, the son of Simon.', pt: 'Jesus respondeu: É aquele a quem eu der o bocado molhado. E, molhando o bocado, deu-o a Judas Iscariotes, filho de Simão.' },
      { v: 27, en: 'And after the sop Satan entered into him. Then said Jesus unto him, That thou doest, do quickly.', pt: 'E depois do bocado, então entrou nele Satanás. Disse-lhe pois Jesus: O que fazes, faze depressa.' },
      { v: 28, en: 'Now no man at the table knew for what intent he spake this unto him.', pt: 'Nenhum dos que estavam à mesa entendeu por que lhe disse isso.' },
      { v: 29, en: 'For some of them thought, because Judas had the bag, that Jesus had said unto him, Buy those things that we have need of against the feast; or, that he should give something to the poor.', pt: 'Porque alguns cuidavam que, como Judas tinha a bolsa, Jesus lhe dissera: Compra o que necessitamos para a festa, ou que desse alguma coisa aos pobres.' },
      { v: 30, en: 'He then having received the sop went immediately out: and it was night.', pt: 'Ele, pois, tendo recebido o bocado, saiu logo; e era noite.' },
      { v: 31, en: 'Therefore, when he was gone out, Jesus said, Now is the Son of man glorified, and God is glorified in him.', pt: 'Quando ele saiu, disse Jesus: Agora é glorificado o Filho do homem, e Deus é glorificado nele.' },
      { v: 32, en: 'If God be glorified in him, God shall also glorify him in himself, and shall straightway glorify him.', pt: 'Se Deus é glorificado nele, também Deus o glorificará em si mesmo, e logo o glorificará.' },
      { v: 33, en: 'Little children, yet a little while I am with you. Ye shall seek me: and as I said unto the Jews, Whither I go, ye cannot come; so now I say to you.', pt: 'Filhinhos, ainda um pouco estou convosco. Buscar-me-eis; e, como disse aos judeus: Para onde eu vou, vós não podeis ir, assim agora digo a vós.' },
      { v: 34, en: 'A new commandment I give unto you, That ye love one another; as I have loved you, that ye also love one another.', pt: 'Um novo mandamento vos dou: Que vos ameis uns aos outros; assim como eu vos amei, que também vós uns aos outros vos ameis.' },
      { v: 35, en: 'By this shall all men know that ye are my disciples, if ye have love one to another.', pt: 'Nisto conhecerão todos que sois meus discípulos, se vos amardes uns aos outros.' },
      { v: 36, en: 'Simon Peter said unto him, Lord, whither goest thou? Jesus answered him, Whither I go, thou canst not follow me now; but thou shalt follow me afterwards.', pt: 'Disse-lhe Simão Pedro: Senhor, para onde vais? Jesus respondeu-lhe: Para onde eu vou, tu não me podes seguir agora; mas seguir-me-ás depois.' },
      { v: 37, en: 'Peter said unto him, Lord, why cannot I follow thee now? I will lay down my life for thy sake.', pt: 'Pedro disse-lhe: Senhor, por que não te posso seguir agora? Darei a minha vida por ti.' },
      { v: 38, en: 'Jesus answered him, Wilt thou lay down thy life for my sake? Verily, verily, I say unto thee, The cock shall not crow, till thou hast denied me thrice.', pt: 'Jesus respondeu-lhe: Darás a tua vida por mim? Em verdade, em verdade te digo que não cantará o galo, sem que me negueis três vezes.' },
    ],
    14: [
      { v: 1,  en: 'Let not your heart be troubled: ye believe in God, believe also in me.', pt: 'Não se turbe o vosso coração; credes em Deus, crede também em mim.' },
      { v: 2,  en: "In my Father's house are many mansions: if it were not so, I would have told you. I go to prepare a place for you.", pt: 'Na casa de meu Pai há muitas moradas. Se assim não fosse, eu vo-lo diria. Vou preparar-vos lugar.' },
      { v: 3,  en: 'And if I go and prepare a place for you, I will come again, and receive you unto myself; that where I am, there ye may be also.', pt: 'E quando eu for e vos preparar lugar, voltarei e tomar-vos-ei para mim mesmo, para que onde eu estiver estejais vós também.' },
      { v: 4,  en: 'And whither I go ye know, and the way ye know.', pt: 'E sabeis para onde vou, e conheceis o caminho.' },
      { v: 5,  en: 'Thomas saith unto him, Lord, we know not whither thou goest; and how can we know the way?', pt: 'Disse-lhe Tomé: Senhor, não sabemos para onde vais; como podemos saber o caminho?' },
      { v: 6,  en: 'Jesus saith unto him, I am the way, the truth, and the life: no man cometh unto the Father, but by me.', pt: 'Jesus disse-lhe: Eu sou o caminho, e a verdade, e a vida; ninguém vem ao Pai senão por mim.' },
      { v: 7,  en: 'If ye had known me, ye should have known my Father also: and from henceforth ye know him, and have seen him.', pt: 'Se vós me conhecêsseis a mim, também conheceríeis a meu Pai; e já desde agora o conheceis e o tendes visto.' },
      { v: 8,  en: 'Philip saith unto him, Lord, shew us the Father, and it sufficeth us.', pt: 'Disse-lhe Filipe: Senhor, mostra-nos o Pai, e isso nos basta.' },
      { v: 9,  en: 'Jesus saith unto him, Have I been so long time with you, and yet hast thou not known me, Philip? he that hath seen me hath seen the Father; and how sayest thou then, Shew us the Father?', pt: 'Jesus disse-lhe: Há tanto tempo estou convosco, e não me conheces, Filipe? Quem me viu a mim viu o Pai; como, pois, dizes: Mostra-nos o Pai?' },
      { v: 10, en: 'Believest thou not that I am in the Father, and the Father in me? the words that I speak unto you I speak not of myself: but the Father that dwelleth in me, he doeth the works.', pt: 'Não crês tu que eu estou no Pai e que o Pai está em mim? As palavras que eu vos digo, não as digo por mim mesmo; mas o Pai, que em mim reside, é quem faz as obras.' },
      { v: 11, en: 'Believe me that I am in the Father, and the Father in me: or else believe me for the very works\' sake.', pt: 'Crede-me que estou no Pai e o Pai em mim; ou então crede-me pelas mesmas obras.' },
      { v: 12, en: 'Verily, verily, I say unto you, He that believeth on me, the works that I do shall he do also; and greater works than these shall he do; because I go unto my Father.', pt: 'Em verdade, em verdade vos digo que aquele que crê em mim fará também as obras que eu faço, e fará maiores do que estas; porque eu vou para o Pai.' },
      { v: 13, en: 'And whatsoever ye shall ask in my name, that will I do, that the Father may be glorified in the Son.', pt: 'E tudo quanto pedirdes em meu nome, eu o farei, para que o Pai seja glorificado no Filho.' },
      { v: 14, en: 'If ye shall ask any thing in my name, I will do it.', pt: 'Se pedirdes alguma coisa em meu nome, eu a farei.' },
      { v: 15, en: 'If ye love me, keep my commandments.', pt: 'Se me amardes, guardai os meus mandamentos.' },
      { v: 16, en: 'And I will pray the Father, and he shall give you another Comforter, that he may abide with you for ever;', pt: 'E eu rogarei ao Pai, e ele vos dará outro Consolador, para que fique convosco para sempre;' },
      { v: 17, en: 'Even the Spirit of truth; whom the world cannot receive, because it seeth him not, neither knoweth him: but ye know him; for he dwelleth with you, and shall be in you.', pt: 'O Espírito da verdade, que o mundo não pode receber, porque não o vê nem o conhece; vós o conheceis, porque habita convosco e estará em vós.' },
      { v: 18, en: 'I will not leave you comfortless: I will come to you.', pt: 'Não vos deixarei órfãos; virei a vós.' },
      { v: 19, en: 'Yet a little while, and the world seeth me no more; but ye see me: because I live, ye shall live also.', pt: 'Ainda um pouco e o mundo não me verá mais; mas vós me vereis; porque eu vivo, vós também vivereis.' },
      { v: 20, en: 'At that day ye shall know that I am in my Father, and ye in me, and I in you.', pt: 'Naquele dia vós conhecereis que estou em meu Pai, e vós em mim, e eu em vós.' },
      { v: 21, en: 'He that hath my commandments, and keepeth them, he it is that loveth me: and he that loveth me shall be loved of my Father, and I will love him, and will manifest myself to him.', pt: 'Quem tem os meus mandamentos e os guarda, esse é o que me ama; e quem me ama será amado de meu Pai; e eu o amarei e me manifestarei a ele.' },
      { v: 22, en: 'Judas saith unto him, not Iscariot, Lord, how is it that thou wilt manifest thyself unto us, and not unto the world?', pt: 'Disse-lhe Judas (não o Iscariotes): Senhor, como é que te manifestarás a nós e não ao mundo?' },
      { v: 23, en: 'Jesus answered and said unto him, If a man love me, he will keep my words: and my Father will love him, and we will come unto him, and make our abode with him.', pt: 'Jesus respondeu e disse-lhe: Se alguém me ama, guardará a minha palavra, e meu Pai o amará, e viremos para ele e faremos nele morada.' },
      { v: 24, en: 'He that loveth me not keepeth not my sayings: and the word which ye hear is not mine, but the Father\'s which sent me.', pt: 'Quem não me ama não guarda as minhas palavras; e a palavra que ouvis não é minha, mas do Pai que me enviou.' },
      { v: 25, en: 'These things have I spoken unto you, being yet present with you.', pt: 'Estas coisas vos tenho dito enquanto ficava convosco.' },
      { v: 26, en: 'But the Comforter, which is the Holy Ghost, whom the Father will send in my name, he shall teach you all things, and bring all things to your remembrance, whatsoever I have said unto you.', pt: 'Mas o Consolador, o Espírito Santo, que o Pai enviará em meu nome, esse vos ensinará todas as coisas e vos fará lembrar de tudo quanto vos tenho dito.' },
      { v: 27, en: 'Peace I leave with you, my peace I give unto you: not as the world giveth, give I unto you. Let not your heart be troubled, neither let it be afraid.', pt: 'Deixo-vos a paz, a minha paz vos dou; não vo-la dou como o mundo a dá. Não se turbe o vosso coração, nem se atemorize.' },
      { v: 28, en: 'Ye have heard how I said unto you, I go away, and come again unto you. If ye loved me, ye would rejoice, because I said, I go unto the Father: for my Father is greater than I.', pt: 'Ouvistes que vos disse: Vou, e volto para vós. Se me amásseis, regozijar-vos-íeis por eu ir para o Pai, porque o Pai é maior do que eu.' },
      { v: 29, en: 'And now I have told you before it come to pass, that, when it is come to pass, ye might believe.', pt: 'E agora vo-lo disse antes que aconteça, para que, quando acontecer, creiais.' },
      { v: 30, en: 'Hereafter I will not talk much with you: for the prince of this world cometh, and hath nothing in me.', pt: 'Já não falarei muito convosco, porque vem o príncipe deste mundo, e em mim não tem nada.' },
      { v: 31, en: 'But that the world may know that I love the Father; and as the Father gave me commandment, even so I do. Arise, let us go hence.', pt: 'Mas, para que o mundo conheça que amo o Pai, e que faço como o Pai me mandou, levantai-vos, vamo-nos daqui.' },
    ],
    15: [
      { v: 1,  en: 'I am the true vine, and my Father is the husbandman.', pt: 'Eu sou a videira verdadeira, e meu Pai é o lavrador.' },
      { v: 2,  en: 'Every branch in me that beareth not fruit he taketh away: and every branch that beareth fruit, he purgeth it, that it may bring forth more fruit.', pt: 'Todo o ramo que em mim não dá fruto, ele o tira; e todo aquele que dá fruto, limpa-o, para que dê mais fruto.' },
      { v: 3,  en: 'Now ye are clean through the word which I have spoken unto you.', pt: 'Vós já estais limpos, por causa da palavra que vos tenho dito.' },
      { v: 4,  en: 'Abide in me, and I in you. As the branch cannot bear fruit of itself, except it abide in the vine; no more can ye, except ye abide in me.', pt: 'Ficai em mim, e eu em vós. Como o ramo não pode dar fruto de si mesmo, se não ficar na videira, assim também vós não podeis dar fruto se não permanecerdes em mim.' },
      { v: 5,  en: 'I am the vine, ye are the branches: He that abideth in me, and I in him, the same bringeth forth much fruit: for without me ye can do nothing.', pt: 'Eu sou a videira, vós sois os ramos. Quem está em mim e eu nele, esse dá muito fruto; porque sem mim nada podeis fazer.' },
      { v: 6,  en: 'If a man abide not in me, he is cast forth as a branch, and is withered; and men gather them, and cast them into the fire, and they are burned.', pt: 'Se alguém não permanecer em mim, será lançado fora como o ramo e secará; e os colherão e os lançarão no fogo, e eles arderam.' },
      { v: 7,  en: 'If ye abide in me, and my words abide in you, ye shall ask what ye will, and it shall be done unto you.', pt: 'Se ficardes em mim, e as minhas palavras ficarem em vós, pedireis tudo o que quiserdes, e vos será feito.' },
      { v: 8,  en: 'Herein is my Father glorified, that ye bear much fruit; so shall ye be my disciples.', pt: 'Nisto é glorificado meu Pai, em que deis muito fruto; e assim sereis meus discípulos.' },
      { v: 9,  en: 'As the Father hath loved me, so have I loved you: continue ye in my love.', pt: 'Como o Pai me amou, também eu vos amei; permanecei no meu amor.' },
      { v: 10, en: 'If ye keep my commandments, ye shall abide in my love; even as I have kept my Father\'s commandments, and abide in his love.', pt: 'Se guardardes os meus mandamentos, permanecereis no meu amor; assim como eu tenho guardado os mandamentos de meu Pai e permaneço no seu amor.' },
      { v: 11, en: 'These things have I spoken unto you, that my joy might remain in you, and that your joy might be full.', pt: 'Estas coisas vos tenho dito para que a minha alegria fique em vós e o vosso gozo seja completo.' },
      { v: 12, en: 'This is my commandment, That ye love one another, as I have loved you.', pt: 'Este é o meu mandamento: que vos ameis uns aos outros, como eu vos amei.' },
      { v: 13, en: 'Greater love hath no man than this, that a man lay down his life for his friends.', pt: 'Ninguém tem maior amor do que este: de dar alguém a sua vida pelos seus amigos.' },
      { v: 14, en: 'Ye are my friends, if ye do whatsoever I command you.', pt: 'Vós sois meus amigos, se fizerdes o que eu vos mando.' },
      { v: 15, en: 'Henceforth I call you not servants; for the servant knoweth not what his lord doeth: but I have called you friends; for all things that I have heard of my Father I have made known unto you.', pt: 'Já não vos chamo servos, porque o servo não sabe o que faz o seu senhor; mas tenho-vos chamado amigos, porque tudo quanto ouvi de meu Pai vos tenho dado a conhecer.' },
      { v: 16, en: 'Ye have not chosen me, but I have chosen you, and ordained you, that ye should go and bring forth fruit, and that your fruit should remain: that whatsoever ye shall ask of the Father in my name, he may give it you.', pt: 'Não fostes vós que me escolhestes a mim; pelo contrário, eu vos escolhi a vós, e vos designei para que vades e deis fruto, e o vosso fruto permaneça; a fim de que tudo quanto pedirdes ao Pai em meu nome, ele vo-lo conceda.' },
      { v: 17, en: 'These things I command you, that ye love one another.', pt: 'Estas coisas vos mando: que vos ameis uns aos outros.' },
      { v: 18, en: 'If the world hate you, ye know that it hated me before it hated you.', pt: 'Se o mundo vos odeia, sabei que a mim me odiou primeiro do que a vós.' },
      { v: 19, en: 'If ye were of the world, the world would love his own: but because ye are not of the world, but I have chosen you out of the world, therefore the world hateth you.', pt: 'Se fôsseis do mundo, o mundo amaria o que era seu; mas porque não sois do mundo, antes eu vos escolhi do mundo, por isso o mundo vos odeia.' },
      { v: 20, en: 'Remember the word that I said unto you, The servant is not greater than his lord. If they have persecuted me, they will also persecute you; if they have kept my saying, they will keep yours also.', pt: 'Lembrai-vos da palavra que vos disse: Não é o servo maior do que o seu senhor. Se me perseguiram a mim, também perseguirão a vós; se guardaram a minha palavra, também guardarão a vossa.' },
      { v: 21, en: 'But all these things will they do unto you for my name\'s sake, because they know not him that sent me.', pt: 'Mas tudo isto vos farão por causa do meu nome, porque não conhecem aquele que me enviou.' },
      { v: 22, en: 'If I had not come and spoken unto them, they had not had sin: but now they have no cloke for their sin.', pt: 'Se eu não tivesse vindo e não lhes tivesse falado, não teriam pecado; mas agora não têm desculpa do seu pecado.' },
      { v: 23, en: 'He that hateth me hateth my Father also.', pt: 'Quem me odeia a mim, também odeia a meu Pai.' },
      { v: 24, en: 'If I had not done among them the works which none other man did, they had not had sin: but now have they both seen and hated both me and my Father.', pt: 'Se eu não tivesse feito entre eles obras que nenhum outro fez, não teriam pecado; mas agora viram-nas e odiaram tanto a mim como a meu Pai.' },
      { v: 25, en: 'But this cometh to pass, that the word might be fulfilled that is written in their law, They hated me without a cause.', pt: 'Mas isso acontece para que se cumpra a palavra que está escrita na sua lei: Odiaram-me sem motivo.' },
      { v: 26, en: 'But when the Comforter is come, whom I will send unto you from the Father, even the Spirit of truth, which proceedeth from the Father, he shall testify of me:', pt: 'Mas quando vier o Consolador, que eu vos enviarei da parte do Pai, o Espírito da verdade, que procede do Pai, ele testificará de mim.' },
      { v: 27, en: 'And ye also shall bear witness, because ye have been with me from the beginning.', pt: 'E vós também testificareis, porque desde o princípio estais comigo.' },
    ],
    16: [
      { v: 1,  en: 'These things have I spoken unto you, that ye should not be offended.', pt: 'Tenho-vos dito estas coisas para que não vos escandalizeis.' },
      { v: 2,  en: 'They shall put you out of the synagogues: yea, the time cometh, that whosoever killeth you will think that he doeth God service.', pt: 'Expulsar-vos-ão das sinagogas; e até vem a hora em que qualquer que vos matar pensará que presta um culto a Deus.' },
      { v: 3,  en: 'And these things will they do unto you, because they have not known the Father, nor me.', pt: 'E farão isso porque não conheceram o Pai nem a mim.' },
      { v: 4,  en: 'But these things have I told you, that when the time shall come, ye may remember that I told you of them. And these things I said not unto you at the beginning, because I was with you.', pt: 'Mas tenho-vos dito estas coisas para que, quando chegar a hora, vos lembreis de que eu vo-las disse. E não vos disse estas coisas desde o princípio, porque estava convosco.' },
      { v: 5,  en: 'But now I go my way to him that sent me; and none of you asketh me, Whither goest thou?', pt: 'Mas agora vou àquele que me enviou; e nenhum de vós me pergunta: Para onde vais?' },
      { v: 6,  en: 'But because I have said these things unto you, sorrow hath filled your heart.', pt: 'Mas, porque vos tenho dito estas coisas, a tristeza encheu o vosso coração.' },
      { v: 7,  en: 'Nevertheless I tell you the truth; It is expedient for you that I go away: for if I go not away, the Comforter will not come unto you; but if I depart, I will send him unto you.', pt: 'Mas digo-vos a verdade: Convém-vos que eu vá; porque, se eu não for, o Consolador não virá para vós; mas, se eu for, vo-lo enviarei.' },
      { v: 8,  en: 'And when he is come, he will reprove the world of sin, and of righteousness, and of judgment:', pt: 'E quando ele vier, convencerá o mundo do pecado, e da justiça, e do juízo:' },
      { v: 9,  en: 'Of sin, because they believe not on me;', pt: 'Do pecado, porque não creem em mim;' },
      { v: 10, en: 'Of righteousness, because I go to my Father, and ye see me no more;', pt: 'Da justiça, porque vou para o Pai e não me vereis mais;' },
      { v: 11, en: 'Of judgment, because the prince of this world is judged.', pt: 'Do juízo, porque o príncipe deste mundo já está julgado.' },
      { v: 12, en: 'I have yet many things to say unto you, but ye cannot bear them now.', pt: 'Ainda tenho muitas coisas a dizer-vos, mas vós não as podeis suportar agora.' },
      { v: 13, en: 'Howbeit when he, the Spirit of truth, is come, he will guide you into all truth: for he shall not speak of himself; but whatsoever he shall hear, that shall he speak: and he will shew you things to come.', pt: 'Mas quando vier o Espírito da verdade, ele vos guiará em toda a verdade; porque não falará por si mesmo, mas dirá tudo o que tiver ouvido e vos anunciará as coisas que hão de vir.' },
      { v: 14, en: 'He shall glorify me: for he shall receive of mine, and shall shew it unto you.', pt: 'Ele me glorificará, porque há de receber do que é meu e vo-lo há de anunciar.' },
      { v: 15, en: 'All things that the Father hath are mine: therefore said I, that he shall take of mine, and shall shew it unto you.', pt: 'Tudo o que o Pai tem é meu; por isso vos disse que há de receber do que é meu e vo-lo há de anunciar.' },
      { v: 16, en: 'A little while, and ye shall not see me: and again, a little while, and ye shall see me, because I go to the Father.', pt: 'Ainda um pouco e não me vereis; e outra vez um pouco e ver-me-eis, porque vou para o Pai.' },
      { v: 17, en: 'Then said some of his disciples among themselves, What is this that he saith unto us, A little while, and ye shall not see me: and again, a little while, and ye shall see me: and, Because I go to the Father?', pt: 'Disseram então alguns dos seus discípulos entre si: Que é isto que nos diz: Ainda um pouco e não me vereis; e outra vez um pouco e ver-me-eis; e: Porque vou para o Pai?' },
      { v: 18, en: 'They said therefore, What is this that he saith, A little while? we cannot tell what he saith.', pt: 'Diziam pois: Que é este pouco que diz? Não entendemos o que diz.' },
      { v: 19, en: 'Now Jesus knew that they were desirous to ask him, and said unto them, Do ye enquire among yourselves of that I said, A little while, and ye shall not see me: and again, a little while, and ye shall see me?', pt: 'Jesus, pois, conheceu que queriam interrogá-lo, e disse-lhes: Indagais entre vós acerca do que eu disse: Ainda um pouco e não me vereis; e outra vez um pouco e ver-me-eis?' },
      { v: 20, en: 'Verily, verily, I say unto you, That ye shall weep and lament, but the world shall rejoice: and ye shall be sorrowful, but your sorrow shall be turned into joy.', pt: 'Em verdade, em verdade vos digo que vós chorareis e vos lamentareis, e o mundo se alegrará; vós vos entristecereis, mas a vossa tristeza se converterá em alegria.' },
      { v: 21, en: 'A woman when she is in travail hath sorrow, because her hour is come: but as soon as she is delivered of the child, she remembereth no more the anguish, for joy that a man is born into the world.', pt: 'A mulher, quando está em trabalho de parto, sente angústia, porque é chegada a sua hora; mas quando dá à luz o menino, já não se lembra da angústia, por causa da alegria de ter nascido um homem no mundo.' },
      { v: 22, en: 'And ye now therefore have sorrow: but I will see you again, and your heart shall rejoice, and your joy no man taketh from you.', pt: 'Assim também vós agora tendes tristeza; mas eu tornarei a ver-vos, e o vosso coração se alegrará, e ninguém vos tirará o vosso gozo.' },
      { v: 23, en: 'And in that day ye shall ask me nothing. Verily, verily, I say unto you, Whatsoever ye shall ask the Father in my name, he will give it you.', pt: 'E naquele dia nada me perguntareis. Em verdade, em verdade vos digo que tudo quanto pedirdes ao Pai em meu nome, ele vo-lo dará.' },
      { v: 24, en: 'Hitherto have ye asked nothing in my name: ask, and ye shall receive, that your joy may be full.', pt: 'Até agora nada pedistes em meu nome; pedi e recebereis, para que o vosso gozo seja completo.' },
      { v: 25, en: 'These things have I spoken unto you in proverbs: but the time cometh, when I shall no more speak unto you in proverbs, but I shall shew you plainly of the Father.', pt: 'Tenho-vos dito estas coisas em provérbios; mas a hora vem em que não mais vos falarei em provérbios, mas abertamente vos anunciarei acerca do Pai.' },
      { v: 26, en: 'At that day ye shall ask in my name: and I say not unto you, that I will pray the Father for you:', pt: 'Naquele dia pedireis em meu nome; e não vos digo que rogarei ao Pai por vós,' },
      { v: 27, en: 'For the Father himself loveth you, because ye have loved me, and have believed that I came out from God.', pt: 'Pois o próprio Pai vos ama, porque vós me amastes e crestes que eu saí de Deus.' },
      { v: 28, en: 'I came forth from the Father, and am come into the world: again, I leave the world, and go to the Father.', pt: 'Saí do Pai e vim ao mundo; outra vez deixo o mundo e vou para o Pai.' },
      { v: 29, en: 'His disciples said unto him, Lo, now speakest thou plainly, and speakest no proverb.', pt: 'Disseram-lhe os seus discípulos: Eis que agora falas abertamente e não dizes nenhum provérbio.' },
      { v: 30, en: 'Now are we sure that thou knowest all things, and needest not that any man should ask thee: by this we believe that thou camest forth from God.', pt: 'Agora sabemos que sabes todas as coisas, e não precisas que alguém te interrogue; por isso cremos que saíste de Deus.' },
      { v: 31, en: 'Jesus answered them, Do ye now believe?', pt: 'Jesus respondeu-lhes: Credes agora?' },
      { v: 32, en: 'Behold, the hour cometh, yea, is now come, that ye shall be scattered, every man to his own, and shall leave me alone: and yet I am not alone, because the Father is with me.', pt: 'Eis que a hora vem, e já chegou, em que sereis dispersos, cada um para seu lado, e me deixareis só; mas não estou só, porque o Pai está comigo.' },
      { v: 33, en: 'These things I have spoken unto you, that in me ye might have peace. In the world ye shall have tribulation: but be of good cheer; I have overcome the world.', pt: 'Tenho-vos dito estas coisas para que tenhais paz em mim. No mundo tereis tribulações; mas tende bom ânimo; eu venci o mundo.' },
    ],
    17: [
      { v: 1,  en: 'These words spake Jesus, and lifted up his eyes to heaven, and said, Father, the hour is come; glorify thy Son, that thy Son also may glorify thee:', pt: 'Jesus disse estas coisas, e, levantando os olhos ao céu, disse: Pai, é chegada a hora; glorifica o teu Filho, para que o teu Filho também te glorifique a ti.' },
      { v: 2,  en: 'As thou hast given him power over all flesh, that he should give eternal life to as many as thou hast given him.', pt: 'Assim como lhe deste autoridade sobre toda a carne, que dê a vida eterna a todos os que lhe deste.' },
      { v: 3,  en: 'And this is life eternal, that they might know thee the only true God, and Jesus Christ, whom thou hast sent.', pt: 'E a vida eterna é esta: que te conheçam a ti, o único Deus verdadeiro, e a Jesus Cristo, a quem enviaste.' },
      { v: 4,  en: 'I have glorified thee on the earth: I have finished the work which thou gavest me to do.', pt: 'Eu te glorifiquei na terra, consumando a obra que me deste que fizesse.' },
      { v: 5,  en: 'And now, O Father, glorify thou me with thine own self with the glory which I had with thee before the world was.', pt: 'E agora, Pai, glorifica-me tu junto a ti mesmo com a glória que tive contigo antes que o mundo existisse.' },
      { v: 6,  en: 'I have manifested thy name unto the men which thou gavest me out of the world: thine they were, and thou gavest them me; and they have kept thy word.', pt: 'Tenho manifestado o teu nome aos homens que do mundo me deste; eram teus, e tu mos deste, e guardaram a tua palavra.' },
      { v: 7,  en: 'Now they have known that all things whatsoever thou hast given me are of thee.', pt: 'Agora conheceram que tudo o que me deste vem de ti.' },
      { v: 8,  en: 'For I have given unto them the words which thou gavest me; and they have received them, and have known surely that I came out from thee, and they have believed that thou didst send me.', pt: 'Porque as palavras que me deste eu as dei a eles; e eles as receberam e reconheceram verdadeiramente que saí de ti, e creram que tu me enviaste.' },
      { v: 9,  en: 'I pray for them: I pray not for the world, but for them which thou hast given me; for they are thine.', pt: 'Eu rogo por eles; não rogo pelo mundo, mas por aqueles que me deste, porque são teus.' },
      { v: 10, en: 'And all mine are thine, and thine are mine; and I am glorified in them.', pt: 'E tudo o que é meu é teu, e o que é teu é meu; e sou glorificado neles.' },
      { v: 11, en: 'And now I am no more in the world, but these are in the world, and I come to thee. Holy Father, keep through thine own name those whom thou hast given me, that they may be one, as we are.', pt: 'E já não estou no mundo, mas estes estão no mundo, e eu vou a ti. Pai Santo, guarda-os no teu nome, os que me deste, para que sejam um, como nós.' },
      { v: 12, en: 'While I was with them in the world, I kept them in thy name: those that thou gavest me I have kept, and none of them is lost, but the son of perdition; that the scripture might be fulfilled.', pt: 'Quando estava com eles no mundo, guardava-os no teu nome; os que me deste, eu os guardei; e nenhum deles se perdeu, senão o filho da perdição, para que a Escritura se cumprisse.' },
      { v: 13, en: 'And now come I to thee; and these things I speak in the world, that they might have my joy fulfilled in themselves.', pt: 'Mas agora vou a ti; e digo estas coisas no mundo para que tenham em si mesmos o meu gozo cumprido.' },
      { v: 14, en: 'I have given them thy word; and the world hated them, because they are not of the world, even as I am not of the world.', pt: 'Eu lhes dei a tua palavra, e o mundo os odiou, porque não são do mundo, como eu não sou do mundo.' },
      { v: 15, en: 'I pray not that thou shouldest take them out of the world, but that thou shouldest keep them from the evil.', pt: 'Não te peço que os tires do mundo, mas que os guardes do mal.' },
      { v: 16, en: 'They are not of the world, even as I am not of the world.', pt: 'Não são do mundo, como eu não sou do mundo.' },
      { v: 17, en: 'Sanctify them through thy truth: thy word is truth.', pt: 'Santifica-os na verdade; a tua palavra é a verdade.' },
      { v: 18, en: 'As thou hast sent me into the world, even so have I also sent them into the world.', pt: 'Assim como tu me enviaste ao mundo, também eu os enviei ao mundo.' },
      { v: 19, en: 'And for their sakes I sanctify myself, that they also might be sanctified through the truth.', pt: 'E por amor deles eu me santifico a mim mesmo, para que eles também sejam santificados em verdade.' },
      { v: 20, en: 'Neither pray I for these alone, but for them also which shall believe on me through their word;', pt: 'Mas não rogo somente por estes, mas também por aqueles que pela sua palavra crerão em mim;' },
      { v: 21, en: 'That they all may be one; as thou, Father, art in me, and I in thee, that they also may be one in us: that the world may believe that thou hast sent me.', pt: 'Para que todos sejam um, como tu, ó Pai, és em mim e eu em ti; que também eles sejam um em nós, para que o mundo creia que tu me enviaste.' },
      { v: 22, en: 'And the glory which thou gavest me I have given them; that they may be one, even as we are one:', pt: 'E eu lhes dei a glória que tu me deste, para que sejam um, como nós somos um.' },
      { v: 23, en: 'I in them, and thou in me, that they may be made perfect in one; and that the world may know that thou hast sent me, and hast loved them, as thou hast loved me.', pt: 'Eu neles e tu em mim, para que sejam aperfeiçoados em unidade; e para que o mundo conheça que tu me enviaste e os amaste como também me amaste a mim.' },
      { v: 24, en: 'Father, I will that they also, whom thou hast given me, be with me where I am; that they may behold my glory, which thou hast given me: for thou lovedst me before the foundation of the world.', pt: 'Pai, quero que os que me deste estejam também comigo onde eu estiver, para que vejam a minha glória que me deste; porque tu me amaste antes da fundação do mundo.' },
      { v: 25, en: 'O righteous Father, the world hath not known thee: but I have known thee, and these have known that thou hast sent me.', pt: 'Pai justo, o mundo não te conheceu, mas eu te conheci; e estes conheceram que tu me enviaste.' },
      { v: 26, en: 'And I have declared unto them thy name, and will declare it: that the love wherewith thou hast loved me may be in them, and I in them.', pt: 'E fiz-lhes conhecer o teu nome e ainda o farei conhecer, para que o amor com que me amaste esteja neles e eu neles.' },
    ],
    18: [
      { v: 1,  en: 'When Jesus had spoken these words, he went forth with his disciples over the brook Cedron, where was a garden, into the which he entered, and his disciples.', pt: 'Tendo Jesus dito estas coisas, saiu com os seus discípulos para além do ribeiro de Cedrom, onde havia um jardim, no qual entrou com os seus discípulos.' },
      { v: 2,  en: 'And Judas also, which betrayed him, knew the place: for Jesus ofttimes resorted thither with his disciples.', pt: 'Ora, Judas, o que o traía, conhecia também aquele lugar, porque Jesus muitas vezes se reunia ali com os seus discípulos.' },
      { v: 3,  en: 'Judas then, having received a band of men and officers from the chief priests and Pharisees, cometh thither with lanterns and torches and weapons.', pt: 'Judas, pois, tendo tomado a coorte e os guardas dos principais sacerdotes e dos fariseus, foi ali com lanternas, tochas e armas.' },
      { v: 4,  en: 'Jesus therefore, knowing all things that should come upon him, went forth, and said unto them, Whom seek ye?', pt: 'Jesus, pois, sabendo tudo o que havia de vir sobre ele, adiantou-se e disse-lhes: A quem buscais?' },
      { v: 5,  en: 'They answered him, Jesus of Nazareth. Jesus saith unto them, I am he. And Judas also, which betrayed him, stood with them.', pt: 'Responderam-lhe: A Jesus Nazareno. Disse-lhes Jesus: Eu sou. E Judas, o que o traía, estava com eles.' },
      { v: 6,  en: 'As soon then as he had said unto them, I am he, they went backward, and fell to the ground.', pt: 'Quando, pois, lhes disse: Eu sou, recuaram e caíram por terra.' },
      { v: 7,  en: 'Then asked he them again, Whom seek ye? And they said, Jesus of Nazareth.', pt: 'Tornou, pois, a perguntar-lhes: A quem buscais? E eles disseram: A Jesus Nazareno.' },
      { v: 8,  en: 'Jesus answered, I have told you that I am he: if therefore ye seek me, let these go their way:', pt: 'Jesus respondeu: Já vos disse que eu sou; pois se é a mim que buscais, deixai ir estes.' },
      { v: 9,  en: 'That the saying might be fulfilled, which he spake, Of them which thou gavest me have I lost none.', pt: 'Para que se cumprisse a palavra que dissera: Dos que me deste não perdi nenhum.' },
      { v: 10, en: 'Then Simon Peter having a sword drew it, and smote the high priest\'s servant, and cut off his right ear. The servant\'s name was Malchus.', pt: 'Simão Pedro, que tinha uma espada, sacou-a e feriu o servo do sumo sacerdote, cortando-lhe a orelha direita. O nome do servo era Malco.' },
      { v: 11, en: 'Then said Jesus unto Peter, Put up thy sword into the sheath: the cup which my Father hath given me, shall I not drink it?', pt: 'Jesus, pois, disse a Pedro: Mete a espada na bainha. O cálice que o Pai me deu, não hei de bebê-lo?' },
      { v: 12, en: 'Then the band and the captain and officers of the Jews took Jesus, and bound him,', pt: 'Então a coorte, e o tribuno, e os guardas dos judeus prenderam Jesus e o amarraram.' },
      { v: 13, en: 'And led him away to Annas first; for he was father in law to Caiaphas, which was the high priest that same year.', pt: 'E levaram-no primeiro a Anás; porque era sogro de Caifás, que era sumo sacerdote naquele ano.' },
      { v: 14, en: 'Now Caiaphas was he, which gave counsel to the Jews, that it was expedient that one man should die for the people.', pt: 'Ora, Caifás era quem havia aconselhado os judeus que convinha que um só homem morresse pelo povo.' },
      { v: 15, en: 'And Simon Peter followed Jesus, and so did another disciple: that disciple was known unto the high priest, and went in with Jesus into the palace of the high priest.', pt: 'E Simão Pedro seguia a Jesus, e também outro discípulo. Esse discípulo era conhecido do sumo sacerdote, e entrou com Jesus no palácio do sumo sacerdote.' },
      { v: 16, en: 'But Peter stood at the door without. Then went out that other disciple, which was known unto the high priest, and spake unto her that kept the door, and brought in Peter.', pt: 'Mas Pedro ficou fora à porta. Saiu, pois, o outro discípulo, que era conhecido do sumo sacerdote, e falou à porteira e introduziu a Pedro.' },
      { v: 17, en: 'Then saith the damsel that kept the door unto Peter, Art not thou also one of this man\'s disciples? He saith, I am not.', pt: 'Disse então a criada que guardava a porta a Pedro: Não és também tu um dos discípulos deste homem? Disse ele: Não sou.' },
      { v: 18, en: 'And the servants and officers stood there, who had made a fire of coals; for it was cold: and they warmed themselves: and Peter stood with them, and warmed himself.', pt: 'E os servos e os guardas estavam ali, que tinham feito uma fogueira de carvão, porque estava frio; e aqueciam-se. E também Pedro estava com eles, aquecendo-se.' },
      { v: 19, en: 'The high priest then asked Jesus of his disciples, and of his doctrine.', pt: 'O sumo sacerdote interrogou Jesus acerca dos seus discípulos e da sua doutrina.' },
      { v: 20, en: 'Jesus answered him, I spake openly to the world; I ever taught in the synagogue, and in the temple, whither the Jews always resort; and in secret have I said nothing.', pt: 'Jesus respondeu-lhe: Eu tenho falado abertamente ao mundo; tenho ensinado sempre na sinagoga e no templo, onde todos os judeus se reúnem, e nada tenho dito em segredo.' },
      { v: 21, en: 'Why askest thou me? ask them which heard me, what I have said unto them: behold, they know what I said.', pt: 'Por que me interrogas? Pergunta aos que me ouviram o que lhes disse; eis que eles sabem o que eu disse.' },
      { v: 22, en: 'And when he had thus spoken, one of the officers which stood by struck Jesus with the palm of his hand, saying, Answerest thou the high priest so?', pt: 'E, dizendo ele isto, um dos guardas que estavam presentes deu uma bofetada a Jesus, dizendo: É assim que respondes ao sumo sacerdote?' },
      { v: 23, en: 'Jesus answered him, If I have spoken evil, bear witness of the evil: but if well, why smitest thou me?', pt: 'Jesus respondeu-lhe: Se falei mal, dá testemunho do mal; mas se falei bem, por que me bates?' },
      { v: 24, en: 'Now Annas had sent him bound unto Caiaphas the high priest.', pt: 'Então Anás o enviou amarrado a Caifás, o sumo sacerdote.' },
      { v: 25, en: 'And Simon Peter stood and warmed himself. They said therefore unto him, Art not thou also one of his disciples? He denied it, and said, I am not.', pt: 'Simão Pedro estava em pé, aquecendo-se. Disseram-lhe então: Não és também tu um dos seus discípulos? Ele negou e disse: Não sou.' },
      { v: 26, en: 'One of the servants of the high priest, being his kinsman whose ear Peter cut off, saith, Did not I see thee in the garden with him?', pt: 'Um dos servos do sumo sacerdote, parente daquele a quem Pedro cortara a orelha, disse: Não te vi eu no jardim com ele?' },
      { v: 27, en: 'Peter then denied again: and immediately the cock crew.', pt: 'Pedro negou novamente; e logo cantou o galo.' },
      { v: 28, en: 'Then led they Jesus from Caiaphas unto the hall of judgment: and it was early; and they themselves went not into the judgment hall, lest they should be defiled; but that they might eat the passover.', pt: 'Então levaram Jesus de Caifás ao pretório. Era de manhã cedo; e eles não entraram no pretório, para não se contaminarem, e assim poderem comer a páscoa.' },
      { v: 29, en: 'Pilate then went out unto them, and said, What accusation bring ye against this man?', pt: 'Saiu, pois, Pilatos ter com eles e disse: Que acusação trazeis contra este homem?' },
      { v: 30, en: 'They answered and said unto him, If he were not a malefactor, we would not have delivered him up unto thee.', pt: 'Responderam-lhe: Se este não fosse um malfeitor, não to teríamos entregado.' },
      { v: 31, en: 'Then said Pilate unto them, Take ye him, and judge him according to your law. The Jews therefore said unto him, It is not lawful for us to put any man to death:', pt: 'Então Pilatos lhes disse: Tomai-o vós, e julgai-o segundo a vossa lei. Os judeus pois disseram-lhe: A nós não nos é lícito matar ninguém.' },
      { v: 32, en: 'That the saying of Jesus might be fulfilled, which he spake, signifying what death he should die.', pt: 'Para que se cumprisse a palavra de Jesus, que dissera, indicando de que morte havia de morrer.' },
      { v: 33, en: 'Then Pilate entered into the judgment hall again, and called Jesus, and said unto him, Art thou the King of the Jews?', pt: 'Pilatos, pois, entrou outra vez no pretório e chamou Jesus, e disse-lhe: Tu és o rei dos judeus?' },
      { v: 34, en: 'Jesus answered him, Sayest thou this thing of thyself, or did others tell it thee of me?', pt: 'Jesus respondeu-lhe: Dizes isso de ti mesmo, ou outros to disseram a respeito de mim?' },
      { v: 35, en: 'Pilate answered, Am I a Jew? Thine own nation and the chief priests have delivered thee unto me: what hast thou done?', pt: 'Pilatos respondeu: Porventura sou eu judeu? A tua gente e os principais sacerdotes entregaram-te a mim. Que fizeste?' },
      { v: 36, en: 'Jesus answered, My kingdom is not of this world: if my kingdom were of this world, then would my servants fight, that I should not be delivered to the Jews: but now is my kingdom not from hence.', pt: 'Jesus respondeu: O meu reino não é deste mundo; se o meu reino fosse deste mundo, os meus servos lutariam para que eu não fosse entregue aos judeus; mas agora o meu reino não é daqui.' },
      { v: 37, en: 'Pilate therefore said unto him, Art thou a king then? Jesus answered, Thou sayest that I am a king. To this end was I born, and for this cause came I into the world, that I should bear witness unto the truth. Every one that is of the truth heareth my voice.', pt: 'Disse-lhe então Pilatos: Logo, és rei? Jesus respondeu: Tu dizes que sou rei. Para isso nasci, e para isso vim ao mundo, para dar testemunho da verdade. Todo aquele que é da verdade ouve a minha voz.' },
      { v: 38, en: 'Pilate saith unto him, What is truth? And when he had said this, he went out again unto the Jews, and saith unto them, I find in him no fault at all.', pt: 'Disse-lhe Pilatos: Que é a verdade? E, tendo dito isto, saiu outra vez ter com os judeus e disse-lhes: Eu não acho nele crime algum.' },
      { v: 39, en: 'But ye have a custom, that I should release unto you one at the passover: will ye therefore that I release unto you the King of the Jews?', pt: 'Mas tendes o costume de que eu vos solte um na páscoa. Quereis, pois, que vos solte o rei dos judeus?' },
      { v: 40, en: 'Then cried they all again, saying, Not this man, but Barabbas. Now Barabbas was a robber.', pt: 'Então todos clamaram de novo: Não a este, mas a Barrabás. Ora, Barrabás era um salteador.' },
    ],
    19: [
      { v: 1,  en: 'Then Pilate therefore took Jesus, and scourged him.', pt: 'Então Pilatos tomou Jesus e o mandou açoitar.' },
      { v: 2,  en: 'And the soldiers platted a crown of thorns, and put it on his head, and they put on him a purple robe,', pt: 'E os soldados, tecendo uma coroa de espinhos, puseram-lha na cabeça, e vestiram-no de uma roupa de púrpura,' },
      { v: 3,  en: 'And said, Hail, King of the Jews! and they smote him with their hands.', pt: 'E vinham ter com ele e diziam: Salve, rei dos judeus! E davam-lhe bofetadas.' },
      { v: 4,  en: 'Pilate therefore went forth again, and saith unto them, Behold, I bring him forth to you, that ye may know that I find no fault in him.', pt: 'Tornou, pois, a sair Pilatos e disse-lhes: Eis que vo-lo trago fora, para que saibais que não acho nele crime algum.' },
      { v: 5,  en: 'Then came Jesus forth, wearing the crown of thorns, and the purple robe. And Pilate saith unto them, Behold the man!', pt: 'Saiu pois Jesus fora, usando a coroa de espinhos e a roupa de púrpura. E Pilatos disse-lhes: Eis o homem!' },
      { v: 6,  en: 'When the chief priests therefore and officers saw him, they cried out, saying, Crucify him, crucify him. Pilate saith unto them, Take ye him, and crucify him: for I find no fault in him.', pt: 'E quando os principais sacerdotes e os guardas o viram, gritaram: Crucifica-o, crucifica-o! Disse-lhes Pilatos: Tomai-o vós e crucificai-o; porque eu não acho nele crime algum.' },
      { v: 7,  en: 'The Jews answered him, We have a law, and by our law he ought to die, because he made himself the Son of God.', pt: 'Os judeus responderam-lhe: Nós temos uma lei, e segundo a nossa lei deve morrer, porque se fez Filho de Deus.' },
      { v: 8,  en: 'When Pilate therefore heard that saying, he was the more afraid;', pt: 'Quando Pilatos ouviu este dito, ficou com mais medo;' },
      { v: 9,  en: 'And went again into the judgment hall, and saith unto Jesus, Whence art thou? But Jesus gave him no answer.', pt: 'E entrou de novo no pretório e disse a Jesus: De onde és tu? Mas Jesus não lhe deu resposta.' },
      { v: 10, en: 'Then saith Pilate unto him, Speakest thou not unto me? knowest thou not that I have power to crucify thee, and have power to release thee?', pt: 'Disse-lhe então Pilatos: Não me falas? Não sabes que tenho poder para te soltar e poder para te crucificar?' },
      { v: 11, en: 'Jesus answered, Thou couldest have no power at all against me, except it were given thee from above: therefore he that delivered me unto thee hath the greater sin.', pt: 'Respondeu-lhe Jesus: Não terias contra mim poder algum se de cima te não fora dado; por isso aquele que me entregou tem maior pecado.' },
      { v: 12, en: 'And from thenceforth Pilate sought to release him: but the Jews cried out, saying, If thou let this man go, thou art not Caesar\'s friend: whosoever maketh himself a king speaketh against Caesar.', pt: 'Desde então Pilatos procurava soltá-lo; mas os judeus clamavam: Se soltas este, não és amigo de César; todo aquele que se faz rei é adversário de César.' },
      { v: 13, en: 'When Pilate therefore heard that saying, he brought Jesus forth, and sat down in the judgment seat in a place that is called the Pavement, but in the Hebrew, Gabbatha.', pt: 'Pilatos, pois, ao ouvir estas palavras, trouxe Jesus para fora e assentou-se no tribunal, no lugar chamado Litóstroto, e em hebraico Gábata.' },
      { v: 14, en: 'And it was the preparation of the passover, and about the sixth hour: and he saith unto the Jews, Behold your King!', pt: 'Era a preparação da páscoa, pelas seis horas da manhã. E disse aos judeus: Eis o vosso rei!' },
      { v: 15, en: 'But they cried out, Away with him, away with him, crucify him. Pilate saith unto them, Shall I crucify your King? The chief priests answered, We have no king but Caesar.', pt: 'Mas eles gritaram: Tira, tira, crucifica-o! Disse-lhes Pilatos: Crucificarei o vosso rei? Os principais sacerdotes responderam: Não temos rei senão César.' },
      { v: 16, en: 'Then delivered he him therefore unto them to be crucified. And they took Jesus, and led him away.', pt: 'Então lho entregou para ser crucificado. E eles tomaram Jesus e o levaram.' },
      { v: 17, en: 'And he bearing his cross went forth into a place called the place of a skull, which is called in the Hebrew Golgotha:', pt: 'E ele, carregando a sua cruz, saiu para o lugar chamado da Caveira, que em hebraico se chama Gólgota;' },
      { v: 18, en: 'Where they crucified him, and two other with him, on either side one, and Jesus in the midst.', pt: 'Onde o crucificaram, e outros dois com ele, um de cada lado, e Jesus no meio.' },
      { v: 19, en: 'And Pilate wrote a title, and put it on the cross. And the writing was JESUS OF NAZARETH THE KING OF THE JEWS.', pt: 'E Pilatos escreveu também um título e o pôs na cruz. E estava escrito: JESUS NAZARENO, REI DOS JUDEUS.' },
      { v: 20, en: 'This title then read many of the Jews: for the place where Jesus was crucified was nigh to the city: and it was written in Hebrew, and Greek, and Latin.', pt: 'Muitos dos judeus leram este título, porque o lugar onde Jesus foi crucificado ficava perto da cidade; e estava escrito em hebraico, em grego e em latim.' },
      { v: 21, en: 'Then said the chief priests of the Jews to Pilate, Write not, The King of the Jews; but that he said, I am King of the Jews.', pt: 'Os principais sacerdotes dos judeus disseram então a Pilatos: Não escrevas: Rei dos judeus; mas que ele disse: Sou rei dos judeus.' },
      { v: 22, en: 'Pilate answered, What I have written I have written.', pt: 'Respondeu Pilatos: O que escrevi, escrevi.' },
      { v: 23, en: 'Then the soldiers, when they had crucified Jesus, took his garments, and made four parts, to every soldier a part; and also his coat: now the coat was without seam, woven from the top throughout.', pt: 'Os soldados, pois, quando crucificaram Jesus, tomaram as suas vestes e fizeram quatro partes, uma para cada soldado, e a túnica também. Ora, a túnica era sem costura, tecida toda de uma só peça.' },
      { v: 24, en: 'They said therefore among themselves, Let us not rend it, but cast lots for it, whose it shall be: that the scripture might be fulfilled, which saith, They parted my raiment among them, and for my vesture they did cast lots. These things therefore the soldiers did.', pt: 'Disseram então entre si: Não a rasguemos, mas lancemos sortes para ver de quem será; para que se cumprisse a Escritura que diz: Repartiram entre si as minhas vestes e sobre a minha roupa lançaram sortes. Foi o que os soldados fizeram.' },
      { v: 25, en: 'Now there stood by the cross of Jesus his mother, and his mother\'s sister, Mary the wife of Cleophas, and Mary Magdalene.', pt: 'E estavam junto à cruz de Jesus sua mãe, e a irmã de sua mãe, Maria mulher de Clopas, e Maria Madalena.' },
      { v: 26, en: 'When Jesus therefore saw his mother, and the disciple standing by, whom he loved, he saith unto his mother, Woman, behold thy son!', pt: 'Quando Jesus viu a mãe e o discípulo que ele amava, que ali estava, disse à mãe: Mulher, eis aí o teu filho.' },
      { v: 27, en: 'Then saith he to the disciple, Behold thy mother! And from that hour that disciple took her unto his own home.', pt: 'Depois disse ao discípulo: Eis aí a tua mãe. E desde aquela hora o discípulo a recebeu em sua casa.' },
      { v: 28, en: 'After this, Jesus knowing that all things were now accomplished, that the scripture might be fulfilled, saith, I thirst.', pt: 'Depois disto, Jesus, sabendo que todas as coisas estavam já consumadas, para que a Escritura se cumprisse, disse: Tenho sede.' },
      { v: 29, en: 'Now there was set a vessel full of vinegar: and they filled a spunge with vinegar, and put it upon hyssop, and put it to his mouth.', pt: 'Havia ali um vaso cheio de vinagre; eles, pois, encheram uma esponja de vinagre e, pondo-a num ramo de hissopo, lha chegaram à boca.' },
      { v: 30, en: 'When Jesus therefore had received the vinegar, he said, It is finished: and he bowed his head, and gave up the ghost.', pt: 'Quando Jesus tomou o vinagre, disse: Está consumado. E, inclinando a cabeça, entregou o espírito.' },
      { v: 31, en: 'The Jews therefore, because it was the preparation, that the bodies should not remain upon the cross on the sabbath day, (for that sabbath day was an high day,) besought Pilate that their legs might be broken, and that they might be taken away.', pt: 'Então os judeus, para que os corpos não ficassem na cruz no sábado, pois era a preparação (porque esse dia de sábado era grande), rogaram a Pilatos que se lhes quebrassem as pernas e que fossem tirados.' },
      { v: 32, en: 'Then came the soldiers, and brake the legs of the first, and of the other which was crucified with him.', pt: 'Vieram, pois, os soldados e quebraram as pernas ao primeiro e ao outro que estava crucificado com ele.' },
      { v: 33, en: 'But when they came to Jesus, and saw that he was dead already, they brake not his legs:', pt: 'Mas, quando chegaram a Jesus e viram que já estava morto, não lhe quebraram as pernas.' },
      { v: 34, en: 'But one of the soldiers with a spear pierced his side, and forthwith came there out blood and water.', pt: 'Mas um dos soldados lhe furou o lado com uma lança, e logo saiu sangue e água.' },
      { v: 35, en: 'And he that saw it bare record, and his record is true: and he knoweth that he saith true, that ye might believe.', pt: 'E aquele que viu isto testificou, e o seu testemunho é verdadeiro; e ele sabe que diz a verdade, para que vós também creiais.' },
      { v: 36, en: 'For these things were done, that the scripture should be fulfilled, A bone of him shall not be broken.', pt: 'Porque estas coisas aconteceram para que se cumprisse a Escritura: Nenhum dos seus ossos será quebrado.' },
      { v: 37, en: 'And again another scripture saith, They shall look on him whom they pierced.', pt: 'E outra vez diz a Escritura: Olharão para aquele que traspassaram.' },
      { v: 38, en: 'And after this Joseph of Arimathaea, being a disciple of Jesus, but secretly for fear of the Jews, besought Pilate that he might take away the body of Jesus: and Pilate gave him leave. He came therefore, and took the body of Jesus.', pt: 'Depois disto, José de Arimateia, sendo discípulo de Jesus, mas secretamente, por medo dos judeus, rogou a Pilatos que lhe permitisse tirar o corpo de Jesus; e Pilatos o permitiu. Veio, pois, e tirou o corpo de Jesus.' },
      { v: 39, en: 'And there came also Nicodemus, which at the first came to Jesus by night, and brought a mixture of myrrh and aloes, about an hundred pound weight.', pt: 'Também Nicodemos, que de noite viera ter com Jesus, trouxe uma mistura de mirra e aloés, de quase cem libras.' },
      { v: 40, en: 'Then took they the body of Jesus, and wound it in linen clothes with the spices, as the manner of the Jews is to bury.', pt: 'Tomaram, pois, o corpo de Jesus, e o envolveram em faixas de linho com os aromas, como é costume dos judeus enterrar.' },
      { v: 41, en: 'Now in the place where he was crucified there was a garden; and in the garden a new sepulchre, wherein was never man yet laid.', pt: 'Ora, no lugar onde foi crucificado havia um jardim, e no jardim um sepulcro novo, em que ainda ninguém tinha sido posto.' },
      { v: 42, en: 'There laid they Jesus therefore because of the Jews\' preparation day; for the sepulchre was nigh at hand.', pt: 'Ali, pois, por causa da preparação da páscoa dos judeus, e porque o sepulcro estava perto, puseram Jesus.' },
    ],
    20: [
      { v: 1,  en: 'The first day of the week cometh Mary Magdalene early, when it was yet dark, unto the sepulchre, and seeth the stone taken away from the sepulchre.', pt: 'No primeiro dia da semana, Maria Madalena foi ao sepulcro de manhã cedo, sendo ainda escuro, e viu que a pedra estava retirada do sepulcro.' },
      { v: 2,  en: 'Then she runneth, and cometh to Simon Peter, and to the other disciple, whom Jesus loved, and saith unto them, They have taken away the Lord out of the sepulchre, and we know not where they have laid him.', pt: 'Correu, pois, e foi ter com Simão Pedro e com o outro discípulo, aquele que Jesus amava, e disse-lhes: Tiraram o Senhor do sepulcro e não sabemos onde o puseram.' },
      { v: 3,  en: 'Peter therefore went forth, and that other disciple, and came to the sepulchre.', pt: 'Saiu pois Pedro e o outro discípulo e foram ao sepulcro.' },
      { v: 4,  en: 'So they ran both together: and the other disciple did outrun Peter, and came first to the sepulchre.', pt: 'Corriam os dois juntos; e o outro discípulo correu mais depressa do que Pedro e chegou primeiro ao sepulcro.' },
      { v: 5,  en: 'And he stooping down, and looking in, saw the linen clothes lying; yet went he not in.', pt: 'E, tendo-se abaixado, viu as faixas de linho ali colocadas; mas não entrou.' },
      { v: 6,  en: 'Then cometh Simon Peter following him, and went into the sepulchre, and seeth the linen clothes lie,', pt: 'Chegou Simão Pedro, que o seguia, e entrou no sepulcro e viu as faixas de linho colocadas,' },
      { v: 7,  en: 'And the napkin, that was about his head, not lying with the linen clothes, but wrapped together in a place by itself.', pt: 'E o sudário, que estivera na cabeça dele, não posto com as faixas de linho, mas enrolado num lugar à parte.' },
      { v: 8,  en: 'Then went in also that other disciple, which came first to the sepulchre, and he saw, and believed.', pt: 'Então entrou também o outro discípulo, que chegara primeiro ao sepulcro, e viu e creu.' },
      { v: 9,  en: 'For as yet they knew not the scripture, that he must rise again from the dead.', pt: 'Porque ainda não tinham entendido a Escritura: que convinha que ele ressuscitasse dos mortos.' },
      { v: 10, en: 'Then the disciples went away again unto their own home.', pt: 'Então os discípulos foram de novo para casa.' },
      { v: 11, en: 'But Mary stood without at the sepulchre weeping: and as she wept, she stooped down, and looked into the sepulchre,', pt: 'Maria, porém, estava fora, junto ao sepulcro, a chorar. E, chorando, abaixou-se e olhou para dentro do sepulcro,' },
      { v: 12, en: 'And seeth two angels in white sitting, the one at the head, and the other at the feet, where the body of Jesus had lain.', pt: 'E viu dois anjos vestidos de branco assentados, um à cabeceira e outro aos pés, no lugar onde o corpo de Jesus estivera.' },
      { v: 13, en: 'And they say unto her, Woman, why weepest thou? She saith unto them, Because they have taken away my Lord, and I know not where they have laid him.', pt: 'E eles disseram-lhe: Mulher, por que choras? Disse-lhes ela: Porque tiraram o meu Senhor, e não sei onde o puseram.' },
      { v: 14, en: 'And when she had thus said, she turned herself back, and saw Jesus standing, and knew not that it was Jesus.', pt: 'E, tendo dito isto, se virou para trás e viu Jesus que estava ali, e não sabia que era Jesus.' },
      { v: 15, en: 'Jesus saith unto her, Woman, why weepest thou? whom seekest thou? She, supposing him to be the gardener, saith unto him, Sir, if thou have borne him hence, tell me where thou hast laid him, and I will take him away.', pt: 'Jesus disse-lhe: Mulher, por que choras? A quem procuras? Ela, pensando que era o jardineiro, disse-lhe: Senhor, se tu o levaste daqui, diz-me onde o puseste, e eu o tomarei.' },
      { v: 16, en: 'Jesus saith unto her, Mary. She turned herself, and saith unto him, Rabboni; which is to say, Master.', pt: 'Jesus disse-lhe: Maria! Ela, voltando-se, disse-lhe: Raboni! (que quer dizer, Mestre).' },
      { v: 17, en: 'Jesus saith unto her, Touch me not; for I am not yet ascended to my Father: but go to my brethren, and say unto them, I ascend unto my Father, and your Father; and to my God, and your God.', pt: 'Jesus disse-lhe: Não me toques, porque ainda não subi para meu Pai; mas vai aos meus irmãos e dize-lhes: Subo para meu Pai e vosso Pai, e meu Deus e vosso Deus.' },
      { v: 18, en: 'Mary Magdalene came and told the disciples that she had seen the Lord, and that he had spoken these things unto her.', pt: 'Maria Madalena foi e anunciou aos discípulos que vira o Senhor e que ele lhe dissera estas coisas.' },
      { v: 19, en: 'Then the same day at evening, being the first day of the week, when the doors were shut where the disciples were assembled for fear of the Jews, came Jesus and stood in the midst, and saith unto them, Peace be unto you.', pt: 'Sendo, pois, tarde aquele dia, o primeiro da semana, e estando as portas cerradas onde os discípulos se encontravam, por medo dos judeus, veio Jesus e pôs-se no meio e disse-lhes: Paz seja convosco!' },
      { v: 20, en: 'And when he had so said, he shewed unto them his hands and his side. Then were the disciples glad, when they saw the Lord.', pt: 'E, dizendo isto, mostrou-lhes as mãos e o lado. Os discípulos alegraram-se quando viram o Senhor.' },
      { v: 21, en: 'Then said Jesus to them again, Peace be unto you: as my Father hath sent me, even so send I you.', pt: 'Então Jesus lhes disse outra vez: Paz seja convosco! Como o Pai me enviou, assim também eu vos envio.' },
      { v: 22, en: 'And when he had said this, he breathed on them, and saith unto them, Receive ye the Holy Ghost:', pt: 'E, dizendo isto, soprou sobre eles e disse-lhes: Recebei o Espírito Santo.' },
      { v: 23, en: 'Whose soever sins ye remit, they are remitted unto them; and whose soever sins ye retain, they are retained.', pt: 'A quem perdoardes os pecados, são-lhes perdoados; a quem os retiverdes, são retidos.' },
      { v: 24, en: 'But Thomas, one of the twelve, called Didymus, was not with them when Jesus came.', pt: 'Ora, Tomé, um dos doze, chamado Dídimo, não estava com eles quando Jesus veio.' },
      { v: 25, en: 'The other disciples therefore said unto him, We have seen the Lord. But he said unto them, Except I shall see in his hands the print of the nails, and put my finger into the print of the nails, and thrust my hand into his side, I will not believe.', pt: 'Disseram-lhe então os outros discípulos: Vimos o Senhor. Ele, porém, disse-lhes: Se eu não vir nas suas mãos o sinal dos cravos, e não meter o meu dedo no sinal dos cravos, e não meter a minha mão no seu lado, de modo algum o crerei.' },
      { v: 26, en: 'And after eight days again his disciples were within, and Thomas with them: then came Jesus, the doors being shut, and stood in the midst, and said, Peace be unto you.', pt: 'Oito dias depois, estavam outra vez os seus discípulos dentro da casa, e Tomé com eles. Veio Jesus, estando as portas fechadas, e pôs-se no meio e disse: Paz seja convosco!' },
      { v: 27, en: 'Then saith he to Thomas, Reach hither thy finger, and behold my hands; and reach hither thy hand, and thrust it into my side: and be not faithless, but believing.', pt: 'Depois disse a Tomé: Traz aqui o teu dedo e vê as minhas mãos; e traz aqui a tua mão e mete-a no meu lado; e não sejas incrédulo, mas crente.' },
      { v: 28, en: 'And Thomas answered and said unto him, My Lord and my God.', pt: 'Respondeu Tomé e disse-lhe: Senhor meu e Deus meu!' },
      { v: 29, en: 'Jesus saith unto him, Thomas, because thou hast seen me, thou hast believed: blessed are they that have not seen, and yet have believed.', pt: 'Jesus disse-lhe: Porque me viste, Tomé, creste; bem-aventurados os que não viram e creram.' },
      { v: 30, en: 'And many other signs truly did Jesus in the presence of his disciples, which are not written in this book:', pt: 'Jesus fez ainda muitos outros sinais na presença dos seus discípulos, os quais não estão escritos neste livro.' },
      { v: 31, en: 'But these are written, that ye might believe that Jesus is the Christ, the Son of God; and that believing ye might have life through his name.', pt: 'Estes, porém, foram escritos para que creiais que Jesus é o Cristo, o Filho de Deus, e para que, crendo, tenhais vida em seu nome.' },
    ],
    21: [
      { v: 1,  en: 'After these things Jesus shewed himself again to the disciples at the sea of Tiberias; and on this wise shewed he himself.', pt: 'Depois disto Jesus manifestou-se outra vez aos discípulos junto do mar de Tiberíades; e manifestou-se deste modo.' },
      { v: 2,  en: 'There were together Simon Peter, and Thomas called Didymus, and Nathanael of Cana in Galilee, and the sons of Zebedee, and two other of his disciples.', pt: 'Estavam juntos Simão Pedro, e Tomé chamado Dídimo, e Natanael de Caná da Galileia, e os filhos de Zebedeu, e dois outros dos seus discípulos.' },
      { v: 3,  en: 'Simon Peter saith unto them, I go a fishing. They say unto him, We also go with thee. They went forth, and entered into a ship immediately; and that night they caught nothing.', pt: 'Disse-lhes Simão Pedro: Vou pescar. Disseram-lhe: Vamos também nós contigo. Foram e entraram logo num barco; e naquela noite não pescaram nada.' },
      { v: 4,  en: 'But when the morning was now come, Jesus stood on the shore: but the disciples knew not that it was Jesus.', pt: 'Mas, quando já amanheceu, Jesus se pôs em pé na praia; os discípulos, porém, não sabiam que era Jesus.' },
      { v: 5,  en: 'Then Jesus saith unto them, Children, have ye any meat? They answered him, No.', pt: 'Disse-lhes então Jesus: Filhinhos, tendes algum mantimento? Responderam-lhe: Não.' },
      { v: 6,  en: 'And he said unto them, Cast the net on the right side of the ship, and ye shall find. They cast therefore, and now they were not able to draw it for the multitude of fishes.', pt: 'E ele disse-lhes: Lançai a rede para o lado direito do barco e achareis. Lançaram-na, pois, e já não a podiam arrastar, por causa da quantidade de peixes.' },
      { v: 7,  en: 'Therefore that disciple whom Jesus loved saith unto Peter, It is the Lord. Now when Simon Peter heard that it was the Lord, he girt his fisher\'s coat unto him, (for he was naked,) and did cast himself into the sea.', pt: 'Então o discípulo a quem Jesus amava disse a Pedro: É o Senhor! E Simão Pedro, ouvindo que era o Senhor, cingiu a túnica (porque estava nu) e atirou-se ao mar.' },
      { v: 8,  en: 'And the other disciples came in a little ship; (for they were not far from land, but as it were two hundred cubits,) dragging the net with fishes.', pt: 'Os outros discípulos vieram de barco (porque não estavam longe de terra, mas apenas cerca de duzentos côvados), arrastando a rede com os peixes.' },
      { v: 9,  en: 'As soon then as they were come to land, they saw a fire of coals there, and fish laid thereon, and bread.', pt: 'Logo que desembarcaram, viram uma brasa ali posta, e um peixe em cima dela, e pão.' },
      { v: 10, en: 'Jesus saith unto them, Bring of the fish which ye have now caught.', pt: 'Jesus disse-lhes: Trazei dos peixes que apanhastes agora.' },
      { v: 11, en: 'Simon Peter went up, and drew the net to land full of great fishes, an hundred and fifty and three: and for all there were so many, yet was not the net broken.', pt: 'Simão Pedro subiu e puxou a rede a terra, cheia de grandes peixes, cento e cinquenta e três; e, sendo tantos, não se rompeu a rede.' },
      { v: 12, en: 'Jesus saith unto them, Come and dine. And none of the disciples durst ask him, Who art thou? knowing that it was the Lord.', pt: 'Jesus disse-lhes: Vinde e jantai. E nenhum dos discípulos ousava perguntar-lhe: Tu, quem és? sabendo que era o Senhor.' },
      { v: 13, en: 'Jesus then cometh, and taketh bread, and giveth them, and fish likewise.', pt: 'Jesus veio e tomou o pão e lho deu; e do mesmo modo o peixe.' },
      { v: 14, en: 'This is now the third time that Jesus shewed himself to his disciples, after that he was risen from the dead.', pt: 'Esta era já a terceira vez que Jesus se manifestou aos discípulos, depois de ter ressuscitado dos mortos.' },
      { v: 15, en: 'So when they had dined, Jesus saith to Simon Peter, Simon, son of Jonas, lovest thou me more than these? He saith unto him, Yea, Lord; thou knowest that I love thee. He saith unto him, Feed my lambs.', pt: 'Quando, pois, jantaram, disse Jesus a Simão Pedro: Simão, filho de Jonas, amas-me mais do que estes? Disse-lhe: Sim, Senhor; tu sabes que te amo. Disse-lhe: Apascenta os meus cordeiros.' },
      { v: 16, en: 'He saith to him again the second time, Simon, son of Jonas, lovest thou me? He saith unto him, Yea, Lord; thou knowest that I love thee. He saith unto him, Feed my sheep.', pt: 'Disse-lhe outra vez, pela segunda vez: Simão, filho de Jonas, amas-me? Disse-lhe: Sim, Senhor; tu sabes que te amo. Disse-lhe: Apascenta as minhas ovelhas.' },
      { v: 17, en: 'He saith unto him the third time, Simon, son of Jonas, lovest thou me? Peter was grieved because he said unto him the third time, Lovest thou me? And he said unto him, Lord, thou knowest all things; thou knowest that I love thee. Jesus saith unto him, Feed my sheep.', pt: 'Disse-lhe pela terceira vez: Simão, filho de Jonas, amas-me? Pedro entristeceu-se por lhe ter dito pela terceira vez: Amas-me? E disse-lhe: Senhor, tu sabes todas as coisas; tu sabes que te amo. Jesus disse-lhe: Apascenta as minhas ovelhas.' },
      { v: 18, en: 'Verily, verily, I say unto thee, When thou wast young, thou girdedst thyself, and walkedst whither thou wouldest: but when thou shalt be old, thou shalt stretch forth thy hands, and another shall gird thee, and carry thee whither thou wouldest not.', pt: 'Em verdade, em verdade te digo que, quando eras mais jovem, tu mesmo te cingia e andavas para onde querias; mas quando fores velho, estenderás as tuas mãos e outro te cingirá e levará para onde não queres.' },
      { v: 19, en: 'This spake he, signifying by what death he should glorify God. And when he had spoken this, he saith unto him, Follow me.', pt: 'Disse isto significando com que morte havia de glorificar a Deus. E, tendo dito isto, disse-lhe: Segue-me.' },
      { v: 20, en: 'Then Peter, turning about, seeth the disciple whom Jesus loved following; which also leaned on his breast at supper, and said, Lord, which is he that betrayeth thee?', pt: 'Pedro, voltando-se, viu que o seguia o discípulo que Jesus amava, o que também na ceia se tinha recostado sobre o seu peito e dissera: Senhor, quem é o que te trai?' },
      { v: 21, en: 'Peter seeing him saith to Jesus, Lord, and what shall this man do?', pt: 'Vendo-o Pedro, disse a Jesus: Senhor, e este, que será?' },
      { v: 22, en: 'Jesus saith unto him, If I will that he tarry till I come, what is that to thee? follow thou me.', pt: 'Jesus disse-lhe: Se eu quero que ele fique até que eu venha, que te importa? Tu, segue-me.' },
      { v: 23, en: 'Then went this saying abroad among the brethren, that that disciple should not die: yet Jesus said not unto him, He shall not die; but, If I will that he tarry till I come, what is that to thee?', pt: 'Espalhou-se então entre os irmãos este dito, que aquele discípulo não morreria; porém Jesus não lhe dissera que não morreria, mas: Se eu quero que fique até que eu venha, que te importa?' },
      { v: 24, en: 'This is the disciple which testifieth of these things, and wrote these things: and we know that his testimony is true.', pt: 'Este é o discípulo que testifica estas coisas e que as escreveu; e sabemos que o seu testemunho é verdadeiro.' },
      { v: 25, en: 'And there are also many other things which Jesus did, the which, if they should be written every one, I suppose that even the world itself could not contain the books that should be written. Amen.', pt: 'Há também muitas outras coisas que Jesus fez, as quais, se fossem escritas uma por uma, creio que nem o mesmo mundo poderia conter os livros que se haveriam de escrever.' },
    ],
  },
};
